-- Poems batch 321
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e8ef0739-6ddc-4e1a-87eb-85053d0d27a3','白鬚','蘇轍','宋','宋诗','song-poetry','','[]','中歲謬學道，白鬚何由生。',120,'全唐诗/poet.song.49000.json','["中歲謬學道，白鬚何由生。", "故人指我笑，聞道未能行。", "我笑謝故人，唯唯亦否否。", "老聃古道師，白髮生而有。", "佛告波斯匿，汝有不白存。", "亭中掌亭人，何嘗隨客奔。", "客去不用留，主在亭不毀。", "墁牆支折棟，在我不在爾。", "道成款玉晨，跪乞五色丸。", "肝心化黄金，齒髮何足言。"]'),
('d4b80cd3-b9e9-48f4-8851-9d966f2fba34','寒食二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','寒食今年客汝南，餘樽傾瀉亦醺酣。',64,'全唐诗/poet.song.49000.json','["寒食今年客汝南，餘樽傾瀉亦醺酣。", "道人久厭世間濁，僧舍猶存肉食慚。", "花折園夫時送客，餳留孫女尚分甘。", "欲遊紫極誰爲伴，長揖孤松對不談。"]'),
('ac36558d-9dde-443f-9d28-aeaaf194a92b','寒食二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','寄住汝南懷嶺南，五年一醉久猶酣。',64,'全唐诗/poet.song.49000.json','["寄住汝南懷嶺南，五年一醉久猶酣。", "身逃爭地差云靜，名落塵寰終自慚。", "耳畔飛蠅看尚在，鼻中醇酢近能甘。", "今朝寒食唯當飲，買酒先防客欲談。"]'),
('93031c9e-e29b-4c6d-8205-f848414092e8','潁川城東野老','蘇轍','宋','宋诗','song-poetry','','[]','我歸潁川無故人，城東野老鬚如銀。',160,'全唐诗/poet.song.49000.json','["我歸潁川無故人，城東野老鬚如銀。", "少年椎埋起黄塵，晚歲折節依仙真。", "走如麏鹿人莫親，呼來上堂飲清樽。", "踞床閉目略頻伸，指我黄河出崑崙。", "東流入海還天津，沐浴周遍纔逡巡。", "嬰兒跏趺乘日輪，脫身遊戲走四鄰。", "逢人不告非自珍，許我已老知閉門。", "東朝太行款真君，告我不返遊峨岷。", "還家一舍卧不晨，闔棺空空但衣巾。", "平生自言師洞賓，嗟世賤目貴所聞。"]'),
('eb32eb0a-75ac-42fe-8c4b-df3a1902d032','汝南示三子','蘇轍','宋','宋诗','song-poetry','','[]','此生頼有三男子，到處來看老病翁。',64,'全唐诗/poet.song.49000.json','["此生頼有三男子，到處來看老病翁。", "飲食粗便魚稻足，音塵不隔馬牛風。", "道場莫問何方是，舍宅元依畢竟空。", "且爾不歸歸亦得，汝曹免復走西東。"]'),
('f1e86ec6-b5ea-44f3-aa7d-9a47194b347c','謝任亮教授送千葉牡丹','蘇轍','宋','宋诗','song-poetry','','[]','花從單葉成千葉，家住汝南疑洛南。',64,'全唐诗/poet.song.49000.json','["花從單葉成千葉，家住汝南疑洛南。", "亂剝浮苞任狼籍，併偷春色恣醺酣。", "香穠得露久彌馥，頭重迎風似不堪。", "居士誰知已離畏，金槃剪送病中庵。"]'),
('0a20af9a-4e2d-4053-bc32-dd3a1ed04f74','思歸二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','汝南百日留，走遍三男子。',120,'全唐诗/poet.song.49000.json','["汝南百日留，走遍三男子。", "思歸非吾計，聊亦爲爾耳。", "行裝理肩輿，客舍卷床笫。", "兒言世情惡，平地風波起。", "舟行或易摇，舟靜姑且已。", "匏繫雖非願，蠖屈當有俟。", "老人思慮拙，小子言有理。", "晨炊廩粟紅，曉市淮魚美。", "索居庖無人，歸去迎伯姊。", "終歲得安閑，幽居無彼此。"]'),
('faaaa00f-cd90-4848-bf90-6d180326b689','思歸二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','我老不待言，有女年四十。',120,'全唐诗/poet.song.49000.json','["我老不待言，有女年四十。", "念我客汝南，無與具朝食。", "翩然乘肩輿，面有風土色。", "許蔡雖云近，傳舍三經夕。", "衰老累汝曹，愧嘆心不懌。", "磨刀鱠縷紅，洗盞酒花白。", "母老行役難，女來生理葺。", "外孫跨鞍馬，遇事亦閑習。", "居然數口家，解我百憂集。", "厄窮須父子，他人非所及。"]'),
('5be0df3e-fb67-442e-b349-5a26673bccd0','萬蝶花','蘇轍','宋','宋诗','song-poetry','','[]','誰唱殘春蝶戀花，一團粉翅壓枝斜。',32,'全唐诗/poet.song.49000.json','["誰唱殘春蝶戀花，一團粉翅壓枝斜。", "美人欲向釵頭插，又恐驚飛鬢似鴉。"]'),
('e9959336-c26f-4cb7-bbdc-ae40a50f976c','春盡','蘇轍','宋','宋诗','song-poetry','','[]','春風過盡百花空，燕坐笙簫起滅中。',64,'全唐诗/poet.song.49000.json','["春風過盡百花空，燕坐笙簫起滅中。", "樹影連天開翠幕，鳥聲入耳當歌童。", "楞嚴十卷幾回讀，法酒三升是客同。", "試問鄰僧行乞在，何人閑暇似衰翁。"]'),
('8fa6a93c-5343-46cd-8a07-3631d0c0c76a','夢中咏醉人','蘇轍','宋','宋诗','song-poetry','','[]','城中醉人舞連臂，城外醉人相枕睡。',160,'全唐诗/poet.song.49000.json','["城中醉人舞連臂，城外醉人相枕睡。", "此人心中未必空，暫爾頹然似無事。", "我生從來不解飲，終日騰騰少憂累。", "昔年曾見樂全翁，自說少年飲都市。", "一時同飲石與劉，不論升斗俱不醉。", "樓中日夜狂歌呼，錢盡酒空姑且止。", "都人疑是神仙人，誰謂兩人皆醉死。", "此翁年老不復飲，面光如玉心如水。", "我今在家同出家，萬法過前心不起。", "此翁已死誰與言，欲言已似前生記。"]'),
('0b88063d-8919-4db7-9389-daa533c3f9cb','立秋偶作','蘇轍','宋','宋诗','song-poetry','','[]','十年憂患本誰知，慚愧仙翁有舊期。',64,'全唐诗/poet.song.49000.json','["十年憂患本誰知，慚愧仙翁有舊期。", "度嶺還家天許我，斸山種粟我尤誰。", "秋風欲踐故人約，春氣潛通病樹滋。", "心似死灰鬚似雪，眼看多事亦奚爲。"]'),
('e48c58e7-1d73-4797-8a6f-749e7def7111','汝南遷居','蘇轍','宋','宋诗','song-poetry','','[]','病暑暑已退，思歸未成歸。',96,'全唐诗/poet.song.49000.json','["病暑暑已退，思歸未成歸。", "人事不可期，當受不當違。", "客居汝南城，未覺吾廬非。", "忽聞鵲反巢，坐使鳩驚飛。", "三繞擇所安，一枝粗得依。", "我來衆草生，漸見百卉腓。", "天行若循環，物化如發機。", "閉目內自觀，此理良密微。"]'),
('e32c1575-9c34-470e-95bf-6d6e492000ed','寄內','蘇轍','宋','宋诗','song-poetry','','[]','與君少年初相識，君年十五我十七。',192,'全唐诗/poet.song.49000.json','["與君少年初相識，君年十五我十七。", "上事姑章旁兄弟，君雖少年少過失。", "昏晨定省歲月短，五十還朝定何益。", "憂深責重樂無幾，失足一墜南海北。", "身居穽中不見天，仰面虛空聞下石。", "丈夫學道等憂患，婦人亦爾何從得。", "歸來舊許生白鬚，回顧慚君髮如漆。", "遷居汝南復何事，龜老支床隨所擲。", "相望一月兩得書，聞君肺病久消釋。", "我經三伏常暴下，近喜秋風掃烝濕。", "病除寢食未復故，相見猶驚身似腊。", "劉根夫婦俱有道，去日饒君著鞭策。"]'),
('cb285ac0-03f0-4c53-afa7-f02aa3640aa6','病愈二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','學道雖云久，沉疴竟未除。',48,'全唐诗/poet.song.49000.json','["學道雖云久，沉疴竟未除。", "炎烝度三伏，晻曖覺中虛。", "嘉穀不自長，荒榛終費鋤。", "何辭用蘭石，梨棗得扶疏。"]'),
('82f9c36d-9661-4c39-afe8-ef4d0cc08807','病愈二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','病退日身輕，身輕心轉清。',48,'全唐诗/poet.song.49000.json','["病退日身輕，身輕心轉清。", "山空流水上，海靜寸燈明。", "朝市誰留住，林泉自不行。", "筠溪慚丐士，流蕩過平生。"]'),
('fddc4867-9677-440c-bcfe-b956602a861b','九日三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','早歲寡歡意，衰年仍病纏。',48,'全唐诗/poet.song.49000.json','["早歲寡歡意，衰年仍病纏。", "客居逢九日，斗酒破千錢。", "萸菊驚秋晚，兒孫慰目前。", "登高懶不出，多酌任頹然。"]'),
('a311d57a-5d3a-49ee-b8ef-5af596156289','九日三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','狂夫老無頼，見逐便忘歸。',48,'全唐诗/poet.song.49000.json','["狂夫老無頼，見逐便忘歸。", "小酌還成醉，僑居不覺非。", "妻孥應念我，風雨未縫衣。", "憂患十年足，何時賦式微。"]'),
('2e612c14-669d-40b1-8599-c0b84563c915','九日三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','黄菊與秋競，白鬚隨日添。',48,'全唐诗/poet.song.49000.json','["黄菊與秋競，白鬚隨日添。", "時人知不憙，野老未相嫌。", "但酌清樽盡，猶存薄俸霑。", "日西聞客至，更問酒家帘。"]'),
('8f77436c-3d94-4c62-a6f4-c702be4b81b2','立冬聞雷','蘇轍','宋','宋诗','song-poetry','','[]','陽淫不收斂，半歲苦常燠。',168,'全唐诗/poet.song.49000.json','["陽淫不收斂，半歲苦常燠。", "禾黍飼蝗螟，粳稻委平陸。", "民饑强扶耒，秋晚麥當宿。", "閔然候一雨，霜落水泉縮。", "薈蔚山朝隮，滂沱雨翻瀆。", "經旬勢益暴，方冬歲愈蹙。", "半夜發春雷，中天轉車轂。", "老夫睡不寐，稚子起驚哭。", "平明視中庭，松菊半摧禿。", "潛發枯草萌，亂起蟄蟲伏。", "薪槱不出市，晨炊午未熟。", "首種不入土，春餉難滿腹。", "書生信古語，洪範有遺牘。", "時無中壘君，此意誰當告。"]'),
('b892a814-1281-44b5-a502-7e6f8e1e285b','將歸二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','久客初何事，言歸似有名。',48,'全唐诗/poet.song.49000.json','["久客初何事，言歸似有名。", "騰騰且隨俗，落落竟無成。", "病苦醫猶厭，囊空身自輕。", "家人驚別後，無限白鬚生。"]'),
('6a10c660-e563-45e7-9b29-e94091b990f6','將歸二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','爲客不滿歲，還家見兩孫。',48,'全唐诗/poet.song.49000.json','["爲客不滿歲，還家見兩孫。", "遥知臨竹戶，相對引瓢樽。", "老罷那嫌瘦，心寬尚喜存。", "風波隨處有，何幸免驚奔。"]'),
('6e9bb1e2-b999-4c9a-8683-923a9fe6a51d','示資福諭老','蘇轍','宋','宋诗','song-poetry','','[]','幽居百無營，孤坐若假寐。',96,'全唐诗/poet.song.49000.json','["幽居百無營，孤坐若假寐。", "根塵兩相接，逆流就一意。", "意念紛無端，中止不及地。", "寂然了無覺，乃造真實際。", "百川入滄溟，衆水皆一味。", "止爲潭淵深，動作濤瀾起。", "動止初何心，乃遇適然耳。", "吾心未嘗勞，萬物將自理。"]'),
('64442fae-7b58-462b-9a0a-f2e4af83fc47','三不歸行','蘇轍','宋','宋诗','song-poetry','','[]','客心摇摇若懸旌，三度欲歸歸不成。',224,'全唐诗/poet.song.49000.json','["客心摇摇若懸旌，三度欲歸歸不成。", "方春欲歸我自懶，秋冬欲歸事自變。", "問我欲歸定何時，天公默定人不知。", "孔公晚歲將入楚，盤桓陳蔡行且住。", "昭王已死不復南，意欲歸老父母邦。", "衛靈父子無足取，姑爾息肩俟東魯。", "三桓豈知用聖人，哀公亦自不能臣。", "冉求一戰却齊虜，請君召師君亦許。", "歸來閉戶理詩書，弁冕時出從大夫。", "夢見周公已不復，老死故國心亦足。", "孔公愈老愈屯邅，顧我未及門下賢。", "鄉邦萬里不能往，妻孥近寄潁川上。", "依嵩架潁結茅茨，自問此志於何期。", "汝南一寓歲行復，來年歸去栽松竹。"]'),
('3f20e829-20e5-4461-bd05-9687f0f03743','罷提舉太平宮欲還居潁川','蘇轍','宋','宋诗','song-poetry','','[]','避世山林中，衣草食芋栗。',168,'全唐诗/poet.song.49000.json','["避世山林中，衣草食芋栗。", "奈何處朝市，日耗太倉積。", "中心久自笑，公議肯相釋。", "終然幸寬政，尚許存寄秩。", "經年汝南居，久與茅茨隔。", "祠官一掃空，避就兩皆失。", "父子相携扶，里巷行可即。", "屋敝且圬牆，蝗餘尚遺粒。", "交遊忌點染，還往但親戚。", "閉門便衰病，杜口謝彈詰。", "餘年迫懸車，奏草屢濡筆。", "籍中顧未敢，爾後儻容乞。", "幽居足暇豫，肉食多憂慄。", "永懷城東老，未盡長年術。"]'),
('7cee1285-fff9-4f7c-b706-65ba117fcd46','次遲韵寄适遜','蘇轍','宋','宋诗','song-poetry','','[]','饑民畏寒尤惡雪，旋理破裘紝敗纈。',96,'全唐诗/poet.song.49000.json','["饑民畏寒尤惡雪，旋理破裘紝敗纈。", "我雖久客未成歸，黍酒虀羹還潑節。", "汝雨薪炭舊如土，爾來薄俸纔供爇。", "眼前暖熱無可道，心下清凉有餘潔。", "潁川歸去知何時，祠宮欲罷無同列。", "夜中仿佛夢兩兒，欲迓老人先聚說。"]'),
('cfcdbf9c-d9b0-4e5e-b2ca-7559837f73e0','次遲韵對雪','蘇轍','宋','宋诗','song-poetry','','[]','雪寒近可憂，麥熟遠有喜。',120,'全唐诗/poet.song.49000.json','["雪寒近可憂，麥熟遠有喜。", "我生憂喜中，所遇一已委。", "平生聞汝南，米賤豚魚美。", "今年惡蝗旱，流民鬻妻子。", "一食方半菽，三日已于耜。", "號呼人誰聞，愍惻天自邇。", "繁陰忽連夕，飛霰墮千里。", "卷舒驚太速，原隰殊未被。", "貧家望一麥，生事如毛起。", "薦饑當逐熟，西去真納履。"]'),
('1e82fded-46ed-4f11-86d0-167ee49061c4','還潁川','蘇轍','宋','宋诗','song-poetry','','[]','昔賢仕不遇，避世遊金馬。',120,'全唐诗/poet.song.49000.json','["昔賢仕不遇，避世遊金馬。", "嗟我獨何爲，不容在田野。", "欹區寄汝南，落泊反長社。", "東西俱畏人，何適可安者。", "故廬已荆榛，遺壠但松檟。", "頹齡迫衰暮，舊物一已捨。", "安能爲妻孥，辛苦問田舍。", "平生事瞿曇，心外知皆假。", "歸休得溟渤，坐受百川瀉。", "何人實造物，未聽相陶冶。"]'),
('40678a1b-91eb-421c-904e-8cdfd545bfa1','題郾城彼岸寺二首 文殊院古柏','蘇轍','宋','宋诗','song-poetry','','[]','曾看大柏孔明祠，行盡天涯未見之。',64,'全唐诗/poet.song.49000.json','["曾看大柏孔明祠，行盡天涯未見之。", "此樹便當稱子行，他山只可作孫枝。", "棟梁知是誰家用，舟楫唯應海水宜。", "日莫飛鴉集無數，青田老鶴未曾知。"]'),
('89be390c-2413-4e9e-8093-f156207a3649','題郾城彼岸寺二首 武宗元比部畫文殊玄奘','蘇轍','宋','宋诗','song-poetry','','[]','遺墨消磨顧陸餘，開元一一數吳盧。',64,'全唐诗/poet.song.49000.json','["遺墨消磨顧陸餘，開元一一數吳盧。", "本朝唯有宗元近，國本長留後世模。", "出世真人氣雍穆，入蕃老釋面清癯。", "居人不惜遊人愛，風雨侵陵色欲無。"]'),
('65ab233e-0a04-4482-b6af-f1dfb5149417','上巳日久病不出示兒侄二首  其一','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春氣侵脾久在床，開門桃李著泥香。',64,'全唐诗/poet.song.49000.json','["春氣侵脾久在床，開門桃李著泥香。", "牛鳴頗覺西湖近，鳳去長憐北榭荒。", "欲出老人無伴侶，退歸諸子解農桑。", "南鄰約賣千竿竹，拄杖穿林看笋長。"]'),
('3e660420-0b9a-48e3-aaeb-8bd062fb009d','上巳日久病不出示兒侄二首  其二','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','卧聞諸子到西湖，鵠鷺翩翩衆客俱。',64,'全唐诗/poet.song.49000.json','["卧聞諸子到西湖，鵠鷺翩翩衆客俱。", "紈扇藤鞋試輕駃，隻雞斗酒助歡娛。", "行歌久已饒渠輩，睡美猶應屬老夫。", "春服既成沂可浴，孔門世不乏迂儒。"]'),
('3ca83ab1-46a0-4b66-9415-934f62b6ac30','葺東齋','蘇轍','宋','宋诗','song-poetry','','[]','敝屋如燕巢，歲歲添泥土。',120,'全唐诗/poet.song.49000.json','["敝屋如燕巢，歲歲添泥土。", "泥多暫完潔，屋老終難固。", "况復非吾廬，聊爾避風雨。", "圖書易新幌，几杖移故處。", "宵眠不擇安，鼻息若炊釜。", "兒孫喜相告，定省便蚤莫。", "我生溪山間，弱冠衡茅住。", "生來乏華屋，所至輒成趣。", "苦恨無囊金，莫克償地主。", "投老付天公，著身豈無所。"]'),
('47686a8c-f929-411b-831a-538daaab4fc9','次遲韵千葉牡丹二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','潩上名園似洛濱，花頭種種鬥尖新。',64,'全唐诗/poet.song.49000.json','["潩上名園似洛濱，花頭種種鬥尖新。", "共傳青帝開金屋，欲遣姚黄比玉真。", "秦嶺猶應篆詩句，杜鵑直恐降天神。", "老人髮少花頭重，起舞欹斜酒力勻。"]'),
('456f6c0d-82ff-4e15-ab52-a0201fdb9f20','次遲韵千葉牡丹二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','老人無力年年懶，世事如花種種新。',64,'全唐诗/poet.song.49000.json','["老人無力年年懶，世事如花種種新。", "百巧從來知是妄，一機何處定非真。", "園夫漫接曾無種，物化相乘豈有神。", "畢竟春風不揀擇，隨開隨落自勻勻。"]'),
('be6baa62-b321-4d97-9752-4466818aa520','盆池白蓮','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白蓮生淤泥，清濁不相干。',144,'全唐诗/poet.song.49000.json','["白蓮生淤泥，清濁不相干。", "道人無室家，心迹兩蕭然。", "我住西湖濱，蒲蓮若雲屯。", "幽居常閉戶，時聽遊人言。", "色香世所共，眼鼻我亦存。", "鄰父閔我獨，遺我數寸根。", "潩水不入園，庭有三尺盆。", "兒童汲甘井，日晏泥水溫。", "及秋尚百日，花葉隨風翻。", "舉目得秀色，引息收清芬。", "此心湛不起，六塵空過門。", "誰家白蓮花，不受風霜殘。"]'),
('1f1f716c-e69c-43f4-bffe-2d5d1fd4c495','咏竹二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','湖濱宜草木，修竹可三尋。',48,'全唐诗/poet.song.49000.json','["湖濱宜草木，修竹可三尋。", "廛居多野思，移種近牆陰。", "及爾迷未醒，方予熱正侵。", "無嫌不逮本，地薄肯成林。"]'),
('070ebbfb-90f4-43cc-9025-5ed943fdff22','咏竹二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','南鄰竹甚茂，門巷不容賓。',48,'全唐诗/poet.song.49000.json','["南鄰竹甚茂，門巷不容賓。", "懸印君當往，囊金我患貧。", "翠旌稍亂起，犀角筍初勻。", "不惜圖書賣，端來作主人。"]'),
('082ac2de-4d7d-4eb4-b26f-e737d6f854fa','見兒侄唱酬次韵五首  其一','蘇轍','宋','宋诗','song-poetry','','[]','芝蘭生吾廬，一雨一增蒨。',48,'全唐诗/poet.song.49000.json','["芝蘭生吾廬，一雨一增蒨。", "本亦何預人，懷抱終眷眷。", "老傅時已迫，塵垢日須浣。", "永慚舊文書，展讀不終卷。"]'),
('7c296682-4332-483b-a6ac-9565669f42cb','見兒侄唱酬次韵五首  其二','蘇轍','宋','宋诗','song-poetry','','[]','讀書雖不惡，不讀亦自好。',48,'全唐诗/poet.song.49000.json','["讀書雖不惡，不讀亦自好。", "根牙就區別，花實隨時老。", "耘鋤不可無，雨露勿憂少。", "我釣不在魚，一竿寄洲島。"]'),
('7befb5f4-ab89-4e76-b620-0b200555c814','見兒侄唱酬次韵五首  其三','蘇轍','宋','宋诗','song-poetry','','[]','宇宙非不寬，閉門自爲阻。',48,'全唐诗/poet.song.49000.json','["宇宙非不寬，閉門自爲阻。", "心知外塵惡，且忍閑居苦。", "跏趺默非睡，龕燈翳復吐。", "道士爲我言，嬰兒出歌舞。"]'),
('e3001a3b-8dec-4a33-8f94-49ed469e4940','見兒侄唱酬次韵五首  其四','蘇轍','宋','宋诗','song-poetry','','[]','身病要須閑，閑極自成趣。',48,'全唐诗/poet.song.49000.json','["身病要須閑，閑極自成趣。", "空虛雖近道，懶拙初非悟。", "偶將今生脚，還着古人屨。", "大小適相同，本來無別處。"]'),
('7e2a9257-a343-4ab0-8847-22b50d290cfe','見兒侄唱酬次韵五首  其五','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖雖不到，甘井竊餘凉。',48,'全唐诗/poet.song.49000.json','["西湖雖不到，甘井竊餘凉。", "三伏罷飲酒，桂漿携一觴。", "冠者五六人，起舞互低昂。", "人生有離合，此歡未易忘。"]'),
('1f525165-435e-4428-b1c3-d7e5024366c8','初得南園','蘇轍','宋','宋诗','song-poetry','','[]','倒囊僅得千竿竹，掃地初開一畝宮。',64,'全唐诗/poet.song.49000.json','["倒囊僅得千竿竹，掃地初開一畝宮。", "千里故園魂夢裏，百年生事寂寥中。", "晏家不願諸侯賜，顔氏終成陋巷風。", "洗竹移花吾事了，子孫他日記衰翁。"]'),
('078a8525-8aff-45bb-bb50-c08f946b1e07','移竹','蘇轍','宋','宋诗','song-poetry','','[]','牆陰竹蒙密，板築念相妨。',48,'全唐诗/poet.song.49000.json','["牆陰竹蒙密，板築念相妨。", "欲補園東缺，欣乘雨後凉。", "三年生筍遍，一徑引風長。", "但恐翁彌老，筇枝懶復將。"]'),
('b2813def-98c6-4c4d-a330-8a287a29e2fe','記夢','蘇轍','宋','宋诗','song-poetry','','[]','長魚三尺困橫盆，送入清流喜欲奔。',32,'全唐诗/poet.song.49000.json','["長魚三尺困橫盆，送入清流喜欲奔。", "報我金匙僅盈寸，擲還聊喜不貪存。"]'),
('34f45ba1-7483-4246-97a6-c57e037eb3d4','葺居五首  其一','蘇轍','宋','宋诗','song-poetry','','[]','南堂初一家，隔絕歲月久。',48,'全唐诗/poet.song.49000.json','["南堂初一家，隔絕歲月久。", "開牆北風入，爽氣通戶牖。", "棟梁未摧折，斤斧聊結構。", "非言事輪奐，粗反昔人舊。"]'),
('dfb460c4-e16b-47a3-9cdc-56cbb110c870','葺居五首  其二','蘇轍','宋','宋诗','song-poetry','','[]','庭方止數尋，風月所從入。',48,'全唐诗/poet.song.49000.json','["庭方止數尋，風月所從入。", "百年養毒樹，攢芒比刀戟。", "伐之念生久，不伐愁跣足。", "且復爲人謀，庖椹利朝食。"]'),
('aa62886a-0896-4974-bce9-98628ceb4af1','葺居五首  其三','蘇轍','宋','宋诗','song-poetry','','[]','竹林失蕃養，春筍日瑣細。',48,'全唐诗/poet.song.49000.json','["竹林失蕃養，春筍日瑣細。", "草蔓半縈纏，樗櫟互虧蔽。", "已令具刀鐮，稍俟秋霜厲。", "欲成林下飲，更種園東地。"]'),
('9bee0428-d1fc-4a53-aef9-6eb40aba26c6','葺居五首  其四','蘇轍','宋','宋诗','song-poetry','','[]','雜花生竹間，竹荒花亦瘁。',48,'全唐诗/poet.song.49000.json','["雜花生竹間，竹荒花亦瘁。", "移花通狂鞭，春到兩皆遂。", "牆東破茅屋，排去收遺址。", "時來拾瓦礫，細細留花地。"]'),
('b6eef97b-0425-4d5e-92be-ce1ba1eba6c4','葺居五首  其五','蘇轍','宋','宋诗','song-poetry','','[]','東南皆民居，屋敗如齬齒。',48,'全唐诗/poet.song.49000.json','["東南皆民居，屋敗如齬齒。", "一完誠未能，綴葺聊且爾。", "內修晨夜虞，外結比鄰喜。", "無心本何營，生理未免此。"]'),
('a64ac072-c6b2-4427-bf40-227447b7477a','再賦葺居三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','誰將修竹寄鄰家，秋斫長竿春食芽。',32,'全唐诗/poet.song.49000.json','["誰將修竹寄鄰家，秋斫長竿春食芽。", "旋築高牆護鷄犬，稍容嵇阮醉喧嘩。"]'),
('8d4b4112-791a-4208-8069-f4e5cf30ed3c','再賦葺居三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','短垣疏戶略藏遮，翠竹長松夾徑斜。',32,'全唐诗/poet.song.49000.json','["短垣疏戶略藏遮，翠竹長松夾徑斜。", "遊宦歸來四十載，粗成好事一田家。"]'),
('23d119eb-7032-4ba8-a651-3ca8c53bdbdb','再賦葺居三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','南北高堂本富家，百年梁柱半欹斜。',32,'全唐诗/poet.song.49000.json','["南北高堂本富家，百年梁柱半欹斜。", "略教扶起猶堪住，西望吾廬已自奢。"]'),
('27d02d83-e387-4ef9-a85e-5abe4e14e1e0','歲莫口號二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','六十年來又七年，眼昏頭白意茫然。',32,'全唐诗/poet.song.49000.json','["六十年來又七年，眼昏頭白意茫然。", "逢人欲說平生舊，少有能知兩世前。"]'),
('1393651f-680e-422b-b7ca-c8afc67d7caf','歲莫口號二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','兩世相從今幾人，回頭强半已埃塵。',32,'全唐诗/poet.song.49000.json','["兩世相從今幾人，回頭强半已埃塵。", "此心點檢終如一，時事無端日日新。"]'),
('a5ff45c3-9c8f-4cdd-aaf6-ff39694d2ad0','雪後小酌贈內','蘇轍','宋','宋诗','song-poetry','','[]','薄雪爲燈止，和風應節來。',48,'全唐诗/poet.song.49000.json','["薄雪爲燈止，和風應節來。", "出遊吾已懶，小酌意難裁。", "竹徑泥方滑，菁畦凍欲開。", "細君憐老病，加料作新醅。"]'),
('8621df98-9f6e-46bf-9bb4-683469ca5b3f','喜雨','蘇轍','宋','宋诗','song-poetry','','[]','奪官分所甘，年來祿又絕。',168,'全唐诗/poet.song.49000.json','["奪官分所甘，年來祿又絕。", "天公尚憐人，歲賫禾與麥。", "經冬雪屢下，根鬚連地脈。", "庖厨望餠餌，甕盎思麯糵。", "一春百日旱，田作龜板拆。", "老農淚欲墮，無麥真無食。", "朱明候纔兆，風雷起通夕。", "田中有人至，膏潤已逾尺。", "繼來不違願，飽食真可必。", "民生亦何幸，天意每相恤。", "我幸又已多，鋤耒坐不執。", "同爾樂豐穰，異爾苦稅役。", "時聞吏號呼，手把縣符赤。", "歲賦行自辦，橫斂何時畢。"]'),
('b2404468-f9ad-4c41-ab7d-b01988d32e9d','收蜜蜂','蘇轍','宋','宋诗','song-poetry','','[]','空中蜂隊如車輪，中有王子蜂中尊。',128,'全唐诗/poet.song.49000.json','["空中蜂隊如車輪，中有王子蜂中尊。", "分房減口未有處，野老解與蜂語言。", "前人傳蜜延客住，後人秉艾催客奔。", "布囊包裹鬧如市，坌入竹屋新且完。", "小窗出入旋知路，幽圃首夏花正繁。", "相逢處處命儔侶，共入新宅長子孫。", "今年活計知尚淺，蜜蠟未暇分主人。", "明年少割助和藥，慚愧野老知利源。"]'),
('0c5266c7-5b42-4747-8af4-56b6c227ddab','養竹','蘇轍','宋','宋诗','song-poetry','','[]','病竹養經年，生筍大如母。',120,'全唐诗/poet.song.49000.json','["病竹養經年，生筍大如母。", "初番放出林，末番任供口。", "欲求五寸圍，更聽三年後。", "蕭疏盡椽桷，無復堪作帚。", "吾廬適營葺，便可開戶牖。", "秀色到衣冠，清風盪塵垢。", "物生恨失養，養至無不厚。", "斧斤日摧剝，陰陽自難救。", "閑居玩草木，農圃即師友。", "養人如養竹，舉目皆孝秀。"]'),
('427d5d18-274a-42d2-94b3-0b31f033b9bc','和遲田舍雜詩九首  其一','蘇轍','宋','宋诗','song-poetry','','[]','麥生置不視，麥熟爲一來。',48,'全唐诗/poet.song.49000.json','["麥生置不視，麥熟爲一來。", "我懶客亦惰，田荒誰使開。", "勤事知有獲，直駕獨未回。", "交遊悉吾病，門巷多蒼苔。"]'),
('aafc57b5-660e-406e-b5bb-85e4e36788cd','和遲田舍雜詩九首  其二','蘇轍','宋','宋诗','song-poetry','','[]','我生無定居，投老旋求宅。',48,'全唐诗/poet.song.49000.json','["我生無定居，投老旋求宅。", "未暇棟宇完，先問松筠碧。", "床銳日益銷，車轄轉生澀。", "東家雖告貧，鬻否猶未必。"]'),
('19c3fc8e-2887-4050-97d2-6c054281a3f4','和遲田舍雜詩九首  其三','蘇轍','宋','宋诗','song-poetry','','[]','偶自十年閑，非繼七人作。',48,'全唐诗/poet.song.49000.json','["偶自十年閑，非繼七人作。", "早歲漫云云，志大終落落。", "齒髮已半空，頭顱不難度。", "顔曾本吾師，終身美藜藿。"]'),
('56288301-3fd8-4fc8-9ae4-eb5887de6a9a','和遲田舍雜詩九首  其四','蘇轍','宋','宋诗','song-poetry','','[]','至人竟安在，陶鑄皆粃糠。',48,'全唐诗/poet.song.49000.json','["至人竟安在，陶鑄皆粃糠。", "世俗那得知，楚楚事冠裳。", "方醉狂正作，吾語未可莊。", "天定能勝人，更看熟黄粱。"]'),
('a85bc1e7-2ac7-43bb-a8f6-e157ba9efcf2','和遲田舍雜詩九首  其五','蘇轍','宋','宋诗','song-poetry','','[]','平湖近西垣，杖屨可以遊。',48,'全唐诗/poet.song.49000.json','["平湖近西垣，杖屨可以遊。", "偶從大夫後，不往三經秋。", "盎中插蒲蓮，菱芡亦易求。", "閉門具樽俎，父子相獻酬。"]'),
('c43eebb2-33e3-4e3d-a3af-16b0aacd6eb9','和遲田舍雜詩九首  其六','蘇轍','宋','宋诗','song-poetry','','[]','試問西寺僧，云何古佛意。',48,'全唐诗/poet.song.49000.json','["試問西寺僧，云何古佛意。", "別無安心法，但復餠師餽。", "外物來無從，往亦無所至。", "佛法見在前，我亦從此逝。"]'),
('097f79b5-422f-4369-af81-e918592aa867','和遲田舍雜詩九首  其七','蘇轍','宋','宋诗','song-poetry','','[]','老佛同一源，出山便異流。',48,'全唐诗/poet.song.49000.json','["老佛同一源，出山便異流。", "少小本好道，意在三神洲。", "子房見黄石，願封小國留。", "終老預人事，斷穀爲呂憂。"]'),
('37cd742c-b727-4730-8857-05cc5e1896db','和遲田舍雜詩九首  其八','蘇轍','宋','宋诗','song-poetry','','[]','蒼然澗下松，不願世雕刻。',48,'全唐诗/poet.song.49000.json','["蒼然澗下松，不願世雕刻。", "斧斤百夫手，牽挽千牛力。", "斷成華屋柱，加以綴衣飾。", "人心喜相賀，松心終自惜。"]'),
('60908571-394d-4cb3-bc33-b5aa54a877d8','和遲田舍雜詩九首  其九','蘇轍','宋','宋诗','song-poetry','','[]','汲汲陷有爲，昏昏墮無記。',48,'全唐诗/poet.song.49000.json','["汲汲陷有爲，昏昏墮無記。", "湛然古井水，心在獨無意。", "讀書非求解，食粟姑自遂。", "幸有三男子，力田奉租稅。"]'),
('bc3760a4-0b6c-4578-bdaf-ef312454870c','雨病','蘇轍','宋','宋诗','song-poetry','','[]','晴送麥入倉，雨催穀含穗。',144,'全唐诗/poet.song.49000.json','["晴送麥入倉，雨催穀含穗。", "共怪天公仁，曲盡老農意。", "誰爲三日霖，下漉一丈地。", "百谷爭奔流，通川不可厲。", "夜聞屋山落，晝說城闉閉。", "老羸知奈何，脾病尤所畏。", "中宵得暴下，亭午卧忘起。", "良醫過我言，勿藥行自喜。", "損食存谷神，收心辟邪氣。", "兀然槁木居，油爾元和至。", "天唯不窮人，人則昧其理。", "學道三十年，愧爾良醫賜。"]'),
('1b17e73e-7190-4436-8f8b-912773d6fc01','施崇寧寺馬','蘇轍','宋','宋诗','song-poetry','','[]','南歸閉門萬事了，病卧常多起常少。',128,'全唐诗/poet.song.49000.json','["南歸閉門萬事了，病卧常多起常少。", "未用田間下澤車，何須櫪上追風驃。", "鄉人記我少年日，滇馬爲致風前鳥。", "三年伏櫪人共怪，馬不能言心可曉。", "坐馳千里氣蟠結，日食生芻空自笑。", "主人自是箕潁人，誰復爲送洮岷道。", "支公惠眼識神駿，山下泉甘足芳草。", "法流一洗百病消，翹足長鳴且忘老。"]'),
('917818ad-4ed1-4590-8a6f-51cffd2f2e1f','南堂新遊花壇二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','亂竹侵紅藥，病花羞晚春。',48,'全唐诗/poet.song.49000.json','["亂竹侵紅藥，病花羞晚春。", "移根近談笑，得土長精神。", "榮悴非由爾，芬芳止爲人。", "庭西井泉好，汲灌每躬親。"]'),
('a6377f10-1753-406d-893c-635edb6845ab','南堂新遊花壇二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','老木不忍伐，橫枝宜少除。',48,'全唐诗/poet.song.49000.json','["老木不忍伐，橫枝宜少除。", "根莖漸有託，雨露稍分餘。", "生意初無損，開花終自如。", "他年諸草木，成就此幽居。"]'),
('5dbb3ea1-556f-4f53-b29f-e62c7837cb9b','夢中謝和老惠茶','蘇轍','宋','宋诗','song-poetry','','[]','西鄰禪師憐我老，北苑新茶惠初到。',64,'全唐诗/poet.song.49000.json','["西鄰禪師憐我老，北苑新茶惠初到。", "晨興已覺三嗅多，午枕初便一杯少。", "七碗煎嘗病未能，兩腋風生空自笑。", "定中直往蓬萊山，盧老未應知此妙。"]'),
('3e04c261-54ae-47eb-a479-1f96b9923646','新霜','蘇轍','宋','宋诗','song-poetry','','[]','敗檐疏戶秋寒早，老人脚冷先知曉。',64,'全唐诗/poet.song.49000.json','["敗檐疏戶秋寒早，老人脚冷先知曉。", "濃霜滿地作微雪，落葉投空似飛鳥。", "新舂未覺廩庾空，宿逋暗奪衾稠少。", "旱田首種未言入，敢信來年真食麨。"]'),
('13576616-9e7b-4082-860e-0c0ca2627f2d','戲作家釀二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','方暑儲麯糵，及秋舂秫稻。',120,'全唐诗/poet.song.49000.json','["方暑儲麯糵，及秋舂秫稻。", "甘泉汲桐柏，火候問鄰媼。", "唧唧鳴甕盎，暾暾化梨棗。", "一撥欣已熟，急搊嫌不早。", "病色變渥丹，羸軀驚醉倒。", "子雲多交遊，好事時相造。", "嗣宗尚出仕，兵厨可常到。", "嗟我老杜門，奈此平生好。", "未出禁酒國，耻爲甕間盜。", "一醉汁滓空，入腹誰復告。"]'),
('829857fc-44b6-49cd-afd4-a8e1475a032b','戲作家釀二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','我飲半合耳，晨興不可無。',144,'全唐诗/poet.song.49000.json','["我飲半合耳，晨興不可無。", "千錢買一斗，衆口分須臾。", "月俸本有助，法許吏未俞。", "愍愍坐相視，饞涎落盤盂。", "潁潩舊乏水，粳糯貴如珠。", "今年利陂堨，碓聲喧里閭。", "典衣易鍾釜，入甕生醍醐。", "歡欣走童孺，左右陳肴蔬。", "細酌奉翁媼，餘潤霑庖厨。", "詰朝日南至，相戒留全壺。", "一家有喜色，經冬可無沽。", "莫怪杜拾遺，斗水寬憂虞。"]'),
('82f03b51-01fc-4ce1-bbf6-e4bf91a4504e','冬至雪','蘇轍','宋','宋诗','song-poetry','','[]','旱久魃不死，連陰未成雪。',96,'全唐诗/poet.song.49000.json','["旱久魃不死，連陰未成雪。", "微陽九地來，顛風三日發。", "父老竊相語，號令風爲節。", "講武罷冬夫，畿甸休保甲。", "纍囚出死地，冗官去煩雜。", "手詔可人心，吾君信明哲。", "風頻雪猶吝，來歲恐無麥。", "天公聽一言，惟幸早誅魃。"]'),
('08dd4fe9-bdeb-4e4d-9e90-5ccefa342f87','歲莫二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','嶺南萬里歸來客，潁上六年多病身。',64,'全唐诗/poet.song.49000.json','["嶺南萬里歸來客，潁上六年多病身。", "未死誰言猶有命，長閑豈復更尤人。", "眼看世事知難了，手注遺編近一新。", "點檢平生無幾恨，濁醪初熟正逢春。"]'),
('6cf7e8e9-3193-4d8a-9bb2-33efdffa4067','歲莫二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','文章習氣消未盡，般若初心老漸明。',64,'全唐诗/poet.song.49000.json','["文章習氣消未盡，般若初心老漸明。", "粗有春秋傳舊學，終憑止觀定無生。", "維摩晚亦諧生事，彌勒初猶重世名。", "鬚髮來年應更白，莫留塵滓溷澄清。"]'),
('1ae41037-74df-48e6-b0df-7fbefb8a109b','春後望雪','蘇轍','宋','宋诗','song-poetry','','[]','秋雨僅熟禾，冬雪不揜塊。',120,'全唐诗/poet.song.49000.json','["秋雨僅熟禾，冬雪不揜塊。", "溫風搜麥根，天意欲爲害。", "老農强推測，妄謂春當改。", "三陽已換節，六出尚茫昧。", "朝看扶桑暾，夜聽土囊噫。", "倉場久空竭，榆棗方伐賣。", "丁夫病風熱，孺子作瘡疥。", "無知此何辜，得罪彼有在。", "造物伊誰憎，亦復自無奈。", "慎勿翻雪海，凍餒無疆界。"]'),
('f3a05261-6ab9-4b8c-8bff-0631d907fd69','除夜','蘇轍','宋','宋诗','song-poetry','','[]','年更六十七，旬滿三百六。',72,'全唐诗/poet.song.49000.json','["年更六十七，旬滿三百六。", "俯仰定何爲，萬事如轉轂。", "禪心澹不起，非人自歌哭。", "芸芸初莫禦，勢盡行將復。", "學道道可成，無心心每足。", "守歲聽兒曹，自笑未免俗。"]'),
('8cb16f71-d83d-49a0-87b1-5c64e5d500f3','喜雨','蘇轍','宋','宋诗','song-poetry','','[]','歷時書不雨，此法存春秋。',120,'全唐诗/poet.song.49000.json','["歷時書不雨，此法存春秋。", "我請誅旱魃，天公信聞不。", "魃去未出門，油雲裹嵩丘。", "濛濛三日雨，入土如膏流。", "二麥返生意，百草萌芽抽。", "農夫但相賀，漫不知其由。", "魃來有巢穴，遺卵遍九州。", "一掃不能盡，餘孽未遽休。", "安得風雨師，速遣雷霆搜。", "衆魃誠已去，秋成儻無憂。"]'),
('9b0b2978-9ac1-44e3-8e90-4086c5d16845','甲子日雨','蘇轍','宋','宋诗','song-poetry','','[]','一冬無雪麥方病，細雨迎春歲有望。',64,'全唐诗/poet.song.49000.json','["一冬無雪麥方病，細雨迎春歲有望。", "愁見積陰連甲子，復令父老念耕桑。", "瘦田未足終年計，濁酒誰供清旦嘗。", "頼有真人不饑渴，閉門却掃但焚香。"]'),
('aefbb45d-0f8e-4f7b-8baa-0c996a160609','新火','蘇轍','宋','宋诗','song-poetry','','[]','百口共一竈，終年事烹煎。',96,'全唐诗/poet.song.49000.json','["百口共一竈，終年事烹煎。", "力耕飼饑饞，竈敝火亦煩。", "昨日一百五，老穉俱食寒。", "呼童戛枯竹，粲然吐青煙。", "適從何方來，熒熒百家傳。", "性火出真空，應量曾無邊。", "老病何所求，石瓶煮寒泉。", "斂爲一夫用，無心固當然。"]'),
('0b220fef-81c2-4617-954f-699913f7e709','次韵和人咏酴醾','蘇轍','宋','宋诗','song-poetry','','[]','蜀中酴醾生如積，開落春風山寂寂。',128,'全唐诗/poet.song.49000.json','["蜀中酴醾生如積，開落春風山寂寂。", "已憐正發香晻曖，猶愛未開光的皪。", "半垂野水弱如墜，直上長松勇無敵。", "風中娜娜應數丈，月下煌煌真一色。", "故園聞道開愈繁，老人自恨歸無日。", "百花已過春欲莫，燕坐繩床空數息。", "朝來滿把得幽香，案頭亂插銅瓶濕。", "一番花蕊轉頭空，誰能往問天台拾。"]'),
('6af72bce-1c40-4774-99e8-683430a210e8','閑居五咏 杜門','蘇轍','宋','宋诗','song-poetry','','[]','可憐杜門久，不覺杜門非。',72,'全唐诗/poet.song.49000.json','["可憐杜門久，不覺杜門非。", "床銳日日銷，髀肉年年肥。", "眼暗書罷讀，肺病酒亦稀。", "經年客不至，不冠仍不衣。", "視聽了不昧，色聲久已微。", "終然渾爲一，誰言我無歸。"]'),
('27164456-7454-4df4-b890-4d4e78cc65e6','閑居五咏 坐忘','蘇轍','宋','宋诗','song-poetry','','[]','少年常病肺，納息肺自斂。',72,'全唐诗/poet.song.49000.json','["少年常病肺，納息肺自斂。", "靈液洗昏煩，百藥無此驗。", "爾來觀坐忘，一語頓非漸。", "道妙有至力，端能破諸暗。", "跏趺百無營，純白乃受染。", "至人不妄言，此說豈吾僭。"]'),
('3c014c2c-e425-4e25-8bc7-b55df535fac9','閑居五咏 讀書','蘇轍','宋','宋诗','song-poetry','','[]','習氣不易除，書魔閒即至。',72,'全唐诗/poet.song.49000.json','["習氣不易除，書魔閒即至。", "圖史紛滿前，展卷輒忘睡。", "古今浩無垠，得失同一軌。", "前人已不悟，今人復如此。", "愍然嫠婦憂，嗟哉肉食鄙。", "掩卷勿重陳，慟哭傷人氣。"]'),
('8bfd2ea3-6232-4f00-b7e2-7211be398a64','閑居五咏 買宅','蘇轍','宋','宋诗','song-poetry','','[]','我老未有宅，諸子以爲言。',72,'全唐诗/poet.song.49000.json','["我老未有宅，諸子以爲言。", "東家欲遷去，餘積尚可捐。", "一費豈不病，百口儻獲安。", "田家伐榆棗，賦役輸緡錢。", "長大可雙棟，瑣細堪尺椽。", "生理付兒曹，老幸食且眠。"]'),
('f1581d30-81aa-4f7b-b368-777671d0cbd8','閑居五咏 移竹','蘇轍','宋','宋诗','song-poetry','','[]','前年買南園，本爲一畝竹。',72,'全唐诗/poet.song.49000.json','["前年買南園，本爲一畝竹。", "稍去千百竿，欲廣西南屋。", "本心初不爾，百口居未足。", "黽勉斤斧餘，慚愧琅玕綠。", "東園有餘地，補種何年復。", "凜凜歲寒姿，餘木非此族。"]'),
('cc19afbc-d786-499e-8ce1-aaf13df5ea05','城中牡丹推高皇廟園遲适聯騎往觀歸報未開戲作','蘇轍','宋','宋诗','song-poetry','','[]','漢廟名園甲潁昌，洛川珍品重姚黄。',64,'全唐诗/poet.song.49000.json','["漢廟名園甲潁昌，洛川珍品重姚黄。", "雨餘往看初疑晚，春盡方開自不忙。", "爭占一時人意速，養成千葉化功長。", "老人終歲關門坐，花落花開已兩忘。"]'),
('849f23f9-c943-44aa-a2a7-2b94bda3d039','外孫文驥與可學士之孫也予親教之學作詩俊發猶有家風喜其不墜作詩贈之','蘇轍','宋','宋诗','song-poetry','','[]','已矣石室老，奄然三十年。',48,'全唐诗/poet.song.49000.json','["已矣石室老，奄然三十年。", "遺孫生不識，妙理定誰傳。", "孔伋仍聞道，賈嘉終象賢。", "文章猶細事，風節記高堅。"]'),
('5c2f9db7-a25e-46f4-8dc2-a1a89d47c590','春深三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','郊原紅綠變青陰，閉戶不知春已深。',64,'全唐诗/poet.song.49000.json','["郊原紅綠變青陰，閉戶不知春已深。", "稍喜荒畦添野薺，坐看新竹補疏林。", "簾中飛絮縈殘夢，窗外啼鶑伴獨吟。", "欲聽楞嚴終懶出，道人知我祖無心。"]'),
('d3f07280-df08-4fed-9012-b9df003f7d9b','春深三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','小園松竹有清陰，懶病從茲日益深。',64,'全唐诗/poet.song.49000.json','["小園松竹有清陰，懶病從茲日益深。", "醉客滿堂慚北海，野僧同社憶東林。", "逢人問道空長嘯，久客思歸尚越吟。", "三十年前誦圓覺，年來雖老解安心。"]'),
('8b0bce3b-0362-4159-8130-84855f1961a4','春深三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','偶有茅檐潩水陰，近依城市淺非深。',64,'全唐诗/poet.song.49000.json','["偶有茅檐潩水陰，近依城市淺非深。", "幽居每自比陳寔，古學何人貴杜林。", "鄰父時來陪小飲，兒曹頗解續微吟。", "前年僅了春秋傳，後有仁人知我心。"]'),
('678032ee-d6b0-4322-9ff5-d5a26fb40487','次遲韵示陳天倪秀才侄孫元老主簿','蘇轍','宋','宋诗','song-poetry','','[]','茅檐有佳客，肅肅清風興。',96,'全唐诗/poet.song.49000.json','["茅檐有佳客，肅肅清風興。", "吾孫成均來，左右皆良朋。", "爲憐衆兄弟，將冠未有稱。", "條枚失熂燎，中林化薪蒸。", "老夫方苦貧，不辦酒如澠。", "夏田已失麥，種豆喜多蠅。", "何以待君子，簞瓢容一升。", "君來豈非誤，門庭冷如冰。"]'),
('68c2a4a3-da69-4036-8700-3f21d0c0e574','再次前韵示元老','蘇轍','宋','宋诗','song-poetry','','[]','豪傑多自悟，不待文王興。',96,'全唐诗/poet.song.49000.json','["豪傑多自悟，不待文王興。", "四方有餘師，十室豈無朋。", "我老不知時，早歲誰誤稱。", "歸來理茅屋，對客食藜蒸。", "遇渴即飲水，何嘗問淄澠。", "冠裳强包裹，毀譽如飛蠅。", "植根久已爾，苕穎日自升。", "忘我亦忘法，無冰知消冰。"]'),
('9aece693-ae25-4398-896e-3533ad0fc355','築室示三子','蘇轍','宋','宋诗','song-poetry','','[]','宅舍元依畢竟空，小乘慣住草庵中。',64,'全唐诗/poet.song.49000.json','["宅舍元依畢竟空，小乘慣住草庵中。", "一生滯念餘妻子，百口僑居怯雨風。", "松竹已栽猶稍稍，棟梁未具勿匆匆。", "三間道院吾真足，餘問兒曹莫問翁。"]'),
('1b63f45c-7c48-4fbb-b166-8d6f32a51a0b','開窗','蘇轍','宋','宋诗','song-poetry','','[]','綠竹琅玕色，紅葵旌節花。',48,'全唐诗/poet.song.49000.json','["綠竹琅玕色，紅葵旌節花。", "開窗風細細，窺戶月斜斜。", "活計無多子，文章自一家。", "一床方病卧，隨意上三車。"]'),
('322c72f2-e4d0-4f43-bc8d-c5b06c6f5828','遜往泉城穫麥','蘇轍','宋','宋诗','song-poetry','','[]','少年食稻不食粟，老居潁川稻不足。',160,'全唐诗/poet.song.49000.json','["少年食稻不食粟，老居潁川稻不足。", "人言小麥勝西川，雪花落磨煮成玉。", "冷淘槐葉冰上齒，湯餠羊羹火入腹。", "五年隨俗粗得飽，晨朝稻米纔供粥。", "兒曹知我老且饞，觸熱泉城正三伏。", "田家有信呼即來，亭午驅牛汗如浴。", "吾兒生來讀書史，不慣田間爭斗斛。", "今年久旱麥粒細，及半罷休饒老宿。", "歸來爛熳煞蒼耳，來歲未知還爾熟。", "百口且留終歲儲，貧交强半倉無穀。"]'),
('317e4052-3650-4e70-9de4-3425bc297552','送元老西歸','蘇轍','宋','宋诗','song-poetry','','[]','晝錦西歸及早秋，十年太學爲親留。',64,'全唐诗/poet.song.49000.json','["晝錦西歸及早秋，十年太學爲親留。", "讀詩俛就當年說，答策甘從下第收。", "莫嫌簿領妨爲學，從此文章始自由。", "家有吏師遺躅在，當令耆舊識風流。"]'),
('66b96ed4-7b95-473b-b4c9-4f095ce51c42','蜀人舊食决明花耳潁川夏秋少菜崇寧老僧教人并食其葉有鄉人西歸使爲父老言之戲作','蘇轍','宋','宋诗','song-poetry','','[]','秋蔬舊採决明花，三嗅馨香每嘆嗟。',32,'全唐诗/poet.song.49000.json','["秋蔬舊採决明花，三嗅馨香每嘆嗟。", "西寺衲僧并食葉，因君說與故人家。"]'),
('8ef05175-c879-44d8-a4b2-d43f13595729','諸子將築室以畫圖相示三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','還家卜築初無地，隨分經營似有時。',64,'全唐诗/poet.song.49000.json','["還家卜築初無地，隨分經營似有時。", "多斫修篁終未忍，略存古柏更無疑。", "畫圖且作百間計，入室猶應三歲期。", "得到安居真老矣，一生歌哭任於斯。"]'),
('c40a1b99-23a6-44ac-9838-e8f2086eab3d','諸子將築室以畫圖相示三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','舊廬近已借諸子，新宅分甘臨老時。',64,'全唐诗/poet.song.49000.json','["舊廬近已借諸子，新宅分甘臨老時。", "萬里松楸終獨往，四方兄弟亦何疑。", "竹間疏戶幽人到，林上長松野鶴期。", "已覺高軒慚衛賜，可憐黄犬哭秦斯。"]'),
('ef65ddec-103d-416f-b8bf-1a30bf9bc88f','諸子將築室以畫圖相示三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','積因得果通三世，臨老長閑自一時。',64,'全唐诗/poet.song.49000.json','["積因得果通三世，臨老長閑自一時。", "久爾觀心終未悟，偶然見道了無疑。", "南遷北返吾何病，片瓦尺椽天與期。", "自斷此生今已矣，世間何物更如斯。"]'),
('59057cf9-9d5c-4b96-bff8-b141ebc795c1','題韓駒秀才詩卷','蘇轍','宋','宋诗','song-poetry','','[]','唐朝文士例能詩，李杜高深得到希。',32,'全唐诗/poet.song.49000.json','["唐朝文士例能詩，李杜高深得到希。", "我讀君詩笑無語，恍然重見儲光羲。"]'),
('f54ba8fa-517b-44c8-a68a-938563a9ba10','秋社分題','蘇轍','宋','宋诗','song-poetry','','[]','天公閔貧病，雨止得豐穰。',48,'全唐诗/poet.song.49000.json','["天公閔貧病，雨止得豐穰。", "南畝場功作，東家社酒香。", "分均思孺子，歸遺笑東方。", "肯勸拾遺住，休嫌父老狂。"]'),
('a2ad8e75-697d-4f4d-88de-28805a8080f9','釀重陽酒','蘇轍','宋','宋诗','song-poetry','','[]','風前隔年麯，甕裏重陽酒。',120,'全唐诗/poet.song.49000.json','["風前隔年麯，甕裏重陽酒。", "適從臺無餽，飲啜不濡口。", "秋嘗日已迫，收拾煩主婦。", "仰空露成霜，搴庭菊將秀。", "金微火猶壯，未可多覆篰。", "唧唧候鳴聲，涓涓報初溜。", "輕巾漉糟脚，寒泉養罌缶。", "誰來共嘉節，但約鄰人父。", "生理正艱難，一醉陶衰朽。", "他年或豐餘，此味恐無有。"]'),
('6679b612-5103-4472-be16-33b739a50219','中秋無月同諸子二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','風雨來無定，泥塗日向深。',48,'全唐诗/poet.song.49000.json','["風雨來無定，泥塗日向深。", "直埋今夜月，真失衆人心。", "雲外天衢凈，人間濁霧侵。", "幽人久不寐，起坐夜愔愔。"]'),
('da199106-64cc-4d89-abd2-a1792e55b0d4','中秋無月同諸子二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','捲衣換斗酒，欲飲月明中。',48,'全唐诗/poet.song.49000.json','["捲衣換斗酒，欲飲月明中。", "坐看浮雲合，遥憐四海同。", "清光知未泯，來歲尚無窮。", "且盡樽中淥，高眠聽雨風。"]'),
('beaf2458-927d-4961-9a54-9d3d9e2b55b1','予昔在京師畫工韓若拙爲予寫真今十三年矣容貌日衰展卷茫然葉縣楊生畫不減韓復令作之以記其變偶作','蘇轍','宋','宋诗','song-poetry','','[]','白髮蒼顔日日新，丹青猶是舊來身。',64,'全唐诗/poet.song.49000.json','["白髮蒼顔日日新，丹青猶是舊來身。", "百年迅速何曾住，方寸空虛老更真。", "一幅蕭條寄衰朽，異時仿佛見精神。", "近存八十一章注，從道老聃門下人。"]'),
('2b5b90f1-2d02-49a5-8db0-1761bc05b9d6','九日獨酌三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','府縣嫌吾舊黨人，鄉鄰畏我昔黄門。',64,'全唐诗/poet.song.49000.json','["府縣嫌吾舊黨人，鄉鄰畏我昔黄門。", "終年閉戶已三歲，九日無人共一樽。", "白酒近令沽野店，黄花旋遣折籬根。", "老妻也說無生話，獨酌油然對子孫。"]'),
('d202aa78-e4f0-40a1-9de3-435322464a27','九日獨酌三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','故國忘歸懶問人，新居斫竹旋開門。',64,'全唐诗/poet.song.49000.json','["故國忘歸懶問人，新居斫竹旋開門。", "菊生牆下不知節，酒滴床頭初滿樽。", "漲水驟來真有浪，浮雲卷去自無根。", "凡心漫作潁濱傳，留與他年好事孫。"]'),
('1b6e087d-bb08-4056-999b-714effb34603','九日獨酌三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','平昔交遊今幾人，後生誰復款吾門。',64,'全唐诗/poet.song.49000.json','["平昔交遊今幾人，後生誰復款吾門。", "茅檐適性輕華屋，黍酒忘形敵上樽。", "東圃旋移花百本，西軒恨斫竹千根。", "舍南頼有凌雲柏，父老經過說二孫。"]'),
('718d7b75-b84e-41b8-93b5-b9e6d49c2a62','泉城田舍','蘇轍','宋','宋诗','song-poetry','','[]','泉城欲治麥禾囷，五畝鄰家肯見分。',64,'全唐诗/poet.song.49000.json','["泉城欲治麥禾囷，五畝鄰家肯見分。", "莫問三吳朱處士，似勝吾鄉揚子雲。", "陰晴卒歲關憂喜，豐約終身看逸勤。", "家世本來耕且養，諸孫不用耻鋤耘。"]'),
('add4dbf3-865c-4769-8f06-01b8c4e69db1','潁州擇勝亭詩','蘇轍','宋','宋诗','song-poetry','','[]','我嗟世人，誰實與謀。',240,'全唐诗/poet.song.49000.json','["我嗟世人，誰實與謀。", "生伏其廬，死安於丘。", "既成不化，窘若縶囚。", "我行四方，所見或不。", "江海之民，生託于舟。", "前炊釜鬵，後鑿匽溲。", "晝設豆觴，夕張衾稠。", "出入濤瀾，歸宿汀洲。", "與風皆行，與水皆浮。", "坐食網罟，以魚去留。", "居無四鄰，行無朋儔。", "胡貊之民，駕車以遊。", "外纏毳韋，內輯貂鼬。", "美水薦草，驅馬縱牛。", "逐射兔鹿，聚爬薪槱。", "食肉飲水，雨雪相咻。", "草盡水乾，風卷雲收。", "所至成羣，不懷一陬。", "今我柰何，橫自綢繆。", "翼爲華堂，涌爲層樓。", "繚以修垣，貫以通溝。", "勢窮物變，何異一漚。", "棄之不忍，徙去莫由。", "矧茲士夫，泛焉周流。"]'),
('35289725-7bac-4d41-bea9-0679776a1e6d','和子瞻次韵陶淵明停雲詩  其一','蘇轍','宋','宋诗','song-poetry','','[]','雲跨南溟，南北一雨。',40,'全唐诗/poet.song.49000.json','["雲跨南溟，南北一雨。", "瞻望匪遥，檻穽斯阻。", "夢往從之，引手相撫。", "笑言未半，捨我不佇。"]'),
('709cd6ea-9bcf-415b-92c0-3dc09000528d','和子瞻次韵陶淵明停雲詩  其二','蘇轍','宋','宋诗','song-poetry','','[]','晚稻欲登，白露霄濛。',40,'全唐诗/poet.song.49000.json','["晚稻欲登，白露霄濛。", "人飲嘉平，漿酒如江。", "我獨何爲，觀成于窗。", "此心了然，來無所從。"]'),
('04fb960f-ea7b-487f-af92-8e9a954e8637','和子瞻次韵陶淵明停雲詩  其三','蘇轍','宋','宋诗','song-poetry','','[]','欣然而笑，是無枯榮。',40,'全唐诗/poet.song.49000.json','["欣然而笑，是無枯榮。", "手足相依，所鍾則情。", "情忘意消，神凝不征。", "可以安身，可以長生。"]'),
('4f81fbc8-0e40-437e-b3a0-1d52067156e6','和子瞻次韵陶淵明停雲詩  其四','蘇轍','宋','宋诗','song-poetry','','[]','跋扈飛揚，誰匪南柯。',40,'全唐诗/poet.song.49000.json','["跋扈飛揚，誰匪南柯。", "運歷相尋，憂喜雜和。", "我游其外，所享則多。", "削迹拔木，其如予何。"]'),
('4e29a22f-f1d9-4497-b80a-c9197a4393ad','和子瞻次韵陶淵明勸農詩  其一','蘇轍','宋','宋诗','song-poetry','','[]','我遷海康，實編于民。',40,'全唐诗/poet.song.49000.json','["我遷海康，實編于民。", "少而躬耕，老復其真。", "乘流得坎，不問所因。", "願以所知，施及斯人。"]'),
('2df33461-6d1b-4995-86ec-80103b6aae40','和子瞻次韵陶淵明勸農詩  其二','蘇轍','宋','宋诗','song-poetry','','[]','我行四方，稻麥黍稷。',40,'全唐诗/poet.song.49000.json','["我行四方，稻麥黍稷。", "果蔬蒲荷，百種咸植。", "糞溉耘籽，乃後有穡。", "爾獨何爲，開口而食。"]'),
('af715c20-c7e7-479f-9498-089a710c76dd','和子瞻次韵陶淵明勸農詩  其三','蘇轍','宋','宋诗','song-poetry','','[]','掇拾于川，搜捕于陸。',40,'全唐诗/poet.song.49000.json','["掇拾于川，搜捕于陸。", "俯鞠婦子，仰薦昭穆。", "閩乘其偷，載耒逐逐。", "計無百年，謀止信宿。"]'),
('3a3d1954-da3e-4673-8176-a57fd5bd30f9','和子瞻次韵陶淵明勸農詩  其四','蘇轍','宋','宋诗','song-poetry','','[]','我歸無時，視汝長久。',40,'全唐诗/poet.song.49000.json','["我歸無時，視汝長久。", "孰爲沮溺，風雨相耦。", "築室東皋，取足南畝。", "后稷爲烈，夫豈一手。"]'),
('b076a0ad-9d0a-4424-96ef-7ceac412f0bf','和子瞻次韵陶淵明勸農詩  其五','蘇轍','宋','宋诗','song-poetry','','[]','斫木陶土，器則不匱。',40,'全唐诗/poet.song.49000.json','["斫木陶土，器則不匱。", "績麻繅繭，衣則可冀。", "藥餌具前，病安得至。", "坐而告窮，相視徒愧。"]'),
('776052d5-cafd-4b48-b1b5-1fc48fe30023','和子瞻次韵陶淵明勸農詩  其六','蘇轍','宋','宋诗','song-poetry','','[]','莫爲之先，冥不謂鄙。',40,'全唐诗/poet.song.49000.json','["莫爲之先，冥不謂鄙。", "一夫前行，百夫具履。", "以爲不信，出視同軌。", "期爾十年，風變而美。"]'),
('ac23b229-fd39-4c00-8b64-95efef489551','丙戌十月二十三日大雪','蘇轍','宋','宋诗','song-poetry','','[]','秋成粟滿倉，冬藏雪盈尺。',168,'全唐诗/poet.song.49000.json','["秋成粟滿倉，冬藏雪盈尺。", "天意愍無辜，歲事了不逆。", "誰言豐年中，遭此大泉厄。", "肉好雖甚精，十百非其實。", "田家有餘糧，靳靳未肯出。", "閭閻但坐視，愍愍不得食。", "朝饑願充腸，三五本自足。", "飽食就茗飲，竟亦安用十。", "姦豪得巧便，輕重竊相易。", "鄰邦穀如土，胡越兩不及。", "閑民本無頼，翩然去井邑。", "土著坐受窮，忍饑待捐瘠。", "彼哉陶鈞手，用此狂且愎。", "天且無奈何，我亦長太息。"]'),
('d7e50a1d-f74c-4662-ab19-c246949a0e64','畫嘆','蘇轍','宋','宋诗','song-poetry','','[]','武燕未遠嗟誰識，趙董紛紛枉得名。',32,'全唐诗/poet.song.49000.json','["武燕未遠嗟誰識，趙董紛紛枉得名。", "已矣孫陳舊人物，至今但數漢公卿。"]'),
('93f1b48a-2cf2-4aa2-81e3-2c09b294e4ab','夢中反古菖蒲','蘇轍','宋','宋诗','song-poetry','','[]','石上生菖蒲，一寸十二節。',48,'全唐诗/poet.song.49000.json','["石上生菖蒲，一寸十二節。", "仙人勸我食，再三不忍折。", "一人得飽滿，餘人皆不悅。", "已矣勿復言，人人好顔色。"]'),
('4225961e-2dce-4f10-b6d7-9c04c648ad35','次遲韵復雪','蘇轍','宋','宋诗','song-poetry','','[]','老人怕寒愁早作，夜聞飛霰知相虐。',128,'全唐诗/poet.song.49000.json','["老人怕寒愁早作，夜聞飛霰知相虐。", "粟車未到泥復深，場薪欲盡心驚愕。", "山川滉蕩勢如海，孤舟一葉知安泊。", "山中故人消息斷，欲問有無隔溪壑。", "人言王生好事人，回船不顧山陰約。", "故侯生來本貧窶，妻子至今美藜藿。", "曳履長歌解忍饑，裹飯往飼今誰託。", "家人來告酒可蒭，洗盞開瓶同一酌。"]'),
('e1c8c24b-51dc-45fa-91ee-6d22d154f448','次韵文氏外孫驥以其祖父與可學士書卷還謝悰學士','蘇轍','宋','宋诗','song-poetry','','[]','西南自是賢俊府，衰老思歸謾留許。',144,'全唐诗/poet.song.49000.json','["西南自是賢俊府，衰老思歸謾留許。", "舂禾磨麥非平生，子孫便推我作古。", "賢哉與可詩中傑，筆墨餘功散繒楮。", "南陽諸謝世有人，此邦亦自非其土。", "一時與我俱作客，白髮蒼顔愧非伍。", "儒術真傳漢太翁，風流未減晉諸庾。", "兩家尚有往還帖，舊集脫遺應可補。", "明窗展卷清淚滴，恍然似與故人語。", "欲鎖空厨付長康，恐君譏我不與取。"]'),
('88af7adb-433e-49cb-91ad-96f6adc2fdc7','守歲','蘇轍','宋','宋诗','song-poetry','','[]','歲云莫矣誰能守，唯有此心初不移。',64,'全唐诗/poet.song.49000.json','["歲云莫矣誰能守，唯有此心初不移。", "宇宙隨流任爾去，虛空對面即吾師。", "三杯醉倒聊從俗，一點靈明欲語誰。", "來日日新無限事，歸根一笑彼安知。"]'),
('c56d7a3f-733f-489f-9633-a9ca6f7c0dad','上元不出','蘇轍','宋','宋诗','song-poetry','','[]','春寒未脫紫貂裘，燈火催人夜出遊。',64,'全唐诗/poet.song.49000.json','["春寒未脫紫貂裘，燈火催人夜出遊。", "老厭歌鍾空命酒，病嫌風露怯登樓。", "擁袍坐睡曾無念，結客追歡久已休。", "試問西鄰傳法老，此時情味似儂不。"]'),
('7d70cfa8-4170-43f9-b3bb-cdd6ce5367e2','將築南屋借功田家','蘇轍','宋','宋诗','song-poetry','','[]','先人敝廬寄西南，不歸三紀今何堪。',128,'全唐诗/poet.song.49000.json','["先人敝廬寄西南，不歸三紀今何堪。", "卜營菟裘閱歲三，西成黍豆餘石甔。", "借功田家并钁杴，農事未起來不嫌。", "併遣浮客從丁男，芒鞋禿巾短後衫。", "杵聲登登駭閭閻，期我一月久不厭。", "我方窮困人所諳，有求不答心自甘。", "一言見許不妄談，飲汝信厚心懷慚。", "晨炊暮餉增醯鹽，歸時不礙田與蠶。"]'),
('88c49b3b-4ca7-4323-babb-2baedbfebc56','丁亥生日','蘇轍','宋','宋诗','song-poetry','','[]','少年即病肺，喘作鋸木聲。',120,'全唐诗/poet.song.49000.json','["少年即病肺，喘作鋸木聲。", "中年復病脾，暴下泉流傾。", "困苦始知道，處世百欲輕。", "收功在晚年，二疾忽已平。", "來年今日中，正行七十程。", "老聃本吾師，妙語初自明。", "至哉希夷微，不受外物嬰。", "非三亦非一，了了無形形。", "迎隨俱不見，瞿曇謂無生。", "湛然琉璃內，寶月長盈盈。"]'),
('e210a02b-61ff-4635-b7f4-154246291469','初葺遺老齋二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','髭鬚渾白已經歲，腰痛春來日又多。',64,'全唐诗/poet.song.49000.json','["髭鬚渾白已經歲，腰痛春來日又多。", "一味安閑猶有礙，却令朝謁擬如何。", "築居定作子孫計，好事久遭僧佛呵。", "尤愧白家履道宅，十年成就飽經過。"]'),
('1633d9b2-2205-4d4c-aa5c-719bc5d57ef5','初葺遺老齋二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','爲留十步南牆竹，莫怪門前鳥雀多。',64,'全唐诗/poet.song.49000.json','["爲留十步南牆竹，莫怪門前鳥雀多。", "陋巷何妨似顔子，勢家應未奪蕭何。", "詩書懶惰何曾讀，氣息調勻不用呵。", "多病從來少賓客，杜門今復幾人過。"]'),
('7a4b0efb-4e1f-486e-8113-4a543485db74','謝人惠千葉牡丹','蘇轍','宋','宋诗','song-poetry','','[]','東風催趁百花新，不出門庭一老人。',64,'全唐诗/poet.song.49000.json','["東風催趁百花新，不出門庭一老人。", "天女要知摩詰病，銀瓶滿送洛陽春。", "可憐最後開千葉，細數餘芳尚一旬。", "更待遊人歸去盡，試將童冠浴湖濱。"]'),
('9732da85-161b-4b39-8d49-fe7871d53929','移陳州牡丹偶得千葉二本喜作','蘇轍','宋','宋诗','song-poetry','','[]','小圃初開清潩岸，名花近取宛丘城。',64,'全唐诗/poet.song.49000.json','["小圃初開清潩岸，名花近取宛丘城。", "爭言千葉根難認，忽發雙葩眼自明。", "謫墮神仙終不俗，飛來鸞鳳有餘清。", "細鋤瓦礫除荆棘，未可令齊衆草生。"]'),
('01d9e31b-76b6-4445-a4b3-e8b296180cf8','因舊','蘇轍','宋','宋诗','song-poetry','','[]','君不見林上鵲，冬深始營巢，及春巢已成。',134,'全唐诗/poet.song.49000.json','["君不見林上鵲，冬深始營巢，及春巢已成。", "又不見梁上燕，春深初作窠，及夏雛已生。", "我爲一區屋，三年費經營。", "紛紛伐梧楸，日厭斤斧聲。", "老境能幾何，何日安餘齡。", "一言愧吾兒，事忌與力爭。", "青楊易三棟，赤榆換雙楹。", "指顧行即具，構築役亦輕。", "酇侯念子孫，不處高閈閎。", "吾今何人斯，此則坐右銘。"]'),
('f3d397bf-0881-4a7b-b455-7ca2dcb835cd','初成遺老齋二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','花時懶出伴遊人，暑雨深藏養病身。',64,'全唐诗/poet.song.49000.json','["花時懶出伴遊人，暑雨深藏養病身。", "新宅丁丁厭斤斧，舊書寂寂卷埃塵。", "久將生事累諸子，頓斂浮根付一真。", "遺老齋成謀宴坐，澹然無語接來賓。"]'),
('8179a0e3-5aef-4af0-9210-939a222b3c3b','初成遺老齋二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','舊說潁川宜老人，朱櫻斑筍養閑身。',64,'全唐诗/poet.song.49000.json','["舊說潁川宜老人，朱櫻斑筍養閑身。", "無心已絕衣冠念，有眼不遭車馬塵。", "青簡自書遺老傳，白鬚仍寫去年真。", "齋成謾作笑談主，已是蕭然一世賓。"]'),
('caefdf39-61ea-49e6-acb1-56abd935b306','蠶麥二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','疏慵自分人嫌我，貧病可憐天養人。',64,'全唐诗/poet.song.49000.json','["疏慵自分人嫌我，貧病可憐天養人。", "蠶眠已報冬裘具，麥熟旋供湯餠新。", "擷桑曉出露濡足，拾穗暮歸塵滿身。", "家家辛苦大作社，典我千錢追四鄰。"]'),
('a868bd25-1557-4db3-b529-4e9b3139cddc','蠶麥二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','三界人家多鮮福，一時蠶麥得難兼。',64,'全唐诗/poet.song.49000.json','["三界人家多鮮福，一時蠶麥得難兼。", "鋤耰已愧非吾力，湯火尤驚取不廉。", "貴客爭誇火浣布，貧家粗有水精鹽。", "薄衫冷麵消長夏，捫腹當知百不堪。"]'),
('f21f4068-f10f-4bd4-8b51-c13525608a4a','文氏外孫入村收麥','蘇轍','宋','宋诗','song-poetry','','[]','欲收新麥繼陳穀，頼有諸孫替老人。',64,'全唐诗/poet.song.49000.json','["欲收新麥繼陳穀，頼有諸孫替老人。", "三夜陰霪敗場圃，一竿晴日舞比鄰。", "急炊大餠償饑乏，多博村酤勞苦辛。", "閉廩歸來真了事，賦詩憐汝足精神。"]'),
('babcb2a5-b309-497f-8030-5302085f5db3','李方叔新宅','蘇轍','宋','宋诗','song-poetry','','[]','我年七十無住宅，斤斧登登亂朝夕。',128,'全唐诗/poet.song.49000.json','["我年七十無住宅，斤斧登登亂朝夕。", "兒孫期我八十年，宅成可作十年客。", "人壽八十知已難，從今未死且盤桓。", "不如君家得衆力，咄嗟便了三十間。", "李君雖貧足圖史，旋鑿明窗安凈几。", "閉門但辦作詩章，好事時來置樽俎。", "我恨年來不出門，不見君家棟宇新。", "心安即是身安處，自揣頭顱莫問人。"]'),
('72978a1a-810e-4ff6-869b-104137d7660c','苦雨','蘇轍','宋','宋诗','song-poetry','','[]','蠶婦絲出盎，田夫麥入倉。',120,'全唐诗/poet.song.49000.json','["蠶婦絲出盎，田夫麥入倉。", "斯人薄福德，二事未易當。", "忽作連日雨，坐使秋田荒。", "出門陷塗潦，入室崩垣牆。", "覆壓先老稚，漂淪及牛羊。", "餘糧詎能久，歲晚憂糟糠。", "天災非妄行，人事密有償。", "嗟哉竟未悟，自謂予不戕。", "造禍未有害，無辜輒先傷。", "簞瓢吾何憂，作詩熱中腸。"]'),
('405b4e4b-f1d5-457b-b50e-1b049b09e22f','殺麥二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','麥幸十分熟，雨過三日霪。',48,'全唐诗/poet.song.49000.json','["麥幸十分熟，雨過三日霪。", "初晴尚未伏，半夜卷重陰。", "細築場無隙，輕推磨有音。", "驚聞諸縣水，一曬直千金。"]'),
('66a2d0ac-2d24-4139-8ca4-8f4b34154ff9','殺麥二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','雨後麥多病，庾中蛾欲飛。',48,'全唐诗/poet.song.49000.json','["雨後麥多病，庾中蛾欲飛。", "不辭終日暑，幸脫半年饑。", "潦水來何暴，秋田望已微。", "農夫愚可念，此報定誰非。"]'),
('2e8bdef7-9b64-4975-8e59-b9f8f44aa634','立秋後','蘇轍','宋','宋诗','song-poetry','','[]','伏中苦熱焦皮骨，秋後清風濯肺肝。',64,'全唐诗/poet.song.49000.json','["伏中苦熱焦皮骨，秋後清風濯肺肝。", "天地不仁誰念爾，身心無著偶能安。", "詩書久爲消磨日，毛褐還須準擬寒。", "謾許百年知到否，相從一日且盤桓。"]'),
('2d8d3f88-59be-4214-8966-14467df11564','初築南齋','蘇轍','宋','宋诗','song-poetry','','[]','我老不自量，築室盈百間。',144,'全唐诗/poet.song.49000.json','["我老不自量，築室盈百間。", "舊屋收半料，新材伐他山。", "盎中粟將盡，橐中金亦殫。", "凉風八月高，扶架起南邊。", "首成遺老齋，願與客周旋。", "古檜長百尺，翠竹森千竿。", "隔城過清潁，有井皆甘泉。", "平生隠居念，眷眷在山川。", "誰言白髮年，有作竟不然。", "我本師瞿曇，所遇無不安。", "諸子知我懷，勉更求榱椽。", "堂成鋪莞簟，無夢但安眠。"]'),
('32b0560c-7932-4e55-a094-da0550cb0b0b','中秋月望十六終夜如晝','蘇轍','宋','宋诗','song-poetry','','[]','秋氣久已到，月明如可期。',72,'全唐诗/poet.song.49000.json','["秋氣久已到，月明如可期。", "雲生未望夜，天借極圓時。", "冷澈登臨倦，衰慵起舞遲。", "兔閑長擣藥，桂老尚生枝。", "運轉何年住，清明與物宜。", "油然任消長，斤斧定何施。"]'),
('c20bb492-7bd2-4401-8c6c-695fce12a97b','釀重陽酒','蘇轍','宋','宋诗','song-poetry','','[]','家人欲釀重陽酒，香麴甘泉家自有。',128,'全唐诗/poet.song.49000.json','["家人欲釀重陽酒，香麴甘泉家自有。", "黄花抱蕊有佳思，金火未調無好手。", "老奴但欲致村酤，小婢爭言試三斗。", "我年七十似童兒，逢節歡欣事從厚。", "廩粟已空豆方實，羔豚雖貴魚可取。", "病嫌秋雨難爲腹，老咽饞涎空有口。", "折花誰是送酒人，來客但有鄰家父。", "閉門一醉莫問渠，巷爭不用纓冠救。"]'),
('958d574d-07fb-4353-a141-d2896cee9156','戲題菊花','蘇轍','宋','宋诗','song-poetry','','[]','春初種菊助槃蔬，秋晚開花插酒壺。',64,'全唐诗/poet.song.49000.json','["春初種菊助槃蔬，秋晚開花插酒壺。", "微物不多分地力，終年乃爾任人須。", "天隨匕箸幾時輟，彭澤樽罍未遽無。", "更擬食根花落後，一依本草太傷渠。"]'),
('3c18d5e8-d481-413a-aa03-bdde01daa2c0','九日三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','昔忝衣冠舊，今從野老遊。',48,'全唐诗/poet.song.49000.json','["昔忝衣冠舊，今從野老遊。", "籬根菊初綻，甕面酒新蒭。", "不負重陽節，都無舉世憂。", "人生定誰是，萬事本悠悠。"]'),
('3b753fad-6b90-492f-8a15-82371d951874','九日三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','欲就九日飲，旋炊三斗醅。',48,'全唐诗/poet.song.49000.json','["欲就九日飲，旋炊三斗醅。", "今朝不一醉，坐客有空回。", "白髮何須吝，黄花恨晚開。", "問知瓶未罄，相勸盡餘杯。"]'),
('890c25bb-719c-44dd-86cf-20e225dda070','九日三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','從古重此日，今人那得違。',48,'全唐诗/poet.song.49000.json','["從古重此日，今人那得違。", "菊遲知歲閏，酒貴念人饑。", "身安且自慰，家遠不成歸。", "尚憶少年樂，驚呼人盡非。"]'),
('281c5f70-d95c-43f4-8507-28791ce76e6b','十日二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','酒經重九尚殘巵，雨送初寒問篋衣。',64,'全唐诗/poet.song.49000.json','["酒經重九尚殘巵，雨送初寒問篋衣。", "養氣安閑真得計，讀書勤苦已知非。", "謾存講說傳家學，深謝交遊絕世譏。", "築室未成中自笑，何如茅屋對柴扉。"]'),
('44315329-65b7-43a9-ba6f-343f2695a1ad','十日二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','憂患經懷沃漏巵，榮華過眼脫輕衣。',64,'全唐诗/poet.song.49000.json','["憂患經懷沃漏巵，榮華過眼脫輕衣。", "定心稍覺無來往，時事誰能問是非。", "祿去身安常自喜，宅成囊竭可無譏。", "交遊散盡餘親戚，酒熟時來一叩扉。"]'),
('857c5e10-8a52-464c-a7e0-83656decdefc','初成遺老齋待月軒藏書室三首 遺老齋','蘇轍','宋','宋诗','song-poetry','','[]','老人身世兩相遺，綠竹青松自蔽虧。',64,'全唐诗/poet.song.49000.json','["老人身世兩相遺，綠竹青松自蔽虧。", "已喜形骸今我有，枉將名字與人知。", "往還但許鄰家父，問訊纔通說法師。", "燕坐蕭然便終日，客來不識我爲誰。"]'),
('dc87a726-fe72-4588-b50e-dd2c68bce49e','初成遺老齋待月軒藏書室三首 待月軒','蘇轍','宋','宋诗','song-poetry','','[]','軒前無物但長空，孤月忽來東海東。',64,'全唐诗/poet.song.49000.json','["軒前無物但長空，孤月忽來東海東。", "圓滿定從何處得，清明許與衆人同。", "憐渠生死未能免，顧我盈虧略已通。", "夜久客寒要一飲，油然細酌意無窮。"]'),
('2d3d618b-93d9-4fdb-9c7a-d782b436bdd0','初成遺老齋待月軒藏書室三首 藏書室','蘇轍','宋','宋诗','song-poetry','','[]','讀書舊破十年功，老病茫然萬卷空。',64,'全唐诗/poet.song.49000.json','["讀書舊破十年功，老病茫然萬卷空。", "插架都將付諸子，閉關猶得養衰翁。", "案頭螢火從乾死，窗裏飛蠅久未通。", "自見老盧真面目，平生事業有無中。"]'),
('9a329480-9702-4b96-b441-108898447356','久雨','蘇轍','宋','宋诗','song-poetry','','[]','雲低氣尚濁，雨細泥益深。',96,'全唐诗/poet.song.49000.json','["雲低氣尚濁，雨細泥益深。", "經旬勢不止，晚稼日已侵。", "閑居頼田食，憂如老農心。", "堆場欲生耳，棲畝將陸沉。", "常賦雖半釋，雜科起相尋。", "凶年每多暴，此憂及山林。", "號呼天不聞，有言不如喑。", "願見雲解脫，秋陽破羣陰。"]'),
('56a9db6d-6acf-410b-af0b-c72d43d352e1','方築西軒穿地得怪石','蘇轍','宋','宋诗','song-poetry','','[]','卞氏平日本富家，庭中怪石蹲麏麚。',128,'全唐诗/poet.song.49000.json','["卞氏平日本富家，庭中怪石蹲麏麚。", "子孫分散不復惜，排棄坑谷埋泥沙。", "一株躍出隨畚鍤，知我開軒方種花。", "頹然遠嶺垂澗壑，豁然洞穴通烟霞。", "十夫徙置幸不遠，軒前桐柏陰交加。", "我家舊隠久不到，小池尺水三流槎。", "少年旋繞看不足，時呼野老來煎茶。", "老人得此且自慰，更訪餘石探幽遐。"]'),
('10f102e3-670a-4a87-a5f5-35f3f7236ad4','肺病','蘇轍','宋','宋诗','song-poetry','','[]','肺病比不作，屈信三十年。',72,'全唐诗/poet.song.49000.json','["肺病比不作，屈信三十年。", "今年胡爲爾，呀然上衝咽。", "寒冰未易溫，死灰誰使然。", "醫言無庸怪，此理環無端。", "少年少戕敗，今日存精堅。", "假年復除害，非人豈非天。"]'),
('80016da3-d6ea-4b25-bedd-049d51844806','送遜監淮西酒并示諸任二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','疇昔南遷海上雷，艱難唯與汝同來。',64,'全唐诗/poet.song.49000.json','["疇昔南遷海上雷，艱難唯與汝同來。", "再從龍尉茅叢底，旋卜雲橋荔子堆。", "相與閉門尋舊學，誰言復出理官醅。", "乘田委吏先師事，莫學陶翁到即回。"]'),
('f880fd46-6c3f-4335-95c9-46f0b0d9e21c','送遜監淮西酒并示諸任二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','淮西留滯昔經年，唯有諸任時往還。',64,'全唐诗/poet.song.49000.json','["淮西留滯昔經年，唯有諸任時往還。", "炊黍留賓不嫌陋，借書度日免長閑。", "歸來潩水無人問，夢繞伊家古檜間。", "二老舊遊唯我在，後生誰復識蒼顔。"]'),
('aa51fdd8-bf41-4e66-968b-4975e1ad621a','風雪','蘇轍','宋','宋诗','song-poetry','','[]','冬溫未宜人，風雪中夜止。',96,'全唐诗/poet.song.49000.json','["冬溫未宜人，風雪中夜止。", "疾雷略吾窗，輕冰入吾被。", "病去適三日，驚起存一氣。", "心安氣亦安，二物本非二。", "皎然一寸燈，下燭九泉底。", "物來無不應，物去未嘗昧。", "恨我俗緣深，撓此古佛智。", "醫來視六脈，六脈非昔比。"]'),
('89dacabc-ea4d-452c-8458-774085a13215','讀傳燈錄示諸子','蘇轍','宋','宋诗','song-poetry','','[]','大鼎知難一手扛，此心已自十年降。',64,'全唐诗/poet.song.49000.json','["大鼎知難一手扛，此心已自十年降。", "舊存古鏡磨無力，近喜三更月到窗。", "早歲文章真自累，一生憂患信難雙。", "從今父子俱清凈，共說無生或似龐。"]'),
('4b817a19-2fa4-4536-b576-e1cb8bc4f4c0','夢中咏西湖','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰鑿西湖十里中，扁舟載酒颺輕風。',64,'全唐诗/poet.song.49000.json','["誰鑿西湖十里中，扁舟載酒颺輕風。", "草木蕃滋百事足，寒暄淡薄四時同。", "東鄰適與吾廬便，西岸遥將岳麓通。", "閑遊草草無人識，竹杖藤鞋一老翁。"]'),
('d4674e72-a4a2-45bd-9225-2c01518975a7','買炭','蘇轍','宋','宋诗','song-poetry','','[]','苦寒搜病骨，絲纊莫能禦。',168,'全唐诗/poet.song.49000.json','["苦寒搜病骨，絲纊莫能禦。", "析薪燎枯竹，勃鬰烟充宇。", "西山古松櫟，材大招斤斧。", "根槎委溪谷，龍伏熊虎踞。", "挑抉靡遺餘，陶穴付一炬。", "積火變深黳，牙角猶憤怒。", "老翁擁破氈，正晝出無屨。", "百錢不滿籃，一坐幸至莫。", "御爐歲增貢，圓直中常度。", "閭閻不敢售，根節姑付汝。", "升平百年後，地力已難富。", "知夸不知嗇，俯首欲誰訴。", "百物今盡然，豈爲一炭故。", "我老或不及，預爲子孫懼。"]'),
('1b112981-5e24-4c0e-81da-2e8608aa8f52','欲雪','蘇轍','宋','宋诗','song-poetry','','[]','今年麥中熟，餠餌不充口。',96,'全唐诗/poet.song.49000.json','["今年麥中熟，餠餌不充口。", "老農畏冬旱，薄雪未覆畝。", "驕陽引狂風，三白知應否。", "久晴車牛通，薪炭家家有。", "唯有口腹憂，此病誰能救。", "達官例謀身，一醉日自富。", "尚應天愍人，雲族朝來厚。", "飛花得盈尺，一麥可平取。"]'),
('1f833f54-8e36-4887-96c5-5a08190d54e1','那吒','蘇轍','宋','宋诗','song-poetry','','[]','北方天王有狂子，只知拜佛不拜父。',96,'全唐诗/poet.song.49000.json','["北方天王有狂子，只知拜佛不拜父。", "佛知其愚難教語，寶塔令父左手舉。", "兒來見佛頭輒俯，且與拜父略相似。", "佛如優曇難值遇，見者聞道出生死。", "嗟爾何爲獨如此，業果已定磨不去。", "佛滅到今千萬祀，只在江湖挽船處。"]'),
('ee44218c-bd29-4681-9624-7a85d29d3b45','示諸子','蘇轍','宋','宋诗','song-poetry','','[]','老去惟堪一味閑，坐令諸子了生緣。',64,'全唐诗/poet.song.49000.json','["老去惟堪一味閑，坐令諸子了生緣。", "般柴運水皆行道，挾策讀書那廢田。", "兄弟躬耕真盡力，鄉鄰不慣枉稱賢。", "裕人約己吾家世，到此相承累百年。"]'),
('fd44b7ea-0d66-4fdf-901c-67a91a2da717','戊子正旦','蘇轍','宋','宋诗','song-poetry','','[]','百歲行來已七分，筋骸轉覺不如人。',64,'全唐诗/poet.song.49000.json','["百歲行來已七分，筋骸轉覺不如人。", "法傳心地初投種，雨過花開不待春。", "識路一時如有得，到家諸事本非新。", "舊陳芻狗今無用，付與時人藉兩輪。"]'),
('c3412ffd-7e2d-4ff2-8da9-b24a08171f2a','題舊鍾馗','蘇轍','宋','宋诗','song-poetry','','[]','濟南書記今白鬚，歲節鍾馗舊綠襦。',64,'全唐诗/poet.song.49000.json','["濟南書記今白鬚，歲節鍾馗舊綠襦。", "舉手托天欣見雪，破鞋踏凍可憐渠。", "滔滔時輩今黄壤，六六年華屬老夫。", "兒女未容翁便去，銀瓶隔夜浸屠酥。"]'),
('1977aa6f-93bd-4d6a-a95f-0c82a5eb8b87','七十吟','蘇轍','宋','宋诗','song-poetry','','[]','年來霜雪上人頭，俄爾相將七十秋。',64,'全唐诗/poet.song.49000.json','["年來霜雪上人頭，俄爾相將七十秋。", "欲去天公未遣去，久留敝宅恐難留。", "六窗漸暗猶牽物，一點微明更著油。", "近聽老盧親下種，滿田宿草費鋤耰。"]'),
('ae681bdf-b93a-49eb-a484-5b6c74459700','久旱府中取虎頭骨投邢山潭水得雨戲作','蘇轍','宋','宋诗','song-poetry','','[]','邢山潭中黑色龍，經年懶卧泥沙中。',121,'全唐诗/poet.song.49000.json','["邢山潭中黑色龍，經年懶卧泥沙中。", "嵩陽山中白額虎，何年一箭肉爲土。", "龍雖生，虎雖死，天然猛氣略相似，生不益人死何負。", "虎頭枯骨金石堅，投骨潭中潭水旋。", "龍知虎猛心已愧，虎知龍懶自增氣。", "山前一戰風雨交，父老曉起看麥苗。", "君不見岐山死諸葛，真能奔走生仲達。"]'),
('2f1fa731-19b7-4884-8311-97e1c297743b','生日','蘇轍','宋','宋诗','song-poetry','','[]','扶杖今年見國人，懸弧早歲憶茲晨。',64,'全唐诗/poet.song.49000.json','["扶杖今年見國人，懸弧早歲憶茲晨。", "佛身三世歸依地，鄰寺百僧清凈因。", "蘧子知非慚已晚，白公起定惜餘春。", "舞雩一濯平湖水，鄉黨驚呼白髮新。"]'),
('34a86451-827a-48d8-93c8-f1bdd99094cf','將拆舊屋權住西廊','蘇轍','宋','宋诗','song-poetry','','[]','平生未有三間屋，今歲初成百步廊。',64,'全唐诗/poet.song.49000.json','["平生未有三間屋，今歲初成百步廊。", "欲趁閑年就新宅，不辭暑月卧斜陽。", "修篁已謝前人種，甘井何妨衆口嘗。", "奔走從來成底事，安居到處漫爲鄉。"]'),
('29d41f75-16e6-4bd9-af5e-ccb31b047058','種花二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','築室力已盡，種花功尚疏。',48,'全唐诗/poet.song.49000.json','["築室力已盡，種花功尚疏。", "山丹得春雨，艷色照庭除。", "末品何曾數，羣芳自不如。", "今秋接千葉，試取洛人餘。"]'),
('f93a1581-fa03-4999-8b30-c0a57a581772','種花二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','築室少閑地，種花能幾畦。',48,'全唐诗/poet.song.49000.json','["築室少閑地，種花能幾畦。", "松筠舊滿眼，桃李漸成蹊。", "無計通湖水，長思種藕泥。", "幽懷終不愜，拄杖出城西。"]'),
('217c52cc-aaf3-438e-a7a3-988fde6326a1','同遲賦千葉牡丹','蘇轍','宋','宋诗','song-poetry','','[]','未換中庭三尺土，漫種數叢千葉花。',64,'全唐诗/poet.song.49000.json','["未換中庭三尺土，漫種數叢千葉花。", "造物不違遺老意，一枝頗似洛人家。", "名園不放尋芳客，陋巷希聞載酒車。", "未忍畫瓶修佛供，清樽酌盡試山茶。"]'),
('da039200-72a2-467a-9704-35fe8e60d377','同遲賦春晚','蘇轍','宋','宋诗','song-poetry','','[]','池塘春旱欲生塵，一雨能令草木新。',64,'全唐诗/poet.song.49000.json','["池塘春旱欲生塵，一雨能令草木新。", "脾病不嫌櫻笋薄，廩空偏喜麥禾勻。", "白須照水湖光凈，淥酒留人鳥哢頻。", "但恐少年嫌老醜，眼前無復一時人。"]'),
('501d0001-6039-4ab9-be39-b2bc6bbcd929','春無雷','蘇轍','宋','宋诗','song-poetry','','[]','經冬無雪麥不死，秋雨過多深入土。',160,'全唐诗/poet.song.49000.json','["經冬無雪麥不死，秋雨過多深入土。", "人言來歲定無麥，農父掉頭笑不許。", "清明雨足麥欣欣，旋敕奴婢修破囷。", "大麥過期當半熟，小麥未晚猶十分。", "東家西舍發陳積，十錢一餠猶難得。", "向來天公不爲人，市人半是溝中瘠。", "前望麥熟一月期，老稚相勸聊忍饑。", "誰令伏枕作寒熱，囊中無錢誰肯醫。", "天公愛人何所吝，一春雨作雷不震。", "雷聲一起百妖除，病人起舞不須扶。"]'),
('546f6a66-7ff5-4454-af80-c3712262ce86','聞卞氏舊有怪石藏宅中問其遺孫指一廢井云盡在是矣井在室中床下尚未能取先作','蘇轍','宋','宋诗','song-poetry','','[]','昔人遊宦久江湖，怪石嵌空駭里閭。',64,'全唐诗/poet.song.49000.json','["昔人遊宦久江湖，怪石嵌空駭里閭。", "一井深藏緣底事，百年不出待潛夫。", "棄捐泥土性仍在，睥睨林亭氣漸蘇。", "微物廢興猶有定，此生窮達謾長吁。"]'),
('995ae496-c7b4-490e-bd87-adeeb7ccdf9e','仲夏始雷','蘇轍','宋','宋诗','song-poetry','','[]','陽氣溟濛九地來，經春涉夏始聞雷。',64,'全唐诗/poet.song.49000.json','["陽氣溟濛九地來，經春涉夏始聞雷。", "麥禾此去或可望，桃李向來誰使開。", "號令迍邅人共怪，陰陽顛倒物應猜。", "一聲震蕩雖驚耳，遍地妖氛未易回。"]'),
('5f8a1bd4-b005-498f-94fb-bc2a5a5b5968','八璽','蘇轍','宋','宋诗','song-poetry','','[]','秦人一璽十五城，百二十城當八璽。',64,'全唐诗/poet.song.49000.json','["秦人一璽十五城，百二十城當八璽。", "元日臨軒組綬新，君臣相顧無窮喜。", "九鼎崢嶸夏禹餘，八璽錯落古所無。", "古人鄙陋今人笑，父老不慣空驚呼。"]'),
('852ff664-1bae-41a2-9572-3ed2e0a95fc8','讀舊詩','蘇轍','宋','宋诗','song-poetry','','[]','早歲吟哦已有詩，年來七十才全衰。',64,'全唐诗/poet.song.49000.json','["早歲吟哦已有詩，年來七十才全衰。", "開編一笑恍如夢，閉目徐思定是誰。", "敵手一時無復在，賞音他日更難期。", "老人不用多言語，一點空明萬法師。"]'),
('53db6b7e-b131-40fa-b7bd-dedb20e37044','五月園夫獻紅菊二絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','黄花九月傲清霜，百草滿園無此香。',32,'全唐诗/poet.song.49000.json','["黄花九月傲清霜，百草滿園無此香。", "紅紫無端盜名字，試尋本草細商量。"]'),
('d6b6a2bb-18fd-4bef-bb5b-73b7696538b9','五月園夫獻紅菊二絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','南陽白菊有奇功，潭上居人多老翁。',32,'全唐诗/poet.song.49000.json','["南陽白菊有奇功，潭上居人多老翁。", "葉似皤蒿莖似棘，未宜放入酒杯中。"]'),
('49467718-a013-4909-956e-b744f0084e88','夏至後得雨','蘇轍','宋','宋诗','song-poetry','','[]','天惟不窮人，旱甚雨輒至。',96,'全唐诗/poet.song.49000.json','["天惟不窮人，旱甚雨輒至。", "麥乾春澤匝，禾槁夏雷墜。", "一年失二雨，廩實真不繼。", "我窮本人窮，得飽天所畀。", "奪祿十五年，有田潁川涘。", "躬耕力不足，分穫中自愧。", "餘功治室廬，棄積霑狗彘。", "久養無用身，未識彼天意。"]'),
('d5ce045e-d6f0-4863-9797-38def5ccda3b','遲往泉店殺麥','蘇轍','宋','宋诗','song-poetry','','[]','罷民不耕穫，豈利有攸往。',120,'全唐诗/poet.song.49000.json','["罷民不耕穫，豈利有攸往。", "古人爲我言，許此亦無妄。", "一冬免鋤犁，二麥盈甕盎。", "火老金尚伏，雨過築場壤。", "鄰家助伯亞，蒼耳割榛莽。", "朝陽得終日，經歲可無恙。", "老夫終病慵，長子幸可仗。", "劬勞慎勿厭，餠餌家共享。", "秋田雨初足，已作豐熟想。", "歸來報好音，相對開臘釀。"]'),
('a35c45dc-b568-46f4-9c2d-9adebdba449a','夏夜對月','蘇轍','宋','宋诗','song-poetry','','[]','大火直南方，萬物委爐炭。',120,'全唐诗/poet.song.49000.json','["大火直南方，萬物委爐炭。", "微雪吐凉月，中夜初一浣。", "老人氣如縷，枕簟亦流汗。", "披衣繞中庭，星斗嘒相粲。", "鳴蜩思清露，抱葉一長嘆。", "栖鵲亦未安，繞樹再三轉。", "我生仰田食，候雨占雲漢。", "枵然未可期，無食終誰怨。", "褰帷竟不寐，夜氣凈如練。", "愛之不忍觸，惟恐朝來散。"]'),
('59c7237f-9341-4906-846e-60e4e47792e2','千葉白蓮花','蘇轍','宋','宋诗','song-poetry','','[]','蓮花生淤泥，凈色比天女。',60,'全唐诗/poet.song.49000.json','["蓮花生淤泥，凈色比天女。", "臨池見千葉，謫墮問何故。", "空明世無匹，銀瓶送佛所。", "清泉養芳潔，爲我三日住。", "蔫然落寶床，應返梵天去。"]'),
('9c5e6fb9-db2e-46f0-b535-e1e88fd6e5fb','追和張公安道贈別絕句','蘇轍','宋','宋诗','song-poetry','','[]','少年便識成都尹，中歲仍爲幕下賓。',32,'全唐诗/poet.song.49000.json','["少年便識成都尹，中歲仍爲幕下賓。", "待我江西徐孺子，一生知己有斯人。"]'),
('e3b255d0-03b4-455e-b2c4-40458dedeb17','遺老齋絕句十二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','杜門本畏人，門開自無客。',24,'全唐诗/poet.song.49000.json','["杜門本畏人，門開自無客。", "孤坐忽三年，心空無一物。"]'),
('72e91273-9102-499b-8a56-d05a734d39c2','遺老齋絕句十二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','衆音入我耳，諸色過吾目。',24,'全唐诗/poet.song.49000.json','["衆音入我耳，諸色過吾目。", "聞見長歷然，靈源不受觸。"]'),
('c5d0f00d-d56e-45b7-a063-37b8e16255bb','遺老齋絕句十二首  其三','蘇轍','宋','宋诗','song-poetry','','[]','茲心凈無垢，尚愛南齋竹。',24,'全唐诗/poet.song.49000.json','["茲心凈無垢，尚愛南齋竹。", "當暑得清風，冷然若新沐。"]'),
('e42ddfe3-1e44-4a0d-9cda-bb0a6aa29d29','遺老齋絕句十二首  其四','蘇轍','宋','宋诗','song-poetry','','[]','老檜真百尺，疏竹疑千畝。',24,'全唐诗/poet.song.49000.json','["老檜真百尺，疏竹疑千畝。", "紛紛霰雪中，見此歲寒友。"]'),
('18ee7056-df2d-4072-b2ae-4bc5da86c346','遺老齋絕句十二首  其五','蘇轍','宋','宋诗','song-poetry','','[]','栽竹種松檜，十年未成陰。',24,'全唐诗/poet.song.49000.json','["栽竹種松檜，十年未成陰。", "昔人定知我，爲我養南林。"]'),
('eacb9c43-7f91-4015-a4c8-ed7d9d21b5be','遺老齋絕句十二首  其六','蘇轍','宋','宋诗','song-poetry','','[]','久無叩門聲，剝啄問何故。',24,'全唐诗/poet.song.49000.json','["久無叩門聲，剝啄問何故。", "田中有人至，昨夜盈尺雨。"]'),
('095c80b5-010a-4da4-b1bc-ab9596d63db0','遺老齋絕句十二首  其七','蘇轍','宋','宋诗','song-poetry','','[]','我居近西城，城枕湖一曲。',24,'全唐诗/poet.song.49000.json','["我居近西城，城枕湖一曲。", "不到平湖上，何物禁吾足。"]'),
('f52923a5-56f5-454a-b4de-97557a0e1121','遺老齋絕句十二首  其八','蘇轍','宋','宋诗','song-poetry','','[]','北臨鳳凰臺，鳳去臺亦圮。',24,'全唐诗/poet.song.49000.json','["北臨鳳凰臺，鳳去臺亦圮。", "萋萋修竹林，喈喈何日至。"]'),
('bddbb4a1-11a8-4354-9998-a327b1c6455c','遺老齋絕句十二首  其九','蘇轍','宋','宋诗','song-poetry','','[]','昔我過嵩麓，雲移見諸峰。',24,'全唐诗/poet.song.49000.json','["昔我過嵩麓，雲移見諸峰。", "重遊未有日，想像曀霾中。"]'),
('edd8ea75-6489-4a6a-aaa3-d499b006654a','遺老齋絕句十二首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','避事已謝客，養性不看書。',24,'全唐诗/poet.song.49000.json','["避事已謝客，養性不看書。", "書中多感遇，掩卷輒長吁。"]'),
('f14fd53b-868f-4dea-90fb-5a62b9366f4f','遺老齋絕句十二首  其一一','蘇轍','宋','宋诗','song-poetry','','[]','人言里中舊，獨有陳太丘。',24,'全唐诗/poet.song.49000.json','["人言里中舊，獨有陳太丘。", "文若命世人，惜哉憂人憂。"]'),
('3b53d952-abf8-42c0-ba79-f61b9d0e1e6b','遺老齋絕句十二首  其一二','蘇轍','宋','宋诗','song-poetry','','[]','巢由老箕山，遁世聊可耳。',24,'全唐诗/poet.song.49000.json','["巢由老箕山，遁世聊可耳。", "臨流愧堯舜，又甚陳仲子。"]'),
('a993aa96-45d7-4480-87c6-3092148d578b','移花','蘇轍','宋','宋诗','song-poetry','','[]','種花南堂南，堂毀花亦瘁。',96,'全唐诗/poet.song.49000.json','["種花南堂南，堂毀花亦瘁。", "理畦西軒西，花好未忍棄。", "慇勤拔陳草，秋雨流入地。", "移根傅生土，指日春風至。", "花來本陳洛，盈尺不爲異。", "力求千葉枝，更與一溉水。", "人功誠已盡，天巧行可致。", "我老百不爲，愛此養花智。"]'),
('99c7cba4-1f3f-4f0d-8fea-64eac09e3e62','服栗','蘇轍','宋','宋诗','song-poetry','','[]','老去日添腰脚病，山翁服栗舊傳方。',64,'全唐诗/poet.song.49000.json','["老去日添腰脚病，山翁服栗舊傳方。", "經霜斧刃全金氣，插手丹田借火光。", "入口鏘鳴初未熟，低頭咀噍不容忙。", "客來爲說晨興晚，三嚥徐收白玉漿。"]'),
('3e2a6b30-c73d-4cd2-8a88-995bbfe6e2b1','白菊','蘇轍','宋','宋诗','song-poetry','','[]','白菊長先黄菊開，年年九日泛新醅。',64,'全唐诗/poet.song.49000.json','["白菊長先黄菊開，年年九日泛新醅。", "猶存古曆摽花候，不奈時人信手栽。", "得勢從教盈九畹，俯眉聊復引三杯。", "愈風明目須真物，能使神農爲爾回。"]'),
('81e8188a-1f9f-4202-83ef-32bc181961b5','九日家釀未熟','蘇轍','宋','宋诗','song-poetry','','[]','平生不喜飲，九日猶一酌。',120,'全唐诗/poet.song.49000.json','["平生不喜飲，九日猶一酌。", "今年失家釀，節到真寂寞。", "床頭瀉餘樽，畦菊吐微萼。", "洗盞對妻孥，肴蔬隨厚薄。", "興來欲徑醉，量盡還自却。", "傍人嘆身健，省己知脾弱。", "尚有姑射人，自守常綽約。", "養生要慈儉，已老慚矍鑠。", "燕居漸忘我，杜門奚不樂。", "風麯日已乾，濁醪可徐作。"]'),
('d7af4d7a-6508-4709-a8c0-b634eda9647d','南齋獨坐','蘇轍','宋','宋诗','song-poetry','','[]','獨坐南齋久，忘家似出家。',48,'全唐诗/poet.song.49000.json','["獨坐南齋久，忘家似出家。", "香烟穠作穗，茶面結成花。", "細竹才通徑，長松初有槎。", "往還真斷絕，一一數歸鴉。"]'),
('386815da-319d-49bf-af84-d6acb63c050a','西成','蘇轍','宋','宋诗','song-poetry','','[]','野老端相慶，西成僅十分。',48,'全唐诗/poet.song.49000.json','["野老端相慶，西成僅十分。", "寒來多釀酒，客過預留饙。", "近事姑求飽，遠憂要浪聞。", "一壺真有理，終日得醺醺。"]'),
('5e2171ab-2b65-458a-9b1f-e8964a42e9b9','藏菜','蘇轍','宋','宋诗','song-poetry','','[]','爨清葵芥充朝膳，歲晚風霜斷菜根。',64,'全唐诗/poet.song.49000.json','["爨清葵芥充朝膳，歲晚風霜斷菜根。", "百日園枯未易過，一家口衆復何言。", "多排甕盎先憂盡，旋設盤盂未覺煩。", "早晚春風到南圃，侵凌雪色有新萱。"]'),
('e643b748-dc26-4819-82f7-55cfd7eb520d','示諸子','蘇轍','宋','宋诗','song-poetry','','[]','諸子才不惡，功名舊有言。',48,'全唐诗/poet.song.49000.json','["諸子才不惡，功名舊有言。", "窮愁念父母，心力盡田園。", "志在要須命，身閑且養源。", "遊鱼脫淵水，何處有飛翻。"]'),
('fc9d3018-8fe3-4c97-978f-67b7322caf15','示諸孫','蘇轍','宋','宋诗','song-poetry','','[]','少年真力學，玄月閉書帷。',48,'全唐诗/poet.song.49000.json','["少年真力學，玄月閉書帷。", "老去渾無頼，心空自不知。", "交遊誰識面，文字略存詩。", "笑向諸孫說，疏慵非汝師。"]'),
('bdee6de3-0660-4801-b6c2-3ea08bee9051','十一月一日作','蘇轍','宋','宋诗','song-poetry','','[]','晝短圖書看不了，夜長鼓角睡難堪。',64,'全唐诗/poet.song.49000.json','["晝短圖書看不了，夜長鼓角睡難堪。", "老懷騷屑誰爲伴，心地空虛成妄談。", "酒少不妨鄰叟共，病多頼有衲僧諳。", "積陰深厚陽初復，一點靈光勤自參。"]'),
('23a9e143-33b3-4c65-964c-b501b8618913','冬至日','蘇轍','宋','宋诗','song-poetry','','[]','陰陽升降自相催，齒髮誰教老不回。',64,'全唐诗/poet.song.49000.json','["陰陽升降自相催，齒髮誰教老不回。", "猶有髻珠常照物，坐看心火冷成灰。", "酥煎隴坂經年在，柑摘吳江半月來。", "官冷無因得官酒，老妻微笑潑新醅。"]'),
('53801d4f-e436-4fd1-b6d3-a559b2254ca6','除日','蘇轍','宋','宋诗','song-poetry','','[]','年年最後飲屠酥，不覺年來七十餘。',64,'全唐诗/poet.song.49000.json','["年年最後飲屠酥，不覺年來七十餘。", "十二春秋新罷講，五千道德適親書。", "木經霜雪根無蠹，船出風波載本虛。", "自怪多年客箕潁，每因吾黨賦歸歟。"]'),
('d5b77fba-2d16-41d3-bf2a-af3be29dddaa','臘中三雪','蘇轍','宋','宋诗','song-poetry','','[]','一臘不虛度，三雪自相因。',48,'全唐诗/poet.song.49000.json','["一臘不虛度，三雪自相因。", "暗添池上凌，稍壓麥中塵。", "餘潤想猶在，苦寒將及春。", "慇勤欲盡酒，扶養病衰人。"]'),
('fb30485e-b4a1-48bd-81aa-82010673ab01','伐雙穀','蘇轍','宋','宋诗','song-poetry','','[]','芳蘭非不嘉，當門自宜鋤。',96,'全唐诗/poet.song.49000.json','["芳蘭非不嘉，當門自宜鋤。", "矧此惡木陰，久妨長者車。", "僕夫礪尋斧，告我日方除。", "久持不忍意，柯條益扶疏。", "植根雖云固，伐去曾須臾。", "我塗雖不寬，出入自有餘。", "開門聽還往，并納賢與愚。", "荒穢一朝盡，來者皆虛徐。"]'),
('7fee6df1-b3b3-46a7-ab66-e6ba0c9be6c5','上元夜适勸至西禪觀燈','蘇轍','宋','宋诗','song-poetry','','[]','三年不踏門前路，今夜仍看屋裏燈。',64,'全唐诗/poet.song.49000.json','["三年不踏門前路，今夜仍看屋裏燈。", "照佛有餘長自照，澄心無法便成澄。", "追歡狂客去忘返，入定孤僧喚不譍。", "更到西禪何所問，隔牆魚鼓正登登。"]'),
('e9771819-7533-45f6-af52-f226131513fa','程八信孺表弟剖符單父相遇潁川歸鄉待闕作長句贈別','蘇轍','宋','宋诗','song-poetry','','[]','我生猶及見大門，弟兄中外十七人。',192,'全唐诗/poet.song.49000.json','["我生猶及見大門，弟兄中外十七人。", "兩家門戶甲鄉黨，正如潁川數孫陳。", "嗈嗈鳴雁略雲漢，風吹散落天一垠。", "歸來勉强整毛羽，飲水啄粒傷離羣。", "東西隔絕不敢恨，死生相失長悲辛。", "蕭蕭華髮對妻子，往往老淚流衣巾。", "仲叔已盡季亦老，雙星孤月耿獨存。", "老夫閉門不敢出，喜君三度乘朱輪。", "今春剖符地尤勝，不齊自古留芳塵。", "回車訪我念衰老，挽衣把臂才逡巡。", "君行到官我未死，杖藜便是不速賓。", "一尊酌我當有問，此國豈有賢於君。"]'),
('69a17968-8c90-400c-94b3-45d214257be4','種松','蘇轍','宋','宋诗','song-poetry','','[]','城郭人家歲寒木，檜柏森森映華屋。',96,'全唐诗/poet.song.49000.json','["城郭人家歲寒木，檜柏森森映華屋。", "青松介僻不入城，野性特嫌塵土辱。", "中庭冉冉盈尺苗，條幹雖短風霜足。", "培根不用糞壤厚，插竹預防鷄犬觸。", "他年期汝三丈高，獨立仙翁毛髮綠。", "老翁自分不及見，子孫見汝知遺直。"]'),
('4f534650-9852-466b-893f-a90b46c6fffd','二月望日雪二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','玄冥留雪惱中春，損麥傷花病老人。',32,'全唐诗/poet.song.49000.json','["玄冥留雪惱中春，損麥傷花病老人。", "已典布裘捐衲襪，朝來酒盡乞比鄰。"]'),
('a57435fa-2f24-4c1a-964a-6ecf106763da','二月望日雪二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','老翁衰病不憂花，百口唯須麥養家。',32,'全唐诗/poet.song.49000.json','["老翁衰病不憂花，百口唯須麥養家。", "聞道田中猶要雪，兼收凝白試山茶。"]'),
('4001e43a-0de0-4a1d-8c2d-2fd4e993e8a6','遜自淮康酒官歸覲逾旬而歸送行二絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','官期未滿許寧親，平日宦遊無此恩。',32,'全唐诗/poet.song.49000.json','["官期未滿許寧親，平日宦遊無此恩。", "雨遍公田及私畝，學書兼得問筠孫。"]'),
('c60015ed-9a0b-4fcb-a735-938a7e1ed7a0','遜自淮康酒官歸覲逾旬而歸送行二絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','乘田委吏責無多，舊學年來竟若何。',32,'全唐诗/poet.song.49000.json','["乘田委吏責無多，舊學年來竟若何。", "開卷新詩可人意，到官無復廢吟哦。"]'),
('93181e52-d25f-4dff-af00-d9bc2e205941','去年秋扇二絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','篋中秋扇委塵埃，春晚炎風拂面來。',32,'全唐诗/poet.song.49000.json','["篋中秋扇委塵埃，春晚炎風拂面來。", "舊物不辭爲世用，故人相見莫心猜。"]'),
('e1feb9cc-a149-4419-a258-d6636f4203c4','去年秋扇二絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','扇中秦女舊乘鸞，拂去浮塵色尚鮮。',32,'全唐诗/poet.song.49000.json','["扇中秦女舊乘鸞，拂去浮塵色尚鮮。", "未盡炎風早歸去，不堪秋後乞哀憐。"]'),
('5f9dfedd-6899-45ae-b275-cb8365d74ede','讀舊詩','蘇轍','宋','宋诗','song-poetry','','[]','老人詩思如枯泉，轆轤不下甕盎乾。',64,'全唐诗/poet.song.49000.json','["老人詩思如枯泉，轆轤不下甕盎乾。", "舊詩展卷驚三年，粲然佳句疑昔賢。", "老來百事不如前，藜羹稻飯嗟獨便。", "飽食餘暇盡日眠，安用琢句愁心肝。"]'),
('a22a03ec-ae2d-4cc4-9872-207a7a880e43','堂成不施丹雘唯紙窗水屏蕭然如野人之居偶作','蘇轍','宋','宋诗','song-poetry','','[]','高棟虛窗五月凉，客來掃地旋焚香。',64,'全唐诗/poet.song.49000.json','["高棟虛窗五月凉，客來掃地旋焚香。", "白雲低繞明月觀，漲海東流清暑堂。", "病久渴心思沆瀣，夢回餘念屬瀟湘。", "老人夫婦修行久，此處從今是道場。"]'),
('21cf1254-6313-4406-b0f8-7995fd35ac4d','南齋竹三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','幽居一室少塵緣，妻子相看意自閑。',32,'全唐诗/poet.song.49000.json','["幽居一室少塵緣，妻子相看意自閑。", "行到南窗修竹下，恍然如見舊溪山。"]'),
('86a8b3b0-319b-41ed-a535-5896c6f9eda4','南齋竹三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','舊山修竹半塵埃，誰種南林待我來。',32,'全唐诗/poet.song.49000.json','["舊山修竹半塵埃，誰種南林待我來。", "新筍出牆秋雨足，閉門長與護蒼苔。"]'),
('5c964cbb-3d8b-4f72-815b-47f1f38fe083','南齋竹三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','里中佳客舊孫陳，我自疏慵不見人。',32,'全唐诗/poet.song.49000.json','["里中佳客舊孫陳，我自疏慵不見人。", "目倦細書長掩卷，心遊法界四無鄰。"]'),
('7e513f93-7acc-41f6-8428-066def17ffff','中秋新堂看月戲作','蘇轍','宋','宋诗','song-poetry','','[]','年年看月茅檐下，今歲堂成月正圓。',64,'全唐诗/poet.song.49000.json','["年年看月茅檐下，今歲堂成月正圓。", "自笑吾人强分別，不應此月倍嬋娟。", "虛窗每怯高風度，碧瓦頻驚急雨懸。", "七十老翁渾未慣，安居始覺貴公賢。"]'),
('1e43ae87-213c-48ab-a46e-82b5f85d3141','午寢','蘇轍','宋','宋诗','song-poetry','','[]','食飽年來幸有秋，倒床清夢百無憂。',64,'全唐诗/poet.song.49000.json','["食飽年來幸有秋，倒床清夢百無憂。", "忍饑終愧首陽客，睡足何須雲夢州。", "冰酒黄封生不喜，春芽紫筍向誰求。", "平生尚有書魔在，一卷還堪作枕頭。"]'),
('094b22ae-8122-432e-9fda-003e2658c772','九日陰雨不止病中把酒示諸子三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','旱久翻成霧雨災，老人腹疾强啣杯。',64,'全唐诗/poet.song.49000.json','["旱久翻成霧雨災，老人腹疾强啣杯。", "官醅菉豆適初熟，籬菊黄花終未開。", "兒女共憐佳節過，鷄豚恐有故人來。", "衰年此會真餘幾，薄酒無多不用推。"]'),
('1fefa706-4c40-4bb2-a48f-130ab41413fc','九日陰雨不止病中把酒示諸子三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','九日不能飲，呦呦覺胃寒。',48,'全唐诗/poet.song.49000.json','["九日不能飲，呦呦覺胃寒。", "妻孥勸把盞，萸菊正堆槃。", "懶極久成病，年高終鮮歡。", "道人嫌服藥，心息自相安。"]'),
('cd84d922-c77c-4b16-80c8-b117de54d4e9','九日陰雨不止病中把酒示諸子三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','庭菊兼黄白，村醪雜聖賢。',48,'全唐诗/poet.song.49000.json','["庭菊兼黄白，村醪雜聖賢。", "微吟還自喜，不飲信徒然。", "陶亮貧非病，孟嘉醒亦顛。", "相看莫相笑，與爾各當年。"]'),
('7586df08-18e9-470d-b102-6ffed4fa2ca0','落葉滿長安分題','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','有客倦長安，秋風正颯然。',72,'全唐诗/poet.song.49000.json','["有客倦長安，秋風正颯然。", "九衢飛亂葉，八水凝寒烟。", "摇落南山見，凄凉陋巷偏。", "名園失綠暗，清渭泛紅鮮。", "衣信催煩杵，狼烽報極邊。", "長江苦吟處，日暮想橫鞭。"]'),
('907584c4-ca35-40bc-996d-159ffd65ef0f','臘月九日雪三絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','天公留雪待嘉平，飛霰來時曉未明。',32,'全唐诗/poet.song.49000.json','["天公留雪待嘉平，飛霰來時曉未明。", "病士擁衾催暖酒，閉門不聽掃瑶瓊。"]'),
('ba77d72e-0dc9-4c2e-a028-1fd7c5de0826','臘月九日雪三絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','去年家釀不須沽，秫米今年絕市無。',32,'全唐诗/poet.song.49000.json','["去年家釀不須沽，秫米今年絕市無。", "雪沒前山薇蕨盡，誰憐無語獨携鋤。"]'),
('fbc24132-a5a3-4bc4-a3ea-9fc1f08431c1','臘月九日雪三絕句  其三','蘇轍','宋','宋诗','song-poetry','','[]','臘中得雪春宜麥，甕裏無糟寒惱人。',32,'全唐诗/poet.song.49000.json','["臘中得雪春宜麥，甕裏無糟寒惱人。", "未暇樽罍伴佳客，先將餠餌許比鄰。"]'),
('0f7f39a9-172c-46e9-b685-fec1520c5f52','己丑除日二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','閱遍時人身亦老，卷殘舊曆意茫然。',64,'全唐诗/poet.song.49000.json','["閱遍時人身亦老，卷殘舊曆意茫然。", "髭鬚白盡無添處，甲子重來又十年。", "酒儉不容時一醉，堂成且喜夜安眠。", "春秋似是平生事，屋壁深藏付後賢。"]'),
('8a779b2b-dbe9-479b-b5ea-3bdc6896681a','己丑除日二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','橘紅安穩近誰傳，鬢雪蕭騷久已然。',64,'全唐诗/poet.song.49000.json','["橘紅安穩近誰傳，鬢雪蕭騷久已然。", "梅柳任教修故事，蠶絲聊與祝新年。", "敲門賀客辭多病，守歲諸孫聽不眠。", "粗有官酤供夜飲，一瓶渾濁且稱賢。"]'),
('5db22f2e-30c9-43c3-8693-3b845c145fbb','同外孫文九新春五絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','佳人旋貼釵頭勝，園父初挑雪底芹。',32,'全唐诗/poet.song.49000.json','["佳人旋貼釵頭勝，園父初挑雪底芹。", "欲得春來怕春晚，春來會似出山雲。"]'),
('c9e69cbf-da94-464e-b05d-ba9656e4b646','同外孫文九新春五絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','甕中臘脚長憂凍，戶外春風那得知。',32,'全唐诗/poet.song.49000.json','["甕中臘脚長憂凍，戶外春風那得知。", "酒熟定應花未動，舉瓢先對柳千絲。"]'),
('9030e4f5-6702-4fe1-872a-d451f9878a92','同外孫文九新春五絕句  其三','蘇轍','宋','宋诗','song-poetry','','[]','菊葉萱芽初出土，凍虀冷麵欲宜人。',32,'全唐诗/poet.song.49000.json','["菊葉萱芽初出土，凍虀冷麵欲宜人。", "老人脾病難隨汝，洗釜磨刀待晚春。"]'),
('6c7b3615-265d-4db0-8699-22627c9eff51','同外孫文九新春五絕句  其四','蘇轍','宋','宋诗','song-poetry','','[]','築室恨除千本竹，及春先補百株花。',32,'全唐诗/poet.song.49000.json','["築室恨除千本竹，及春先補百株花。", "隔年預與園夫約，春雨晴時問汝家。"]'),
('8961762f-808c-4b21-8c01-8373fbac72ab','同外孫文九新春五絕句  其五','蘇轍','宋','宋诗','song-poetry','','[]','雪覆西山三頃麥，一犁春雨祝天工。',32,'全唐诗/poet.song.49000.json','["雪覆西山三頃麥，一犁春雨祝天工。", "麥秋幸與人同飽，昔日黄門今老農。"]'),
('8ae0a1c7-14e1-41b6-bb32-1b16a73aa8a8','上元前雪三絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','臘中平地雪盈尺，嵩隗山田麥尚乾。',32,'全唐诗/poet.song.49000.json','["臘中平地雪盈尺，嵩隗山田麥尚乾。", "不管上元燈火夜，飛花處處作春寒。"]'),
('1512ec61-8ad6-41b8-80ef-7f95eceb24ba','上元前雪三絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','閉門不問門前事，燈火薰天自不知。',32,'全唐诗/poet.song.49000.json','["閉門不問門前事，燈火薰天自不知。", "聞道朝來雪又下，老人今歲未應饑。"]'),
('382e5289-9cc5-4454-827b-f2859c0dbba3','上元前雪三絕句  其三','蘇轍','宋','宋诗','song-poetry','','[]','天公似管人間事，近事傳聞半是非。',32,'全唐诗/poet.song.49000.json','["天公似管人間事，近事傳聞半是非。", "但使麥田饒雨雪，饑人得飽未相違。"]'),
('b346468a-2f47-4190-bc86-f4859b9916a2','上元雪','蘇轍','宋','宋诗','song-poetry','','[]','上元燈火家家辦，遍地瓊瑶夜夜深。',64,'全唐诗/poet.song.49000.json','["上元燈火家家辦，遍地瓊瑶夜夜深。", "衲被蒙頭真老病，紗籠照佛本無心。", "床頭酒甕恰三斗，山下麥田真百金。", "乞我終年醉且飽，端能擁鼻作微吟。"]'),
('54a745a1-e665-418a-8c7d-684d0aa14ec7','春陰','蘇轍','宋','宋诗','song-poetry','','[]','春後誰令百日陰，雨淫風橫兩相侵。',64,'全唐诗/poet.song.49000.json','["春後誰令百日陰，雨淫風橫兩相侵。", "天公未有惜花意，野老空存念麥心。", "共怪叢筠亦黄落，終憐老檜獨蕭森。", "過中不克陽安在，夏旱前知未易禁。"]'),
('5a091323-836f-4455-96df-446e2934fa60','庭中種花','蘇轍','宋','宋诗','song-poetry','','[]','空庭一無有，初種六株花。',120,'全唐诗/poet.song.49000.json','["空庭一無有，初種六株花。", "青桐綠楊柳，相映成田家。", "春雨散膏油，朝暾發萌牙。", "造物知我心，初來盡枯槎。", "開花已可貴，結子成益佳。", "百事盡如此，一生復何嗟。", "我生本窮陋，中年旅朝衙。", "失脚墮南海，生還夢荒遐。", "築室雖不多，於我則已奢。", "松筠伴衰老，已矣無復加。"]'),
('ad1dd7d9-de69-4fc2-a650-cb83a9c9a71f','曾郎元矩見過逾月聽其言久而不厭追感平昔爲賦詩','蘇轍','宋','宋诗','song-poetry','','[]','胄子相從得佳婿，掖垣同直喜良朋。',64,'全唐诗/poet.song.49000.json','["胄子相從得佳婿，掖垣同直喜良朋。", "交情不意隔生死，世事休論有廢興。", "宿草芊綿淚入土，故琴牢落恨填膺。", "遠來似覺清談勝，試問傳家今幾燈。"]'),
('69f6dbdf-a0ef-4977-b3ac-58d06de5ec3f','閉門','蘇轍','宋','宋诗','song-poetry','','[]','閉門潁昌市，不識潁昌人。',108,'全唐诗/poet.song.49000.json','["閉門潁昌市，不識潁昌人。", "身閑未易過，閑久生暗塵。", "我念作閑計，欲與黄卷親。", "少年病書史，未老目先昏。", "掩卷默無言，閉目中自存。", "心光定中發，廓然四無鄰。", "不知心已空，不見外物紛。", "瞿曇昔嘗云，咄哉不肯信。", "一見勿復失，愈久當愈真。"]'),
('fe7a6031-194f-4e0b-b5c3-28a706ce951e','林筍復生','蘇轍','宋','宋诗','song-poetry','','[]','春寒侵竹竹憔悴，父老皆云未嘗記。',128,'全唐诗/poet.song.49000.json','["春寒侵竹竹憔悴，父老皆云未嘗記。", "偶然雷雨一尺深，知爲南園衆君子。", "從地湧出長如人，一一便有凌雲氣。", "吾家老圃倦栽接，但以歲寒相嫵媚。", "一朝紛紛看黄落，嵇阮相過無醉地。", "陰陽往復知有數，已病還瘳非即死。", "呼童徑語鄰舍翁，種竹未改當年意。", "姚黄左紫終誤人，千葉重臺定何事。"]'),
('1c421798-63a7-40a8-985b-f03f31c5cdbf','老柏','蘇轍','宋','宋诗','song-poetry','','[]','柏根可合抱，柏身長百尺。',96,'全唐诗/poet.song.49000.json','["柏根可合抱，柏身長百尺。", "我年類汝老，我心同汝直。", "我貧初無居，愛汝買此宅。", "索居懷舊友，開軒得三益。", "風中有餘勁，雪後不改色。", "我貧不栽花，繞屋多種竹。", "全家謬聞道，舉目無他物。", "晨興輒相對，知我有慚德。"]'),
('f93b8f99-9492-4ce2-8199-1b6c6a42bd10','蠶麥','蘇轍','宋','宋诗','song-poetry','','[]','春寒風雨淫，蠶麥止半熟。',96,'全唐诗/poet.song.49000.json','["春寒風雨淫，蠶麥止半熟。", "耕桑未嘗親，有獲敢求足。", "鄰田老翁嫗，囊空庾無粟。", "機張久乏緯，食晏惟薄粥。", "熟耕種未下，屢禱雲不族。", "私憂止寒餓，王事念鞭扑。", "爲農良未易，爲吏畏簡牘。", "閉門差似可，忍饑有餘福。"]'),
('6d83085b-b77d-4cf1-80ee-72b7375f4872','喜雨','蘇轍','宋','宋诗','song-poetry','','[]','夏田已報七分熟，秋稼方憂十日乾。',64,'全唐诗/poet.song.49000.json','["夏田已報七分熟，秋稼方憂十日乾。", "好雨徐來不倉卒，天公似欲救艱難。", "魃張鷹犬無遺力，社近鷄豚趁早寒。", "老病隨人幸一飽，爐香無語只長嘆。"]'),
('0316cfb6-7aa1-42fa-975b-6c9523e0fc22','題東坡遺墨卷後','蘇轍','宋','宋诗','song-poetry','','[]','少年喜爲文，兄弟俱有名。',120,'全唐诗/poet.song.49000.json','["少年喜爲文，兄弟俱有名。", "世人不妄言，知我不如兄。", "篇章散人間，墮地皆瓊英。", "凜然自一家，豈與餘人爭。", "多難晚流落，歸來分死生。", "晨光迫殘月，回顧失長庚。", "展卷得遺草，流涕濕冠纓。", "斯文久衰弊，涇流自爲清。", "科斗藏壁中，見者空嘆驚。", "廢興自有時，詩書付西京。"]'),
('b0e8de9c-205d-466f-95ff-f7162485431b','洗竹','蘇轍','宋','宋诗','song-poetry','','[]','寒甚南軒竹半黄，晚抽旱筍雜榛荒。',64,'全唐诗/poet.song.49000.json','["寒甚南軒竹半黄，晚抽旱筍雜榛荒。", "不嫌毒手千竿盡，稍放清風八月凉。", "短篲只堪除糞壤，新萌會看伏牛羊。", "扶持造化須人力，早聽人言布麥糠。"]'),
('4d39ae9b-17ba-4833-8525-0a42dd7ec5b0','寄張芸叟','蘇轍','宋','宋诗','song-poetry','','[]','老矣張芸叟，親編樂府詞。',48,'全唐诗/poet.song.49000.json','["老矣張芸叟，親編樂府詞。", "才高君未覺，手戰我先衰。", "點𪑮舊無對，吟哦今與誰。", "十年酬唱絕，歡喜得新詩。"]'),
('74fe28bb-11d3-4901-9fc6-0b9dbb96c389','兩中秋絕句二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','潁川城下兩中秋，金氣初凝火尚流。',32,'全唐诗/poet.song.49000.json','["潁川城下兩中秋，金氣初凝火尚流。", "脾病家人不教飲，官厨好酒亦難求。"]'),
('5598f498-cd85-434e-a813-39c3132950af','兩中秋絕句二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','兩逢重九尉佗城，蜑叟相從倒酒瓶。',32,'全唐诗/poet.song.49000.json','["兩逢重九尉佗城，蜑叟相從倒酒瓶。", "十二年來均寂寞，此心南北兩冥冥。"]'),
('e1c3a6b0-075f-456e-9254-dee6d8876f47','贈德仲','蘇轍','宋','宋诗','song-poetry','','[]','我昔見子京邑時，鬚髮如漆無一絲。',160,'全唐诗/poet.song.49000.json','["我昔見子京邑時，鬚髮如漆無一絲。", "今年相見潁昌市，霜雪滿面知爲誰。", "故人分散隔生死，孑然惟以影自隨。", "憐子肝心如鐵石，昔所謂可今不移。", "世間取舍竟誰是，惟有古佛終難欺。", "嗟哉我自不知子，意子清凈持律師。", "忽然微笑不言語，袖中錦繡開新詩。", "可憐相識二十載，終日對面初不知。", "蚌含明珠不肯吐，暗行沙底藏光輝。", "蚌爲身計良可耳，旁人不悟寧非嗤。"]'),
('45aec5dd-2b16-4908-beaf-9b8e7ae2d042','閏八月二十五日菊有黄花園中粲然奪目九日不憂無菊而憂無酒戲作','蘇轍','宋','宋诗','song-poetry','','[]','年年九日憂無菊，今歲床空未有糟。',64,'全唐诗/poet.song.49000.json','["年年九日憂無菊，今歲床空未有糟。", "世事何嘗似人意，天公端解惱吾曹。", "金龜解去瓶應滿，玉液傾殘氣尚豪。", "門外白衣還到否，今時好事恐難遭。"]'),
('5978d720-d75b-4025-93a8-e4f5453d134e','九日三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','瓢尊空挂壁，九日若爲歡。',48,'全唐诗/poet.song.49000.json','["瓢尊空挂壁，九日若爲歡。", "白髮逃無計，黄花開已闌。", "酒慳慚對客，風起任飄冠。", "頼有陶翁伴，貧居得自寬。"]'),
('5ccbd782-543a-4da0-bcd7-a0a0047c44c8','九日三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','解衣換村酒，酒薄不須嫌。',48,'全唐诗/poet.song.49000.json','["解衣換村酒，酒薄不須嫌。", "節到勿空過，杯行且强拈。", "得閑身尚健，適意事難兼。", "醉卧南窗日，誰知酸與甜。"]'),
('3f4f7582-2a04-4f14-b8cf-32dae411f686','九日三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','幼子淮西客，雙壺思老人。',48,'全唐诗/poet.song.49000.json','["幼子淮西客，雙壺思老人。", "遠來經顄淡，細酌喜清醇。", "飲罷遥憐汝，歸來早及春。", "南齋昔未有，餘似舊時貧。"]'),
('5230aef2-fa44-4b75-bde7-c8a504dec91c','戲題三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','懊惱嘉榮白髮年，逢人依舊唱陽關。',32,'全唐诗/poet.song.49000.json','["懊惱嘉榮白髮年，逢人依舊唱陽關。", "渭城朝雨今誰聽，砑鼓跳踉一破顔。"]'),
('1788e66f-2729-4904-92fa-ad7ab3031607','戲題三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','謝傅凄凉已老年，胡琴羌笛怨遺賢。',32,'全唐诗/poet.song.49000.json','["謝傅凄凉已老年，胡琴羌笛怨遺賢。", "使君於此雖不俗，挽斷髭鬚誰見憐。"]'),
('aa36fbd3-6422-41c4-b992-7a2c544f9db8','戲題三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','遍地花鈿嘆百年，蒼顔白髮意凄然。',32,'全唐诗/poet.song.49000.json','["遍地花鈿嘆百年，蒼顔白髮意凄然。", "回頭笑指此郎子，破賊將來知有天。"]'),
('e00fa09b-573c-4d6a-b724-871da5b982da','木冰','蘇轍','宋','宋诗','song-poetry','','[]','老病不眠知夜寒，晨興薄冰滿庭前。',80,'全唐诗/poet.song.49000.json','["老病不眠知夜寒，晨興薄冰滿庭前。", "枯榆老柳變精妍，細稍如苗粗如椽。", "風敲碎玉落紛然，冰裹槲葉誰雕鎸。", "鄰家父老呼東垣，欲沽官酒囊無錢。", "我亦强起試一觀，樹稼不見今十年。"]'),
('6d082dc3-70e7-40bf-aa6a-c3046cadce02','夜坐','蘇轍','宋','宋诗','song-poetry','','[]','少年讀書目力耗，老怯燈光睡常早。',128,'全唐诗/poet.song.49000.json','["少年讀書目力耗，老怯燈光睡常早。", "一陽來復夜正長，城上鼓聲寒考考。", "老僧勸我習禪定，跏趺正坐推不倒。", "一心無著徐自靜，六塵消盡何曾掃。", "湛然已似須陀洹，久爾不負瞿曇老。", "回看塵勞但微笑，欲度羣迷先自了。", "平生誤與道士遊，妄意交梨求火棗。", "知有毗盧一逕通，信脚直前無別巧。"]'),
('b7b92902-247b-4176-a031-ea4e5be30bb6','老史','蘇轍','宋','宋诗','song-poetry','','[]','口食陽翟粟，身衣陽穀絲。',120,'全唐诗/poet.song.49000.json','["口食陽翟粟，身衣陽穀絲。", "二物不相即，飽暖常不時。", "老史知我窮，一歲一奔馳。", "方暑勸脂車，苦寒伺來歸。", "嗟我垂老年，未免憂寒饑。", "老史甚忠信，但恨性重遲。", "事我三十年，閔閔不相離。", "我門了無求，辛苦終不辭。", "平生金石交，至此或已携。", "老史未易得，試復養其兒。"]'),
('2b959a9f-177c-4b5b-a5dd-13606b6eec2d','臘雪次遲韵','蘇轍','宋','宋诗','song-poetry','','[]','冬儲久未辦，佳雪爲人留。',96,'全唐诗/poet.song.49000.json','["冬儲久未辦，佳雪爲人留。", "穀豆入高廩，薪蒸轉十輈。", "紛紛了歲事，閔閔念農疇。", "家有二頃田，一頃種米麰。", "風聲夜中變，飛霰曉未休。", "粗畢今歲寒，復免來年憂。", "天公知人心，未禱得所求。", "傾瓢有遺酌，起和田中謳。"]'),
('d7b53102-bb81-4051-a8a8-7356c91436da','小雪','蘇轍','宋','宋诗','song-poetry','','[]','小雪僅能消膈熱，苦寒偏解惱衰翁。',64,'全唐诗/poet.song.49000.json','["小雪僅能消膈熱，苦寒偏解惱衰翁。", "年豐誰使百物貴，心凈要令萬事空。", "老去禪功深自覺，生來滯運與人同。", "閑中未斷生靈念，清夜焚香處處通。"]'),
('7f51b79e-eae1-4048-8017-136869ec7c4f','土牛','蘇轍','宋','宋诗','song-poetry','','[]','天地非不仁，萬物自芻狗。',72,'全唐诗/poet.song.49000.json','["天地非不仁，萬物自芻狗。", "土牛適成象，逡巡見屠剖。", "田家挽雙角，歸理繅絲釜。", "生無負重力，死作初耕候。", "碎身本不辭，及物稍無負。", "君看劉表牛，豈脫曹公手。"]'),
('5e2f433a-ef53-443f-93c0-42e440517201','除夜二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','年年賦除夜，一賦一衰殘。',48,'全唐诗/poet.song.49000.json','["年年賦除夜，一賦一衰殘。", "家有三斗釀，春餘半月寒。", "鷄豚不改舊，鄰里自相歡。", "元日應無客，蕭然不著冠。"]'),
('e575b46b-5ee8-4579-b25b-52149082840e','除夜二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','七十三年客，相從尚幾年。',48,'全唐诗/poet.song.49000.json','["七十三年客，相從尚幾年。", "西方他日事，東魯一經傳。", "漸解平生縛，初安半夜禪。", "紛紛爭奪際，何意此心全。"]'),
('3ec76474-b6ed-4f38-820e-f573a1d95c5d','遺老齋南一柏雙幹昔歲坐堂上僅可見也今出屋已尺餘偶賦','蘇轍','宋','宋诗','song-poetry','','[]','翠柏擢雙幹，冉冉出屋危。',48,'全唐诗/poet.song.49000.json','["翠柏擢雙幹，冉冉出屋危。", "柏長雖云喜，我老亦可知。", "苦寒不改色，烈風終自持。", "門閑斷來客，相對不相欺。"]'),
('222b3b02-12dc-40f8-ad06-6144d28d6780','正月十六日','蘇轍','宋','宋诗','song-poetry','','[]','上元已過欲收燈，城郭遊人一倍增。',64,'全唐诗/poet.song.49000.json','["上元已過欲收燈，城郭遊人一倍增。", "陌上紅塵霏似霧，雲間明月冷如冰。", "誰言世上驅馳客，老作庵中寂定僧。", "漏水半消燈火冷，長空無滓色澄澄。"]'),
('8de0e785-2be7-45e1-81fd-01dc2bafb710','七十三歲作','蘇轍','宋','宋诗','song-poetry','','[]','一生有志恨無才，久爾蕭蕭白髮催。',64,'全唐诗/poet.song.49000.json','["一生有志恨無才，久爾蕭蕭白髮催。", "力學當年真自信，初心到此未應回。", "舊人化去渾無幾，新障重生撥不開。", "七十三年還住否，獲麟後事轉難裁。"]'),
('44d43b03-6a75-48fd-ac74-4ef4a2be1c70','春旱彌月郡人取水邢山二月五日水入城而雨','蘇轍','宋','宋诗','song-poetry','','[]','春旱時聞孽火然，邢山龍老不安眠。',64,'全唐诗/poet.song.49000.json','["春旱時聞孽火然，邢山龍老不安眠。", "麥生三寸未覆壠，雨過一犁初及泉。", "深愧貧民饑欲死，可憐肉食坐稱賢。", "南齋遺老知尤幸，湯餠黄齏又一年。"]'),
('9a360744-d32d-4ad8-a4f5-7b541c98cd59','龍川道士','蘇轍','宋','宋诗','song-poetry','','[]','昔我遷龍川，不見平生人。',216,'全唐诗/poet.song.49000.json','["昔我遷龍川，不見平生人。", "傾囊買破屋，風雨庇病身。", "頎然一道士，野鶴墮鷄羣。", "飛鳴閭巷中，稍與季子親。", "刺口問生事，褰裳觀運斤。", "俯仰忽三年，愈久意愈真。", "送我出重嶺，長揖清江濱。", "方營玉皇宮，棟宇期一新。", "成功十年後，脫身走中原。", "見公心自足，徒步非我勤。", "我歸客箕潁，晝日長掩關。", "僕夫忽告我，門有萬里賓。", "問其所從來，笑指南天雲。", "心知故人到，驚喜不食言。", "我老益不堪，惟有二頃田。", "年年種麥禾，僅能免饑寒。", "君來亦何爲，助我耕且耘。", "嗟古或有是，今世非所聞。"]'),
('b782df10-f056-461c-a20d-84bdf955b2aa','重贈','蘇轍','宋','宋诗','song-poetry','','[]','出家無復家，視身等雲浮。',168,'全唐诗/poet.song.49000.json','["出家無復家，視身等雲浮。", "東西隨風行，忽然遍九州。", "君居龍川城，築室星一周。", "屋瓦如翬飛，象設具冕旒。", "弟子五六人，門徒散林丘。", "本爲百年計，自可一世留。", "胡爲不復顧，脫去如敝裘。", "萬里一藤杖，來從故人遊。", "故人病老翁，輕重恐未酬。", "疑君了心法，萬物皆浮漚。", "去彼非有嫌，來此亦無求。", "是心摩尼珠，不受篋笥收。", "故人感君意，一言還信不。", "遠行不爲此，浪走非良謀。"]'),
('0f30341a-adb3-4792-b105-921c7b2d3553','食櫻笋二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','一旱經春草木焦，朱櫻結子獨盈條。',64,'全唐诗/poet.song.49000.json','["一旱經春草木焦，朱櫻結子獨盈條。", "盤中宛轉明珠滑，舌上逡巡絳雪消。", "仰囁佳人露猶濕，偷銜啼鳥語尤嬌。", "南方荔子爭先後，羞見炎風六月燒。"]'),
('0406a7d6-0b83-43fa-9849-2d0e825fb221','食櫻笋二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','林竹抽萌不忍挑，誰家盈束伴晨樵。',64,'全唐诗/poet.song.49000.json','["林竹抽萌不忍挑，誰家盈束伴晨樵。", "籜龍似欲號無罪，食客安知惜後凋。", "不願鹽梅調鼎味，姑從律呂應簫韶。", "林間老死雖無用，一試冬深雪到腰。"]'),
('958c7357-8e9a-43fb-93d3-9b0290ebacf7','西軒畫枯木怪石','蘇轍','宋','宋诗','song-poetry','','[]','西軒素屏開白雲，婆娑老桂依霜輪。',96,'全唐诗/poet.song.49000.json','["西軒素屏開白雲，婆娑老桂依霜輪。", "顧兔出走蟾蜍奔，河漢卷海機石蹲。", "牽牛自載倚桂根，清風颯然吹四鄰。", "東坡妙思傳子孫，作詩仿佛追前人。", "筆墨墮地稱奇珍，閉藏不聽落泥塵。", "老人讀書眼病昏，一看落筆生精神。"]'),
('ad4eeed2-d462-4de5-9853-7d73333f180e','悟老住慧林','蘇轍','宋','宋诗','song-poetry','','[]','能公住嶺南，正觀呼不起。',168,'全唐诗/poet.song.49000.json','["能公住嶺南，正觀呼不起。", "忠公客中禁，朝恩不爲累。", "道人無凈穢，所遇忘嗔喜。", "悟公清凈人，心厭紛華地。", "慧林虛法席，去有遲遲意。", "投身淤泥中，佛法何處是。", "引身山林間，過患差無幾。", "力小難自欺，心安似無愧。", "悟世常失人，違心輒喪己。", "徐行勿與較，乘流得坎止。", "君看凈因揩，志以直自遂。", "殺身竟何益，犯難豈爲智。", "去住本由天，毋求亦無避。", "相期明且哲，大雅亦如此。"]'),
('06134d63-687c-4e1a-bfb0-806ade415fbb','蠶麥','蘇轍','宋','宋诗','song-poetry','','[]','春旱麥半熟，蠶收僅十分。',48,'全唐诗/poet.song.49000.json','["春旱麥半熟，蠶收僅十分。", "不憂無餠餌，已幸有襦裙。", "造化真憐汝，耕桑不謾勤。", "經過話關陝，貧病不堪聞。"]'),
('938e7d58-c1ba-4478-80ac-564e3482f284','北堂','蘇轍','宋','宋诗','song-poetry','','[]','吾廬雖不華，粗有南北堂。',120,'全唐诗/poet.song.49000.json','["吾廬雖不華，粗有南北堂。", "通廊開十窗，爽氣來四方。", "風長日氣遠，六月有餘凉。", "兒女避不居，留此奉爺娘。", "爺娘髮如絲，不耐寒暑傷。", "單衣蕉葛輕，軟飯菘芥香。", "無客恣卧起，有客羅壺觴。", "今年得風痹，摩膏沃椒湯。", "念終捨此去，故山松柏蒼。", "此地亦何爲，歲時但烝嘗。"]'),
('4521b533-60d4-48b6-9788-408da39ec425','秋旅','蘇轍','宋','宋诗','song-poetry','','[]','雨晴秋稼如雲屯，豆沒鷄兔禾沒人。',128,'全唐诗/poet.song.49000.json','["雨晴秋稼如雲屯，豆沒鷄兔禾沒人。", "老農歡笑語行路，十年儉薄無今晨。", "無風無雨更一月，藜羹黍飯供四鄰。", "天公似許百姓足，人事未可一二論。", "窮邊逃卒到處滿，燒場入室才逡巡。", "縣符星火雜鞭箠，解衣乞與猶怒嗔。", "我願人心似天意，愛惜老弱憐孤貧。", "古來堯舜知有否，詩書到此皆空文。"]'),
('c0f9ebcb-cf16-4cef-9adb-0456738d3c96','七夕','蘇轍','宋','宋诗','song-poetry','','[]','火流知節換，秋到喜身安。',48,'全唐诗/poet.song.49000.json','["火流知節換，秋到喜身安。", "林鵲真安往，河橋晚未完。", "得閑心不厭，求巧老應難。", "送酒誰知我，瓢樽昨暮乾。"]'),
('f3d0a48d-5669-4c2d-8eb9-d5fc8eb5ac5b','食鷄頭','蘇轍','宋','宋诗','song-poetry','','[]','風開芡觜鐵爲鬚，斧斫沙磨旋付厨。',64,'全唐诗/poet.song.49000.json','["風開芡觜鐵爲鬚，斧斫沙磨旋付厨。", "細嚼兼收上池水，徐咽還成滄海珠。", "佳客滿堂須一斗，閑居頼我近平湖。", "多年不到會靈沼，氣味宛然初不殊。"]'),
('fd1e8f3a-d5aa-4836-b9b4-bf3a75ab2ae7','秋雨','蘇轍','宋','宋诗','song-poetry','','[]','禾田已熟畏愁霖，積潦欲乾泥尚深。',64,'全唐诗/poet.song.49000.json','["禾田已熟畏愁霖，積潦欲乾泥尚深。", "一雨一凉秋向晚，似安似病老相侵。", "人間有盡皆歸物，世外無生頼有心。", "要覔塵埃不到處，一燈相照夜愔愔。"]'),
('2aa564ab-6024-45c7-80e2-7b2bd9cace12','補種牡丹二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','野草凡花著地生，洛陽千葉種難成。',32,'全唐诗/poet.song.49000.json','["野草凡花著地生，洛陽千葉種難成。", "姚黄性似天人潔，糞壤埋根氣不平。"]'),
('597229c5-abb9-4ca2-a95e-8b3450d577a4','補種牡丹二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','換土移根花性安，猶嫌入伏午陰煩。',32,'全唐诗/poet.song.49000.json','["換土移根花性安，猶嫌入伏午陰煩。", "清泉翠幄非難辦，絕色濃香別眼看。"]'),
('5b11e403-641d-43c6-b04d-1094c418ae6c','曹郎子文赴山陽令','蘇轍','宋','宋诗','song-poetry','','[]','囊空口衆不堪閑，却喜平生得細論。',64,'全唐诗/poet.song.49000.json','["囊空口衆不堪閑，却喜平生得細論。", "鶴髮進封償舊德，彩衣聽訟勉平反。", "楚風剽疾觀新政，浙水蕭條咏舊恩。", "記取老人臨別語，茶瓢霜後早相存。"]'),
('d144ef40-1891-4d9c-957b-36b525d12aa4','九日三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','九日真佳節，年年長賦詩。',48,'全唐诗/poet.song.49000.json','["九日真佳節，年年長賦詩。", "深慚鶴髮老，每與菊花期。", "帽落無人拾，酒狂聊自持。", "豐年餘社甕，天意念衰羸。"]'),
('be6879e5-2d6e-4f57-b75f-3b2487ebac13','九日三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','我飲不爲酒，黄花競此時。',48,'全唐诗/poet.song.49000.json','["我飲不爲酒，黄花競此時。", "茱萸謾辟惡，麯糵助和脾。", "淺酌何勞訴，獨醒徒爾爲。", "來年我猶健，相對亦如斯。"]'),
('deb7eea3-3f8c-48fa-bf94-aa81f0725bb2','九日三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','河朔今將到，山陽近欲行。',48,'全唐诗/poet.song.49000.json','["河朔今將到，山陽近欲行。", "老懷驚聚散，一酌慰平生。", "陋巷連牆久，長淮照眼明。", "到官紛訟牒，應憶此時情。"]'),
('d2a40103-835f-461c-9a4c-7bb7b4dcd423','早睡','蘇轍','宋','宋诗','song-poetry','','[]','老人如嬰兒，起晏睡常早。',120,'全唐诗/poet.song.49000.json','["老人如嬰兒，起晏睡常早。", "粗氈薄絮被，孤枕自媚好。", "倒床作龜息，逡巡輒復覺。", "隔門燈火明，仿佛聞語笑。", "杯棬相勸酬，往往見譏誚。", "披衣坐跏趺，衰老當自了。", "室空窗亦虛，半夜明月到。", "老盧下種法，從古無此妙。", "根生花輒開，得者自不少。", "要須海底行，更問藥山老。"]'),
('a1852884-3d5d-4443-b544-0d8b4033e4c3','廳前柏','蘇轍','宋','宋诗','song-poetry','','[]','穉柏如嬰兒，冉冉三尺長。',96,'全唐诗/poet.song.49000.json','["穉柏如嬰兒，冉冉三尺長。", "移根出澗石，植幹對華堂。", "重露恣膏沐，清風時抑揚。", "我老不耐寒，憐汝堪風霜。", "朝夕望爾長，尺寸常度量。", "知非老人伴，可入諸孫行。", "想見十年後，檐前蔚蒼蒼。", "人來顧汝笑，誦我此詩章。"]'),
('c3e3c099-948a-4150-96c0-c745722bbb7a','十月二十九日雪四首  其一','蘇轍','宋','宋诗','song-poetry','','[]','床頭唧唧糟鳴甕，夜半蕭蕭雪打窗。',64,'全唐诗/poet.song.49000.json','["床頭唧唧糟鳴甕，夜半蕭蕭雪打窗。", "擁褐旋驚花著樹，潑醅初喜酒盈缸。", "鄰翁晨乞米三斗，釣戶暮留魚一雙。", "自笑有無今粗足，遥憐逐客過重江。"]'),
('4df94a3a-a6fd-496e-b74c-49c9855fe5b1','十月二十九日雪四首  其二','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','龕燈照室久妨睡，雪氣侵人不隔窗。',64,'全唐诗/poet.song.49000.json','["龕燈照室久妨睡，雪氣侵人不隔窗。", "枕上詩成那起草，槽頭酒滴暗鳴缸。", "遠來狂客應回去，高卧幽人未有雙。", "猶憶新灘泊船處，堆蓬積玉撼長江。"]'),
('9e99520a-254c-4238-a5b0-114b1c2039d0','十月二十九日雪四首  其三','蘇轍','宋','宋诗','song-poetry','','[]','幽居漫爾存三徑，燕坐何妨應六窗。',64,'全唐诗/poet.song.49000.json','["幽居漫爾存三徑，燕坐何妨應六窗。", "老憶舊書時展卷，病封藥酒旋開缸。", "小園摇落黄花盡，古檜飛鳴白鶴雙。", "珍重老盧留種子，養生不復問王江。"]'),
('6584ec31-6f99-49e3-8ff9-0f7a154161b7','十月二十九日雪四首  其四','蘇轍','宋','宋诗','song-poetry','','[]','鷂子一飛超漲海，蜂兒終日透晴窗。',64,'全唐诗/poet.song.49000.json','["鷂子一飛超漲海，蜂兒終日透晴窗。", "心空莫著書千卷，客到長留酒半缸。", "性命早知元有分，文章誰信舊無雙。", "何年結束尋歸路，還看蟆頤下飲江。"]'),
('6dd451b5-36ca-476d-baca-6cbac6a909b1','冬日即事','蘇轍','宋','宋诗','song-poetry','','[]','寒日初加一線長，臘醅添浸隔羅光。',64,'全唐诗/poet.song.49000.json','["寒日初加一線長，臘醅添浸隔羅光。", "新年只願多新酒，舊疾微令變舊方。", "自昔杯棬元窄小，得閑筋力尚康强。", "買田種秫貧無計，自有人家爲插秧。"]'),
('8e79c0d7-f077-40d7-85dd-bdb9b8aa35c1','畫學董生畫山水屏風','蘇轍','宋','宋诗','song-poetry','','[]','承平百事足，鴻都無不有。',192,'全唐诗/poet.song.49000.json','["承平百事足，鴻都無不有。", "策牘試篆隸，丹青寫飛走。", "紛然四方集，狐兔萃林藪。", "何人知有益，長嘯呼鷹狗。", "奔逃走城邑，驚顧念糊口。", "素屏開白雲，稱我茅檐陋。", "濡毫願揮洒，峰巒映岩竇。", "巨石連地軸，飛布瀉天漏。", "縈山一徑通，過水微橋構。", "山家烟火然，遠寺晨鐘叩。", "僧從何方來，行速午齋後。", "有客呼渡船，隔水惟病叟。", "听然發一笑，此處定真否。", "人生初偶然，與此誰夭壽。", "厄窮妄自憐，一醉輒日富。", "客至亦茫然，邀我沽斗酒。"]'),
('67e68ca3-a86c-4b53-9dd3-84475e811219','冬至日作','蘇轍','宋','宋诗','song-poetry','','[]','羲和飛轡留不住，小兒逢節喜欲舞。',112,'全唐诗/poet.song.49000.json','["羲和飛轡留不住，小兒逢節喜欲舞。", "人言老翁似小兒，烝豚釀酒多爲具。", "潁川本自非吾鄉，鄰里十年成舊故。", "誰令閉戶謝往還，壽酒獨向兒孫舉。", "飲罷跏趺閉雙目，寂然自有安心處。", "心安自謂無老少，不知鬚髮已如素。", "似聞錢重薪炭輕，今年九九不難數。"]'),
('c6d9c951-94de-4a97-beb6-987644bca854','冬至雪二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','一氣潜萌九地中，雪花微落四無風。',64,'全唐诗/poet.song.49000.json','["一氣潜萌九地中，雪花微落四無風。", "初陽便有回天力，宿瘴徐看卷地空。", "家釀再投猶恨薄，官酤多取定無功。", "時人淺陋終無益，徑就天公借一豐。"]'),
('102a7239-99c8-46fd-8800-fcf5752a9623','冬至雪二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','佳節蕭條陋巷中，雪穿窗戶有顔風。',64,'全唐诗/poet.song.49000.json','["佳節蕭條陋巷中，雪穿窗戶有顔風。", "出迎過客知非病，歸對先師喜屢空。", "黍醖盈瓢終寡味，石薪烘竈信奇功。", "頗嫌半夜欺毛褐，却喜年來麥定豐。"]'),
('f5845382-fba0-4a85-88f3-79c5e48c084b','讀樂天集戲作五絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','樂天夢得老相從，洛下詩流得二雄。',32,'全唐诗/poet.song.49000.json','["樂天夢得老相從，洛下詩流得二雄。", "自笑索居朋友絕，偶然得句與誰同。"]'),
('ba82c383-2fa3-4865-8ff7-54d958f29cc5','讀樂天集戲作五絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','樂天得法老凝師，後院猶存楊柳枝。',32,'全唐诗/poet.song.49000.json','["樂天得法老凝師，後院猶存楊柳枝。", "春盡絮飛餘一念，我今無累日無思。"]'),
('4e6626b7-277e-46c4-a17e-ef6bbd051e51','讀樂天集戲作五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','樂天投老刺杭蘇，溪石胎禽載舳艫。',32,'全唐诗/poet.song.49000.json','["樂天投老刺杭蘇，溪石胎禽載舳艫。", "我昔不爲二千石，四方異物固應無。"]'),
('ac65acaa-2696-45aa-b2b3-114a009e1376','讀樂天集戲作五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','樂天引洛注池塘，畫舫飛橋映綠楊。',32,'全唐诗/poet.song.49000.json','["樂天引洛注池塘，畫舫飛橋映綠楊。", "潩水隔城來不得，不辭策杖看湖光。"]'),
('39106c71-da88-4520-87bb-f7eecd00df5b','讀樂天集戲作五絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','樂天種竹自成園，我亦牆陰數百竿。',32,'全唐诗/poet.song.49000.json','["樂天種竹自成園，我亦牆陰數百竿。", "不共伊家鬥多少，也能不畏雪霜寒。"]'),
('2f3cf2ee-d13c-4098-b5a9-434a7b8cfcb0','記病','蘇轍','宋','宋诗','song-poetry','','[]','我病在脾胃，一病四十年。',168,'全唐诗/poet.song.49000.json','["我病在脾胃，一病四十年。", "微傷輒暴下，傾注如流泉。", "去年醫告我，此病猶可痊。", "試取薑豆附，三物相和丸。", "服之不旬浹，病去如醫言。", "醫言藥有毒，病已當速捐。", "我意藥有功，服久功則全。", "侵尋作風痹，兩足幾蹣跚。", "徐悟藥過量，醫初固云然。", "舊病則已除，奈此新病纏。", "醫言無甚憂，前藥姑捨旃。", "藥毒久自消，真氣從此完。", "鄙夫不信醫，私智每自賢。", "咄哉已往咎，終身此韋弦。"]'),
('7942fd7b-75ab-4e02-a607-792e68166030','除日二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','屠蘇末後不辭飲，七十四人今自希。',64,'全唐诗/poet.song.49000.json','["屠蘇末後不辭飲，七十四人今自希。", "筋力明年應更減，誠心憂世久知非。", "脾寒服藥近方驗，風痹經冬勢漸微。", "得罪明時歸已晚，此生此病任人譏。"]'),
('05442234-0e71-4768-8b0e-234100c33bba','除日二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','七十四年明日是，三千里外未歸人。',64,'全唐诗/poet.song.49000.json','["七十四年明日是，三千里外未歸人。", "酒篘泉涌如迎節，詩句雲生喜見春。", "賀客不來知我病，鄰家竊語笑吾真。", "時人莫作樂天看，燕坐端能畢此身。"]'),
('58bfcfcd-aa24-4689-b4cd-98b92f817622','上元','蘇轍','宋','宋诗','song-poetry','','[]','上元車馬正喧喧，老病無聊長掩門。',64,'全唐诗/poet.song.49000.json','["上元車馬正喧喧，老病無聊長掩門。", "不著繁燈眩雙目，獨邀明月上前軒。", "跏趺默坐聞三鼓，寂寞誰來共一樽。", "已覺城中塵土臭，急將清雨洗乾坤。"]'),
('31fa46d6-1ca2-48a0-bdcf-5acffb12261c','壬辰生日兒侄諸孫有詩所言皆過記胸中所懷亦自作','蘇轍','宋','宋诗','song-poetry','','[]','生日今朝是，匆匆又一年。',48,'全唐诗/poet.song.49000.json','["生日今朝是，匆匆又一年。", "讀書真已矣，閉目但茫然。", "下種言非妄，開花果定圓。", "驅羊舊有法，視後直須鞭。"]'),
('bd622eeb-2041-4005-ac48-811ba0ee1b64','白鬚','蘇轍','宋','宋诗','song-poetry','','[]','少年不辦求良藥，老病無疑生白鬚。',64,'全唐诗/poet.song.49000.json','["少年不辦求良藥，老病無疑生白鬚。", "下種已遲空悵望，無心猶幸省工夫。", "虛明對面誰知我，寵辱當前莫問渠。", "自頃閉門今十載，此生畢竟得如愚。"]'),
('1c8a2f15-ddee-4a9b-a208-71f57e2d735c','林笋','蘇轍','宋','宋诗','song-poetry','','[]','竹林遭凍曾枯死，春笋連年再發生。',64,'全唐诗/poet.song.49000.json','["竹林遭凍曾枯死，春笋連年再發生。", "天與歲寒終倔强，澤分淇澳轉敷榮。", "狂鞭已逐草侵徑，疏影長隨月到楹。", "嵇阮欲來從我餘，開門一笑亦逢迎。"]'),
('b43fe701-728b-4dc4-b970-c1e56d5d1c5e','西軒種山丹','蘇轍','宋','宋诗','song-poetry','','[]','淮陽千葉花，到此三百里。',120,'全唐诗/poet.song.49000.json','["淮陽千葉花，到此三百里。", "城中衆名園，栽接比桃李。", "吾廬適新成，西有數畦地。", "乘秋種山丹，得雨生可喜。", "山丹非佳花，老圃有深意。", "宿根已得土，絕品皆可寄。", "明年春陽升，盈尺爛如綺。", "居然盜天功，信矣斯人智。", "根苗相因依，非真亦非僞。", "客來但一笑，勿問所從致。"]'),
('e631fd43-8d07-4ea3-8f6b-1aa54c32f1f3','遊西湖','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閉門不出十年久，湖上重遊一夢回。',64,'全唐诗/poet.song.49000.json','["閉門不出十年久，湖上重遊一夢回。", "行過閭閻爭問訊，忽逢魚鳥亦驚猜。", "可憐舉目非吾黨，誰與開尊共一杯。", "歸去無言掩屏卧，古人時向夢中來。"]'),
('60ba409d-51c7-4fc9-ba74-a579ccfae8a3','泛潩水','蘇轍','宋','宋诗','song-poetry','','[]','早歲南遷恨舳艫，歸來平地憶江湖。',64,'全唐诗/poet.song.49000.json','["早歲南遷恨舳艫，歸來平地憶江湖。", "半篙春水花千片，八尺輕船酒一壺。", "徐轉城陰平野闊，稍通竹徑小亭孤。", "前朝宰相終難得，父老咨嗟今亦無。"]'),
('6cd8f116-42cc-4a4c-adfa-a6e32906202a','風痹三作','蘇轍','宋','宋诗','song-poetry','','[]','年老百病生，風痹已三作。',96,'全唐诗/poet.song.49000.json','["年老百病生，風痹已三作。", "主家長患聾，說法仍害脚。", "十年學趺坐，從此罷雀躍。", "閉目時自觀，寸田飽耕鑿。", "下種本無種，服藥亦非藥。", "田熟根自生，病去如花落。", "吾生默已定，有數誰能却。", "數盡吾則行，未應墮冥漠。"]'),
('f7697813-fbfe-4d9f-8b37-0d0fc8fa6eac','新作南門','蘇轍','宋','宋诗','song-poetry','','[]','于公决獄多陰功，自知有子當三公，高作里門車馬通。',144,'全唐诗/poet.song.49000.json','["于公决獄多陰功，自知有子當三公，高作里門車馬通。", "定國精明有父風，飲酒一石耳目聰。", "漢家宰相仍侯封，左右中興始且終。", "我家讀書自我翁，耻言法律羞兵戎。", "中年出入黄門中，智巧不足稱愚忠，雖云寡過亦無功。", "不忮不求心粗空，舉世知我惟天工。", "恃此知不累兒童，作門不庳亦不隆。", "陋巷正與顔生同，勢家笑唾儻見容。"]'),
('98f6b731-0ef8-431a-bf3a-f48e0af719d1','春旱','蘇轍','宋','宋诗','song-poetry','','[]','舊俸存無幾，生齒日益多。',120,'全唐诗/poet.song.49000.json','["舊俸存無幾，生齒日益多。", "敝廬雖粗完，空廩無麥禾。", "首種二頃田，奈此春旱何。", "誰能持隻鷄，一酹邢山阿。", "饑寒誰相念，幸龍未見呵。", "去年投虎頭，叩門用干戈。", "邂逅一尺雨，豈復陰陽和。", "幽明初不隔，誠意豈在多。", "惻然上通天，矧此一盤渦。", "雲興雨隨至，父老行且歌。"]'),
('974b2ac2-686c-481f-afcf-270b7d8148d4','感秋扇','蘇轍','宋','宋诗','song-poetry','','[]','團扇經秋似敗荷，丹青彷彿舊松蘿。',64,'全唐诗/poet.song.49000.json','["團扇經秋似敗荷，丹青彷彿舊松蘿。", "一時用舍非吾事，舉世炎凉奈爾何。", "漢代誰令收汲黯，趙人猶欲用廉頗。", "心知懷袖非安處，重見秋風愧恨多。"]'),
('37bdad0c-87e4-4975-8f88-0319fe4bd649','喜侄邁還家','蘇轍','宋','宋诗','song-poetry','','[]','一別匆匆歲五除，還家怪我白髭鬚。',64,'全唐诗/poet.song.49000.json','["一別匆匆歲五除，還家怪我白髭鬚。", "懷中初見孫三世，巷口新成宅一區。", "林下酒尊還漫設，床頭易傳近看無。", "老年遊宦真安往，南北相望結草廬。"]'),
('01943781-d9b2-450d-ad14-ca15d14f9198','次前韵','蘇轍','宋','宋诗','song-poetry','','[]','心空煩惱不須除，白盡年來罷鑷鬚。',64,'全唐诗/poet.song.49000.json','["心空煩惱不須除，白盡年來罷鑷鬚。", "隨俗治生終落落，苦心憂世漫區區。", "居連里巷知安否，食仰田園問有無。", "我已閉門還往絕，待乘明月過君廬。"]'),
('d118c1d2-905c-458c-be0f-73eb9257ef4b','喜雨','蘇轍','宋','宋诗','song-poetry','','[]','一旱經春夏已半，好雨通宵曉未收。',64,'全唐诗/poet.song.49000.json','["一旱經春夏已半，好雨通宵曉未收。", "氣爽暫令多病喜，來遲未解老農憂。", "力耕僅足公家取，遺秉休違寡婦求。", "時向林間數新竹，籜龍騰上欲迎秋。"]'),
('91f5e873-e493-43a2-a8c4-f7f4f4399726','雨過','蘇轍','宋','宋诗','song-poetry','','[]','東南流注已鳴澗，西北霏微僅斂塵。',64,'全唐诗/poet.song.49000.json','["東南流注已鳴澗，西北霏微僅斂塵。", "人意共懷艱食病，天公那有不仁人。", "雲移已分貧無福，雩應方知社有神。", "田里相望無一舍，終年苦樂會須勻。"]'),
('4462f885-af33-46d1-8fdb-46473ecebb22','溽暑','蘇轍','宋','宋诗','song-poetry','','[]','東風吹鼎方然薪，遊鱼出沒一世人。',80,'全唐诗/poet.song.49000.json','["東風吹鼎方然薪，遊鱼出沒一世人。", "隨湯上下猶欣欣，不識河漢清凉津。", "十年我已不出門，可憐尚寄生死濱。", "老知下種功力新，開花結子當有辰。", "寒暑一過聊嚬呻，至此有道非有神。"]'),
('7024f9d7-406c-477b-8b4a-fa2bb22e460d','外孫文九伏中入村曬麥','蘇轍','宋','宋诗','song-poetry','','[]','春田不雨憂無麥，入囷得半猶足食。',160,'全唐诗/poet.song.49000.json','["春田不雨憂無麥，入囷得半猶足食。", "伏中一曬不可緩，旱田蒼耳猶難得。", "人言春旱夏當潦，入伏未保天日好。", "老農經事言不虛，防風防雨如防盜。", "外孫讀書舊有功，五言七字傳祖風。", "旋投詩筆到田舍，知我老來饞且慵。", "秋田正急車難起，汗滴肩頳愧鄰里。", "磨聲細轉雪花飛，舉家百口磨牙齒。", "食前方丈我所無，烝餠十字或有諸。", "孫歸何用慰勤苦，烹鷄亦有烝胡盧。"]'),
('776cf666-1382-41bf-a55e-cbd2b5e5db1e','大雨後咏南軒竹二絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','苦寒壞我千竿綠，好雨還催衆笋長。',32,'全唐诗/poet.song.49000.json','["苦寒壞我千竿綠，好雨還催衆笋長。", "痛飲雖無嵇阮客，瓢尊一試午陰凉。"]'),
('83553ad5-ff54-4ef4-b73f-31a09c07c513','大雨後咏南軒竹二絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','葉開翡翠才通日，節竦琅玕不怕風。',32,'全唐诗/poet.song.49000.json','["葉開翡翠才通日，節竦琅玕不怕風。", "稍放西邊深二丈，端如幽谷茂林中。"]'),
('d5c70791-0d5d-443a-89fc-5da07707ed26','秋後即事','蘇轍','宋','宋诗','song-poetry','','[]','苦熱真疑不復凉，火流漸見迫西方。',64,'全唐诗/poet.song.49000.json','["苦熱真疑不復凉，火流漸見迫西方。", "清風一夜吹茅屋，竹簟今朝避石床。", "露濕中庭菊含蕊，水浮西浦稻生芒。", "秋成得飽家家事，莫笑農夫喜欲狂。"]'),
('612c1f96-ee6b-4de4-8893-a0f7d42762d3','送遲赴登封丞','蘇轍','宋','宋诗','song-poetry','','[]','昔我過嵩陽，秋高日重九。',120,'全唐诗/poet.song.49000.json','["昔我過嵩陽，秋高日重九。", "晨邀同行客，共舉登高酒。", "藤鞋生胼胝，一覽河山富。", "封壇土消盡，中夜捫星斗。", "下山雙足廢，欲上知難又。", "回首烟雲中，隠約見巖岫。", "未老約來遊，何意七十後。", "吾兒性靜默，丞邑山路口。", "秋暑山尚煩，冬雪山方瘦。", "春山利遊觀，安輿即迎父。"]'),
('96b48b04-d908-4f8d-8ae3-dbe4f2db5d95','省事','蘇轍','宋','宋诗','song-poetry','','[]','早歲讀書無甚解，晚年省事有奇功。',64,'全唐诗/poet.song.49000.json','["早歲讀書無甚解，晚年省事有奇功。", "自許平生初不錯，人言畢竟兩皆空。", "空中有實何人見，實際心知與佛同。", "煩惱消除病亦去，閉門便了此生中。"]'),
('92f8af51-bfc2-4825-8ad2-08e3b391fb82','廣福僧智昕西歸','蘇轍','宋','宋诗','song-poetry','','[]','老人寄東巖，蕭然四無鄰。',144,'全唐诗/poet.song.49000.json','["老人寄東巖，蕭然四無鄰。", "八尺清冷泉，中有白髮人。", "婆娑弄明月，松間夜相賓。", "平生指庚壬，終老投此身。", "築室潁川市，西望長悲辛。", "故山比丘僧，繭足超峨岷。", "歸塗三千里，秋風入衣巾。", "北崦百步外，我夢一室新。", "速營三間堂，永奉兩足尊。", "我歸要有時，久遠與子親。", "悟老非凡僧，瓦礫化金銀。", "歸來味玄言，見日當自陳。"]'),
('47b9c1a8-47f2-46de-8277-578e027aa4a4','種藥苗二首 種甖粟 其一','蘇轍','宋','宋诗','song-poetry','','[]','築室城西，中有圖書。',40,'全唐诗/poet.song.49000.json','["築室城西，中有圖書。", "窗戶之餘，松竹扶疏。", "拔棘開畦，以毓嘉蔬。", "畦夫告予，甖粟可儲。"]'),
('301a6904-e7c9-4e61-af46-6d67702a06da','種藥苗二首 種甖粟 其二','蘇轍','宋','宋诗','song-poetry','','[]','甖小如甖，粟細如粟。',40,'全唐诗/poet.song.49000.json','["甖小如甖，粟細如粟。", "與麥皆種，與穄皆熟。", "苗堪春菜，實比秋穀。", "研作牛乳，烹爲佛粥。"]'),
('329d3d11-d98a-4929-bebf-349b22379d76','種藥苗二首 種甖粟 其三','蘇轍','宋','宋诗','song-poetry','','[]','老人氣衰，飲食無幾。',40,'全唐诗/poet.song.49000.json','["老人氣衰，飲食無幾。", "食肉不消，食菜寡味。", "柳槌石鉢，煎以蜜水。", "便口利喉，調養肺胃。"]'),
('95818858-2bd1-4990-961b-15e43f19d0b1','種藥苗二首 種甖粟 其四','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三年杜門，莫適往還。',40,'全唐诗/poet.song.49000.json','["三年杜門，莫適往還。", "幽人衲僧，相對忘言。", "飲之一杯，失笑欣然。", "我來潁川，如遊廬山。"]'),
('301f9ff3-518d-47f8-9399-f799b4e5c9aa','種藥苗二首 種决明 其一','蘇轍','宋','宋诗','song-poetry','','[]','閑居九年，祿不代耕。',40,'全唐诗/poet.song.49000.json','["閑居九年，祿不代耕。", "肉食不足，藜烝藿羹。", "多求異蔬，以佐晨烹。", "秋種甖粟，春種决明。"]'),
('182a0e32-2d32-4f55-9175-9de6cc85e223','種藥苗二首 種决明 其二','蘇轍','宋','宋诗','song-poetry','','[]','决明明目，功見本草。',40,'全唐诗/poet.song.49000.json','["决明明目，功見本草。", "食其花葉，亦去熱惱。", "有能益人，矧可以飽。", "三嗅不食，笑杜陵老。"]'),
('ed78c55d-0696-4cad-9e5c-d19eec355a6a','種藥苗二首 種决明 其三','蘇轍','宋','宋诗','song-poetry','','[]','老人平生，以書爲累。',40,'全唐诗/poet.song.49000.json','["老人平生，以書爲累。", "夜燈照帷，未曉而起。", "百骸未病，兩目告瘁。", "决明雖良，何補於是。"]'),
('c229229d-22ef-4631-851b-e82a09187917','種藥苗二首 種决明 其四','蘇轍','宋','宋诗','song-poetry','','[]','自我知非，卷去圖書。',40,'全唐诗/poet.song.49000.json','["自我知非，卷去圖書。", "閉目內觀，妙見自如。", "聞阿那律，無目而視。", "决明何爲，適口乎爾。"]'),
('095d8596-3b30-4b2f-859f-66f41cb11f8f','上巳','蘇轍','宋','宋诗','song-poetry','','[]','春服初成日暖，潩河漸滿風凉。',112,'全唐诗/poet.song.49000.json','["春服初成日暖，潩河漸滿風凉。", "欲復孔門故事，略有童冠相將。", "城西百步而近，杏花半落草香。", "欣然願與數子，臨水一振衣裳。", "故人有酒未酌，爲我班荆舉觴。", "我雖少飲不醉，未怪遊人若狂。", "春風自爾一月，花絮極目飛揚。", "誦詩相勸行樂，良士但取無荒。"]'),
('a54157c9-ee11-4114-8b98-6cf0ff854527','上巳後','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上巳已過旬日，西湖尚有遊人。',140,'全唐诗/poet.song.49000.json','["上巳已過旬日，西湖尚有遊人。", "老人復歸閉戶，戶外百事日新。", "呼童試問築室，春晚何日堂成。", "我家舊廬江上，隠居三世相因。", "晏子不願改卜，我今已愧先君。", "始有苟合則止，已老姑欲安身。", "西望烝嘗有處，傳家圖史常陳。", "門中此外何事，世故有耳不聞。", "食訖趺坐日昃，此心皎皎常存。", "萬事汝勿告我，婚嫁自畢諸孫。"]'),
('b95125b2-a7b3-40b3-b156-d7ac9e2ac0de','堂成','蘇轍','宋','宋诗','song-poetry','','[]','築室三年，堂成可居。',240,'全唐诗/poet.song.49000.json','["築室三年，堂成可居。", "我初不知，諸子勞劬。", "父母老矣，風雨未除。", "橐裝幾何，勿問有無。", "伐木於山，因此舊廬。", "不約不豐，燕處無餘。", "堂開六楹，南北四筵。", "晝明廓然，夜冥黯然。", "四鄰無聲，布被粗氈。", "身非蚌螺，一睡經年。", "夜如何其，趺坐燕安。", "善惡不思，此心自圓。", "東廂靖深，以奉嘗烝。", "老佛之廬，朝香夜燈。", "西廂千卷，圖書之林。", "先人所遺，子孫是承。", "杖屨經行，直如引繩。", "顧視而笑，此如我心。", "諸子之室，左右吾背。", "將食擊板，一擊而會。", "瓜畦芋區，分布其外。", "鋤去瓦礫，壤而不塊。", "廢井重浚，泉眼仍在。", "轆轤雷鳴，甘雨時霈。"]'),
('bb0cdb3e-5254-4f4b-a301-a53f60163d85','雙柳','蘇轍','宋','宋诗','song-poetry','','[]','我作新堂，中庭蕭然，雙柳對峙。',150,'全唐诗/poet.song.49000.json','["我作新堂，中庭蕭然，雙柳對峙。", "春陽既應，千條萬葉，風濯雨洗。", "如美婦人，正立櫛髮，髮長至地。", "微風徐來，掩冉相繆，亂而復理。", "垂之爲纓，綰之爲結，屈伸如意。", "燕雀翔舞，蜩蜇嘶鳴，不召而至。", "清霜夜落，衆葉如剪，顔色憔悴。", "永愧松柏，歲寒不改，見嘆夫子。", "聊同淵明，攀條嘯咏，得酒徑醉。", "一廛粗給，三黜不去，亦如展惠。"]'),
('af6b2ad7-559a-44e8-92c7-17ac3eaabf56','大雨聯句','蘇轍','宋','宋诗','song-poetry','','[]','庭松偃蓋如醉，夏雨新凉似秋。',28,'全唐诗/poet.song.49000.json','["庭松偃蓋如醉，夏雨新凉似秋。", "有客高吟擁鼻，無人共吃饅頭。"]'),
('f2c91ffb-00bd-4da8-aa24-c60d769d36ba','和子瞻和陶淵明雜詩十一首  其一','蘇轍','宋','宋诗','song-poetry','','[]','大道與衆往，疾驅祗自塵。',72,'全唐诗/poet.song.49000.json','["大道與衆往，疾驅祗自塵。", "徐行聽所之，何者非吾身。", "却過白鶴峰，鷄犬來相親。", "築室依果樹，有無通四鄰。", "安眠豈有足，良夜惟恐晨。", "晨朝亦何事，倦對往來人。"]'),
('3ec9f6e5-236a-4e18-8ec5-3fa6f3de643a','和子瞻和陶淵明雜詩十一首  其二','蘇轍','宋','宋诗','song-poetry','','[]','莫言三謫遠，歸路近庾嶺。',84,'全唐诗/poet.song.49000.json','["莫言三謫遠，歸路近庾嶺。", "誰憐東坡窮，垂老徙此景。", "幸無薪炭役，豈念冰雪冷。", "平生笑子厚，山水記柳永。", "孜孜苦懷歸，何異走逃影。", "吾觀兩蠻觸，出縮方馳騁。", "百年寄龜息，幸此支床靜。"]'),
('287a8e89-25d9-4b91-bc58-6f29db53e12b','和子瞻和陶淵明雜詩十一首  其三','蘇轍','宋','宋诗','song-poetry','','[]','我來適惡歲，斗米如珠量。',60,'全唐诗/poet.song.49000.json','["我來適惡歲，斗米如珠量。", "何時舉頭看，歲月守心房。", "念我東坡翁，忍饑海中央。", "願翁勿言饑，稷調陰陽。", "玉池有清水，生肥滿中腸。"]'),
('f7738ca3-a946-471d-9519-eb2e4f891b00','和子瞻和陶淵明雜詩十一首  其四','蘇轍','宋','宋诗','song-poetry','','[]','故山縱得歸，無復昔遺老。',72,'全唐诗/poet.song.49000.json','["故山縱得歸，無復昔遺老。", "家風知在否，後生恐難保。", "似聞老翁泉，曾作泥土燥。", "窮冬忽涌溢，絡繹瓶甕早。", "此翁終可信，明月耿懷抱。", "從我先人游，安得不聞道。"]'),
('80c1d2d7-f3ec-455d-b156-8bf5c74abf30','和子瞻和陶淵明雜詩十一首  其五','蘇轍','宋','宋诗','song-poetry','','[]','幽憂如蟄蟲，雷雨驚奮豫。',96,'全唐诗/poet.song.49000.json','["幽憂如蟄蟲，雷雨驚奮豫。", "無根不萌動，有翼皆鶱翥。", "嗟我獨枯槁，無來孰爲去。", "念兄當北遷，海闊煎百慮。", "往來七年間，信矣夢幻如。", "從今便築室，占籍無所住。", "四方無不可，莫住生滅處。", "縱浪大化中，何喜復何懼。"]'),
('e2dc0e17-992e-44bc-8ca1-e615a4ff5bc2','和子瞻和陶淵明雜詩十一首  其六','蘇轍','宋','宋诗','song-poetry','','[]','嘗聞左師言，少子古所喜。',72,'全唐诗/poet.song.49000.json','["嘗聞左師言，少子古所喜。", "二兒從兩父，服辱了百事。", "佳子何關人，自怪餘此意。", "看書時獨笑，屢與古人值。", "他年會六子，道眼誰最駛。", "衣鉢儻可傳，田園不須置。"]'),
('b11afb56-b638-4c8b-b2c9-d6bc81bf770e','和子瞻和陶淵明雜詩十一首  其七','蘇轍','宋','宋诗','song-poetry','','[]','舜以五音言，二雅良褊迫。',72,'全唐诗/poet.song.49000.json','["舜以五音言，二雅良褊迫。", "變風猶井牧，驅人遂阡陌。", "周餘幾崩壞，况經甫與白。", "崎嶇收狂瀾，還付濫觴窄。", "蒙莊涇渭雜，恐有郭象客。", "壁藏待知者，金石聞舊宅。"]'),
('446a47f5-c606-4b36-a5b8-d7bdeb006407','和子瞻和陶淵明雜詩十一首  其八','蘇轍','宋','宋诗','song-poetry','','[]','大道如衣食，六經所耕桑。',84,'全唐诗/poet.song.49000.json','["大道如衣食，六經所耕桑。", "家傳易春秋，未易相粃糠。", "久種終不穫，歲晚嗟無糧。", "念此坐嘆息，追飛及頹陽。", "天公亦假我，書成麟未傷。", "可憐陸忠州，空集千首方。", "何如學袁盎，日把無可觴。"]'),
('94f334fd-7f1a-4786-b389-25f9b1f3b0f0','和子瞻和陶淵明雜詩十一首  其九','蘇轍','宋','宋诗','song-poetry','','[]','五年寓黄閣，盛服朝玄端。',72,'全唐诗/poet.song.49000.json','["五年寓黄閣，盛服朝玄端。", "愧無昔人姿，謬作奇章遷。", "還從九淵底，回望百尺巔。", "身世俱一夢，往來適三餐。", "天公本無心，誰爲此由緣。", "從今罷述作，盡付逍遥篇。"]'),
('66f54fe2-6925-459a-961b-af53804e3b0b','和子瞻和陶淵明雜詩十一首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','吾兄昔在朝，屢欲請會稽。',84,'全唐诗/poet.song.49000.json','["吾兄昔在朝，屢欲請會稽。", "誓將老陽羨，洞天隠蒼崖。", "時事乃大謬，寧復守此懷。", "區區芥子中，豈有兩須彌。", "舉眼即見兄，何者爲別離。", "尻輿駕神馬，孰爲策與羈。", "弭節過蓬萊，海波看增虧。"]'),
('1b55b986-fb8f-4f34-8526-f622eb26d732','和子瞻和陶淵明雜詩十一首  其一一','蘇轍','宋','宋诗','song-poetry','','[]','紅爐厄夏景，團扇悲秋凉。',60,'全唐诗/poet.song.49000.json','["紅爐厄夏景，團扇悲秋凉。", "來鴻已遵渚，去燕亦辭梁。", "冰蠶懷凍藪，火鼠安炎鄉。", "曲士漫談道，夏蟲豈知霜。", "物化何時休，嘆息此路長。"]'),
('beb4cb4a-83d0-4596-95d3-b1c4f72fb177','聯句嘲僧','蘇轍','宋','宋诗','song-poetry','','[]','玉筯插銀河，紅裙蘸碧波。',24,'全唐诗/poet.song.49000.json','["玉筯插銀河，紅裙蘸碧波。", "更行三五步，浸着老僧窠。"]'),
('7a73967e-361c-4853-9048-4d066bc69955','上元後一日觀燈寄王四','蘇轍','宋','宋诗','song-poetry','','[]','城頭月減一分圓，城裏人家萬炬然。',64,'全唐诗/poet.song.49000.json','["城頭月減一分圓，城裏人家萬炬然。", "紫陌羣遊逢酒住，紅裙醉舞向人妍。", "且爲行樂終今夕，共道重來便隔年。", "遥想猖狂夜深處，河沙飛水濕歸韉。"]'),
('1731ce93-6ec5-4a45-a9d0-d2138a00de67','次韵仇池冬至日見寄','蘇轍','宋','宋诗','song-poetry','','[]','身如草木順陰陽，附火重裘百日强。',64,'全唐诗/poet.song.49000.json','["身如草木順陰陽，附火重裘百日强。", "漸喜微和解凝烈，半酣起舞意倉忙。", "吾兄去我行三臘，千里今宵共一觴。", "世事只今人自解，苦寒須盡酒如湯。"]'),
('4ef82c38-3642-4498-b2c2-fbc6ab67d197','益昌除夕感懷','蘇轍','宋','宋诗','song-poetry','','[]','永漏侵春已數籌，地爐猶擁木綿裘。',64,'全唐诗/poet.song.49000.json','["永漏侵春已數籌，地爐猶擁木綿裘。", "無心豈畏三尸訴，愛日還驚一歲休。", "故國二千空醉眼，新年三十恰平頭。", "光陰未用相敦迫，領取衰翁兩鬢秋。"]'),
('9c9aa318-dcac-458c-bd95-8668f7a22df2','除夕','蘇轍','宋','宋诗','song-poetry','','[]','患難思年改，龍鍾惜歲徂。',48,'全唐诗/poet.song.49000.json','["患難思年改，龍鍾惜歲徂。", "關河先壠遠，天地小臣孤。", "吾道憑溫酒，時情付擁爐。", "南荒足妖怪，此日謾桃符。"]'),
('b8dd89f1-333c-43f8-82da-4869f2ab8f72','四月二十八日新熱寄仇池','蘇轍','宋','宋诗','song-poetry','','[]','細莎爲屨如編鬚，輕葛爲服如剪莩。',144,'全唐诗/poet.song.49000.json','["細莎爲屨如編鬚，輕葛爲服如剪莩。", "寒泉洒屋朝露濡，霜簟可薦机可扶。", "風鳴牖間如吹竽，此雖有暑宜亦無。", "庭前峻山槎之餘，盆中養鰍大如魚。", "荻生抱甲未見膚，蔓起上屋將懸壺。", "麥苗高齊可藏烏，此雖非野僅亦如。", "兄居溪堂南山趺，濯足溪水驚雁鳬。", "澄潭百丈清無淤，將往思我立踟躕。", "東軒鄙陋何足居，欲行不行繫轅駒。"]'),
('e49eb1a9-52ff-481c-b0f0-acfc7de36b81','六月十三日病起走筆寄仇池','蘇轍','宋','宋诗','song-poetry','','[]','入伏節氣變，翛然如九秋。',288,'全唐诗/poet.song.49000.json','["入伏節氣變，翛然如九秋。", "牆上有短樹，庭下風颼颼。", "風來吹我衣，虻蚋各已收。", "移床就堂下，仰見月成鈎。", "但與支體快，不作腑臟謀。", "半夜起寒熱，展轉脫水鰌。", "藥劑失先後，欲速反見留。", "不免召楊子，把臂揣厥由。", "笑我冷治冷，徒爾苦舌喉。", "授我桂與薑，乃始與病投。", "逾旬不出戶，映牖披重裘。", "遥聞南山下，不與他土侔。", "山寒雪不解，清氣晝夜浮。", "餘冷入市城，煩熱遭濯潄。", "况乃郡齋靜，滿地貯清流。", "露濕荷葉凈，月上松柏幽。", "牆頭白楊樹，秋聲無時休。", "夜蜩感寒氣，上樹鳴啾啾。", "野鶴弄池水，落拍翅羽修。", "此處雖可愛，慎勿恣意遊。", "凡人愛凉冷，凉冷乃熱讎。", "試掃北窗下，靜卧却所憂。", "屏扇去冰雪，虛室風自油。", "歲熱强自厚，良藥彼有不。"]'),
('f5456798-0a26-44d5-ad66-f6d8addd5e28','題三游洞石壁','蘇轍','宋','宋诗','song-poetry','','[]','昔年有遷客，携手醉嵌巖。',24,'全唐诗/poet.song.49000.json','["昔年有遷客，携手醉嵌巖。", "去我歲已百，游人忽復三。"]'),
('57d8480f-9d35-45c5-8868-14ee75653858','渚宮','蘇轍','宋','宋诗','song-poetry','','[]','楚塞多秋水，荆王有故宮。',36,'全唐诗/poet.song.49000.json','["楚塞多秋水，荆王有故宮。", "湘東晉宗子，高氏楚元戎。", "鑿沼長千尺，開亭費萬工。"]'),
('5fbebbca-3fe6-41ce-81f1-130f3f3d73b8','留題仙都觀','蘇轍','宋','宋诗','song-poetry','','[]','道士白髮尊，面黑嵐氣染。',72,'全唐诗/poet.song.49000.json','["道士白髮尊，面黑嵐氣染。", "自言王方平，學道古有驗。", "道成白晝飛，人世不留窆。", "後有陰長生，此地亦所占。", "並騎雙翔龍，霞綬紫雲襜。", "揚揚玉堂上，與世作豐歉。"]'),
('6f4bdcbb-a67c-40b2-82b9-50925c769a13','題李十八黄龍寺畫壁','蘇轍','宋','宋诗','song-poetry','','[]','胸次崢嶸落筆端，壁題留與老夫看。',32,'全唐诗/poet.song.49000.json','["胸次崢嶸落筆端，壁題留與老夫看。", "枯槎尚倚春風力，蒼竹從來自歲寒。"]'),
('4d091219-b70f-40b8-9ff6-a48fe6f435ec','次韵張禹直開元寺觀畫壁兼簡李德素','蘇轍','宋','宋诗','song-poetry','','[]','丹青古藏壁，風雨飽侵藻。',240,'全唐诗/poet.song.49000.json','["丹青古藏壁，風雨飽侵藻。", "拂塵開蝕鑒，志士淚霑臆。", "靈山遠飛來，不可以智測。", "龍神湛回向，擁衛立劍戟。", "依然吳生手，旌旆略可識。", "鴻濛插樓臺，毫髮數動植。", "廣床瞻二聖，有衆拱萬德。", "飛行湊六合，攬取著一席。", "人人開生面，絕妙推心得。", "李侯天機深，指點目所及。", "三生石上夢，天樂鳴我側。", "幽尋前日事，晦明忽復易。", "章生南溟鵬，籠檻鎖六翮。", "能同寂寞遊，濁酒聊放適。", "西風葉瀟瀟，蟋蟀依牆壁。", "家無萬金産，四鄰砧聲急。", "藜羹傲鼎食，藍縷亦山立。", "並船有歌姝，粉白眉黛黑。", "期公開顔笑，醉語雜翰墨。", "不須談俗事，祇令人氣塞。"]'),
('efb4bfb2-edf9-4853-819c-27a839e3f952','寇萊公','蘇轍','宋','宋诗','song-poetry','','[]','人知公惠在巴東，不識三朝社稷功。',32,'全唐诗/poet.song.49000.json','["人知公惠在巴東，不識三朝社稷功。", "平日孤舟已何處，江亭依舊傍秋風。"]'),
('26a5f293-b992-48b7-81b6-03e260385dff','過豫章','蘇轍','宋','宋诗','song-poetry','','[]','白屋可能無孺子，黄圭不是欠陳蕃。',32,'全唐诗/poet.song.49000.json','["白屋可能無孺子，黄圭不是欠陳蕃。", "古人冷淡今人笑，湖水年年刺舊痕。"]'),
('3d36c40b-a1bf-44d8-b916-09c6f51d92e7','初春游李太尉宅東池','蘇轍','宋','宋诗','song-poetry','','[]','蓬島靈仙宅，星河帝女居。',48,'全唐诗/poet.song.49000.json','["蓬島靈仙宅，星河帝女居。", "波光泛金翠，樓影動雲霞。", "清淺游魚過，參差垂柳斜。", "移舟更尋勝，遠見小桃花。"]'),
('335c5b1c-f164-4d72-b0a8-ffb60d1b277b','次韵程相公以柳湖久涸輒引蔡水溉注感而成咏二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','鱗鱗沙脚出平湖，一噴珠璣碧有餘。',64,'全唐诗/poet.song.49000.json','["鱗鱗沙脚出平湖，一噴珠璣碧有餘。", "依舊鏡中橫紫閣，却從天外望仙閭。", "粉花又結青蓮子，金尾還跳赤鯉魚。", "自惜支離苦爲病，重來應共酒杯疏。"]'),
('a5bc0b06-5f17-48a9-a55c-2544369f4da8','次韵程相公以柳湖久涸輒引蔡水溉注感而成咏二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','老魚呴鬣困無津，鑿破靈河漲舊濆。',64,'全唐诗/poet.song.49000.json','["老魚呴鬣困無津，鑿破靈河漲舊濆。", "明月還從沙渚見，紅塵却傍柳堤分。", "急泉垂下長虹尾，駴浪飛來白鷺群。", "范蠡如聞應更愛，解摇雙槳入西曛。"]'),
('112adadf-a1ab-462f-8dbd-f190d6440a50','詩一首','蘇轍','宋','宋诗','song-poetry','','[]','君不見峨眉山西雪千里，北望成都如井底。',99,'全唐诗/poet.song.49000.json','["君不見峨眉山西雪千里，北望成都如井底。", "春風百日吹不消，五月行人如凍蟻。", "紛紛市人爭奪中，誰信言公似贊公。", "人間熱惱無處洗，故向西齋作雪峰。", "我夢扁舟適吳越，長廊靜院燈如月。", "開門不見人與牛，惟見空庭滿山雪。"]'),
('c4c32c10-2b4b-43d4-a87d-b501c3334060','留題石經院三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','岧嶢山上寺，近在古城中。',24,'全唐诗/poet.song.49000.json','["岧嶢山上寺，近在古城中。", "苦恨河流遠，長教眼力窮。"]'),
('d7e66bee-ba3a-403d-8aa8-95c89a8b52a7','留題石經院三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','盤曲山前路，流年向此消。',24,'全唐诗/poet.song.49000.json','["盤曲山前路，流年向此消。", "興亡須一弔，范叟卧山腰。"]'),
('c46d5596-25d7-465a-84e1-a50d9e5b652c','留題石經院三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','孤絕山南寺，僧居無限清。',24,'全唐诗/poet.song.49000.json','["孤絕山南寺，僧居無限清。", "不知行道處，空聽暮鐘聲。"]'),
('1b013e90-2353-4a87-931d-a16883ab52a6','絕勝亭','蘇轍','宋','宋诗','song-poetry','','[]','夜郎秋漲水連空，上有虛亭縹緲中。',64,'全唐诗/poet.song.49000.json','["夜郎秋漲水連空，上有虛亭縹緲中。", "山滿長天宜落日，江吹曠野作驚風。", "爨烟慘淡浮前浦，漁艇縱橫逐釣筒。", "未省岳陽何似此，應須子細問南公。"]'),
('da1637b2-81d2-4912-9c00-ee4deb05f168','張公洞','蘇轍','宋','宋诗','song-poetry','','[]','亂山深處白雲堆，地坼中空洞府開。',64,'全唐诗/poet.song.49000.json','["亂山深處白雲堆，地坼中空洞府開。", "繭甕有天含宇宙，瑶臺無路接蓬萊。", "金芝春暖青牛卧，珠樹月明黄鶴回。", "此日登臨興何限，春風吹綻碧桃腮。"]'),
('9c275848-7255-4e73-be3d-df8f7f796c67','雎陽五老圖','蘇轍','宋','宋诗','song-poetry','','[]','賢才冠世得優閒，免向金門老贅冠。',64,'全唐诗/poet.song.49000.json','["賢才冠世得優閒，免向金門老贅冠。", "頌德華名盈滿軸，規章文獻表穹桓。", "宦家有道生忠烈，夷夏初寧諫齒寒。", "正是紫微垣裏客，如今列上畫圖看。"]'),
('3c7a5d08-566c-4a39-9c05-fc19cc9ce99c','金沙臺','蘇轍','宋','宋诗','song-poetry','','[]','待罪東軒僅兩秋，搉酤事了且夷猶。',64,'全唐诗/poet.song.49000.json','["待罪東軒僅兩秋，搉酤事了且夷猶。", "奬崇善類詢輿論，過訪仁賢棹小舟。", "契合通家心異姓，情敦同氣邁凡流。", "金沙臺上聊舒樂，即景題詩閤酒甌。"]'),
('5ce5d050-e426-4a58-af59-8aa837cc67b0','句  其一','蘇轍','宋','宋诗','song-poetry','','[]','無山得似巫山秀，何水能如河水清。',16,'全唐诗/poet.song.49000.json','["無山得似巫山秀，何水能如河水清。"]'),
('e37a3d75-530e-4b12-bed6-68b202b948e5','句  其二','蘇轍','宋','宋诗','song-poetry','','[]','謂語巴東人，世世當諱準。',12,'全唐诗/poet.song.49000.json','["謂語巴東人，世世當諱準。"]'),
('10ecd5cd-d428-4fd4-8717-51f499ea56d7','句  其三','蘇轍','宋','宋诗','song-poetry','','[]','仿佛城南路，繁香撲市橋。',12,'全唐诗/poet.song.49000.json','["仿佛城南路，繁香撲市橋。"]'),
('59362a03-459a-420c-87ab-9759c4c75927','句  其四','蘇轍','宋','宋诗','song-poetry','','[]','清江入城郭，小浦生微瀾。',12,'全唐诗/poet.song.49000.json','["清江入城郭，小浦生微瀾。"]'),
('a488ab88-9033-447f-b591-cda2d52569f1','送程給事知越州  其一','何正臣','宋','宋诗','song-poetry','','[]','史君承詔出黄扉，急漿翩翩畫鷁飛。',58,'全唐诗/poet.song.49000.json','["史君承詔出黄扉，急漿翩翩畫鷁飛。", "天上鵷鸞猿鶴喜頻歸。", "列城將吏瞻戎節，夾道鄉人看錦衣。", "今古蓬萊足吟咏，更留風月待珠璣。"]'),
('052127da-0822-44a7-9a6b-5a4100416ad5','送程給事知越州  其二','何正臣','宋','宋诗','song-poetry','','[]','立就金城漳海邊，從來經制祇茫然。',64,'全唐诗/poet.song.49000.json','["立就金城漳海邊，從來經制祇茫然。", "一千里候無宵警，十萬人家自晏眠。", "異城早聞回陣馬，將軍從此罷樓船。", "功成事往翻然去，用捨如公信可賢。"]'),
('0d80c8be-2478-4829-ad88-57d171bb4aa5','運司園亭 西園','杜敏求','宋','宋诗','song-poetry','','[]','潭潭刺史府，宛在城市中。',48,'全唐诗/poet.song.49000.json','["潭潭刺史府，宛在城市中。", "誰知園亭勝，似與山林同。", "幽鳥語晴晝，好花嬌春風。", "物情如有待，賦咏屬詩翁。"]'),
('19a4d6e8-03aa-49a7-84b2-adedd097c461','運司園亭 玉溪堂','杜敏求','宋','宋诗','song-poetry','','[]','堂前對花柳，堂後瞰沼沚。',48,'全唐诗/poet.song.49000.json','["堂前對花柳，堂後瞰沼沚。", "賢者堂中人，虛心湛如水。", "煩暑當風窗，中宵隱月几。", "作詩紀勝概，詩與水清泚。"]'),
('4733423f-766e-497a-8bcf-e80c102ca0c5','運司園亭 雪峰樓','杜敏求','宋','宋诗','song-poetry','','[]','西山最高峰，積雪連四季。',48,'全唐诗/poet.song.49000.json','["西山最高峰，積雪連四季。", "登樓試寓目，入國有故地。", "烽候雖久息，武經思豫備。", "文饒昔籌邊，公意今無愧。"]'),
('97d311e5-7b9f-4089-a250-3cf378faa11d','運司園亭 海棠軒','杜敏求','宋','宋诗','song-poetry','','[]','東風開百花，獨有海棠勝。',48,'全唐诗/poet.song.49000.json','["東風開百花，獨有海棠勝。", "猩血染珠璣，點綴枝條賸。", "日暖錦段新，雨餘燕脂凝。", "何待東閤梅，方能動詩興。"]'),
('ed2d2221-86a2-4d6b-8c4a-b14b7651bfa4','運司園亭 月臺','杜敏求','宋','宋诗','song-poetry','','[]','明從海上來，皎皎入我牖。',48,'全唐诗/poet.song.49000.json','["明從海上來，皎皎入我牖。", "何如登高臺，對月把尊酒。", "問月月無言，浩歌詩千首。", "幾人知此樂，此樂公所有。"]'),
('0526d743-059a-4735-a2b7-754fb8a4952a','運司園亭 翠錦亭','杜敏求','宋','宋诗','song-poetry','','[]','材大難爲用，嘗誇古柏篇。',48,'全唐诗/poet.song.49000.json','["材大難爲用，嘗誇古柏篇。", "亭前老楩楠，黛色亦參天。", "夏暑借清陰，秋籟得自然。", "有如愛庭楸，朝暮東西偏。"]'),
('3c4ca59f-db31-4037-b776-5ba55be62453','運司園亭 湲玉亭','杜敏求','宋','宋诗','song-poetry','','[]','林亭幽且深，砌下玉溪水。',48,'全唐诗/poet.song.49000.json','["林亭幽且深，砌下玉溪水。", "淙琤環珮聲，曉夕清心耳。", "使君性所樂，愛玩不少已。", "方持利物心，默坐窮至理。"]'),
('fa92f47d-67cb-442a-a129-acaf85ab5905','運司園亭 茅庵','杜敏求','宋','宋诗','song-poetry','','[]','深深竹林下，圓庵最幽僻。',48,'全唐诗/poet.song.49000.json','["深深竹林下，圓庵最幽僻。", "高懷本恬曠，野趣助閒適。", "衆人奔名徒，浮世縈物役。", "豈知庵中樂，道勝心自逸。"]'),
('d4cd0d6b-bb9a-4695-8a2c-7ad66c9df061','運司園亭 水閣','杜敏求','宋','宋诗','song-poetry','','[]','方池導流水，橫閣上尋丈。',49,'全唐诗/poet.song.49000.json','["方池導流水，橫閣上尋丈。", "晨曦夜月光，罩影相滉漾。", "游魚時出沒，飛鷗亦下上。", "終朝倚欄桿杆，不見有風浪。"]'),
('b4aa32c3-983d-40df-b9c2-9ddcf7bf3ede','運司園亭 小亭','杜敏求','宋','宋诗','song-poetry','','[]','二亭雖云小，好在泉石間。',48,'全唐诗/poet.song.49000.json','["二亭雖云小，好在泉石間。", "白石自齒齒，清泉亦潺潺。", "公府無留事，暫來寄余閑。", "筇杖烏角巾，一日幾往還。"]'),
('10e3245a-c900-4299-ae92-b9959fb73b04','句','杜敏求','宋','宋诗','song-poetry','','[]','農夫苦相問，燮理是何人。',12,'全唐诗/poet.song.49000.json','["農夫苦相問，燮理是何人。"]'),
('ef787745-ff4b-4877-a816-9794daccbd32','句','韓宗恕','宋','宋诗','song-poetry','','[]','若使漢廷重用賦，子虛應恨不同年。',16,'全唐诗/poet.song.49000.json','["若使漢廷重用賦，子虛應恨不同年。"]'),
('4bd65ed6-46d5-4932-9e97-f5d7a56319d4','耳疾去後呈東坡','王詵','宋','宋诗','song-poetry','','[]','老婆心急頻相勸，性難只得三日限。',32,'全唐诗/poet.song.49000.json','["老婆心急頻相勸，性難只得三日限。", "我耳已較君不割，且喜兩家皆平善。"]'),
('47e2cd19-f7e7-4f63-a759-770b19b2de4e','過後避莊宗廟寄曹殿帥貫道','王詵','宋','宋诗','song-poetry','','[]','代梁繼李號良圖，却惑歌兒便喪軀。',32,'全唐诗/poet.song.49000.json','["代梁繼李號良圖，却惑歌兒便喪軀。", "試拂塵埃覘遺像，元來滿面是髭鬚。"]'),
('034243ed-a2cd-48cd-b3de-e40083873bd2','潁昌湖上贈諸公','王詵','宋','宋诗','song-poetry','','[]','清影十分月，暗香干柄蓮。',24,'全唐诗/poet.song.49000.json','["清影十分月，暗香干柄蓮。", "不知從此別，高會復何年。"]'),
('3f049e6a-8204-4b91-9df3-b04bbc534c2b','奉和子瞻內翰見贈長韻','王詵','宋','宋诗','song-poetry','','[]','帝子相從玉斗邊，洞簫忽斷散非煙。',230,'全唐诗/poet.song.49000.json','["帝子相從玉斗邊，洞簫忽斷散非煙。", "平生未省山水窟，一朝身到心茫然。", "長安日遠那復見，掘地寧知能及泉。", "幾年漂泊漢江上，東流不舍悲長川。", "山重水遠景無盡，翠幕金屏開目前。", "晴雲冪冪曉籠岫，碧嶂溶溶春接天。", "四時爲我供畫本，巧自增損媸與妍。", "心匠構盡遠江意，筆鋒耕徧西山田。", "蒼顔華髪何所遣，聊將戲墨忘餘年。", "將軍色山自金碧，蕭郎翠竹夸嬋娟。", "風流千載無虎頭，於今妙絕推龍眠。", "豈圖俗筆掛高詠，從此得名因謫仙。", "愛詩好畫本天性，輞口先生疑宿緣。", "會當別寫一匹煙霞境，更應消得玉堂醉筆揮長篇。"]'),
('c2d2251c-a6a8-47ec-aece-4d0c52e8d91f','子瞻再和前篇非惟格韻高絕而語意鄭重相與甚厚因復用韻答謝之','王詵','宋','宋诗','song-poetry','','[]','憶從南澗北山邊，慣見嶺雲和野煙。',224,'全唐诗/poet.song.49000.json','["憶從南澗北山邊，慣見嶺雲和野煙。", "山深路僻空弔影，夢驚松竹風蕭然。", "杖藜芒屩謝塵境，已甘老去栖林泉。", "春籃採朮問康伯，夜竈養丹陪稚川。", "漁樵每笑坐爭席，鷗鷺無機馴我前。", "一朝忽作長安夢，此生猶欲更問天。", "歸來未央拜天子，枯荄敢自期春妍。", "造物潛移真幻影，感時未用驚桑田。", "醉來却畫山中景，水墨想像追當年。", "玉堂故人相與厚，意使嫫母齊聯娟。", "豈知憂患耗心力，讀書懶去但欲眠。", "屠龍學就本無用，只堪投老依金仙。", "更得新詩寫珠玉，勸我不作區中緣。", "佩服忠言匪論報，短章重次木瓜篇。"]'),
('cb327541-dde3-487d-bdc2-72a5b42e1bd6','句','王詵','宋','宋诗','song-poetry','','[]','佳人已屬沙吒利，義士今無古押衙。',16,'全唐诗/poet.song.49000.json','["佳人已屬沙吒利，義士今無古押衙。"]'),
('9a264c0a-e611-452e-9587-03caa2546cc7','上王晉卿','王詵門客','宋','宋诗','song-poetry','','[]','幾年流落向天涯，萬里歸來兩鬢華。',64,'全唐诗/poet.song.49000.json','["幾年流落向天涯，萬里歸來兩鬢華。", "翠袖香殘空浥淚，青樓雲渺定誰家。", "佳人已屬沙吒利，義士今無古押衙。", "回首音塵相沉絕，春鶯休囀沁園花。"]'),
('6fd5db7e-f334-405f-9999-8521087ec6f9','賦新繁周表權如詔亭','李琮','宋','宋诗','song-poetry','','[]','家愛兒孫國愛臣，無邪慈教本來均。',64,'全唐诗/poet.song.49000.json','["家愛兒孫國愛臣，無邪慈教本來均。", "非因積善能傳慶，安見天心語合人。", "席擁詩書纔是樂，門多車馬別成春。", "榜亭豈獨榮樽俎，意欲推餘勸里民。"]'),
('cc4994f9-d9d0-432b-9991-ea4266afebb7','和馮允南見寄','李琮','宋','宋诗','song-poetry','','[]','半生才命苦嗟殊，肯更詩窮效聖俞。',64,'全唐诗/poet.song.49000.json','["半生才命苦嗟殊，肯更詩窮效聖俞。", "清識豈期回顧盼，嘉篇聊用借虛無。", "鄉心歲月疑如夢，官況塵埃直未奴。", "聞道南充風物好，未能歸去且狂圖。"]'),
('1cc689dd-3fe1-48d5-8aae-f8ac15943d12','感泉山','李琮','宋','宋诗','song-poetry','','[]','纔到林巒契賞心，蕭然便欲缷朝簪。',64,'全唐诗/poet.song.49000.json','["纔到林巒契賞心，蕭然便欲缷朝簪。", "兩三里路穿田水，四五人家倚樹陰。", "漁叟投竿驚鷺宿，牧童停留學禽音。", "青絲洞裏泉聲響，流出空山換古今。"]'),
('3ae92eee-7f0d-4143-b69e-f364caf344d9','句','李琮','宋','宋诗','song-poetry','','[]','腥味魚中墨，衣成木上綿。',12,'全唐诗/poet.song.49000.json','["腥味魚中墨，衣成木上綿。"]'),
('eba27b87-c8ac-455d-9ad6-09d474beb774','遊盤溪園亭二首  其一','白麟','宋','宋诗','song-poetry','','[]','割忙載酒把寒來，指點盤溪花未開。',32,'全唐诗/poet.song.49000.json','["割忙載酒把寒來，指點盤溪花未開。", "撼動東風須好句，掃除積雪放春回。"]'),
('faaaab4d-ca64-4a4b-9c15-4b4dbad2f3bb','遊盤溪園亭二首  其二','白麟','宋','宋诗','song-poetry','','[]','愛梅愛竹愛溪山，可惜天公未放閒。',32,'全唐诗/poet.song.49000.json','["愛梅愛竹愛溪山，可惜天公未放閒。", "待學盤溪溪上老，松門雖設日常關。"]'),
('005f2fd5-1c86-4a14-821f-eae1c7b63c40','盤溪之遊前一日知幾太博行矣同令君梅下清飲不無悵然吾人會合之難再賦絕句  其一','白麟','宋','宋诗','song-poetry','','[]','君去我來吟賞地，盤溪環繞翠微中。',32,'全唐诗/poet.song.49000.json','["君去我來吟賞地，盤溪環繞翠微中。", "溪人似祕驚人語，不許從容一醉同。"]'),
('4c2a5226-8a06-4d54-b536-6d1ccfaa9193','盤溪之遊前一日知幾太博行矣同令君梅下清飲不無悵然吾人會合之難再賦絕句  其二','白麟','宋','宋诗','song-poetry','','[]','騎鯨人去醉吟來，公子風流尊爲開。',32,'全唐诗/poet.song.49000.json','["騎鯨人去醉吟來，公子風流尊爲開。", "笑問竹間梅淡泊，何如筵上舞低回。"]'),
('3ba84bf2-ce01-4d2e-9f6e-1f9cdacd095c','合江探梅','白麟','宋','宋诗','song-poetry','','[]','艇子飄搖喚不回，半溪清影漾疏梅。',32,'全唐诗/poet.song.49000.json','["艇子飄搖喚不回，半溪清影漾疏梅。", "有人隔岸頻招手，和月和霜剪取來。"]'),
('620131b8-c3e5-4e6e-90a4-eb7855f43e0f','峨眉','白麟','宋','宋诗','song-poetry','','[]','四海佛宮闕，三峨不待誇。',24,'全唐诗/poet.song.49000.json','["四海佛宮闕，三峨不待誇。", "山深龍聽法，野迥鹿銜警。"]'),
('6f1a600a-085b-44f3-bc9c-6cf4a915a098','寓居敘南','白麟','宋','宋诗','song-poetry','','[]','僰道古戎州，何人開天荒。',48,'全唐诗/poet.song.49000.json','["僰道古戎州，何人開天荒。", "向者名勝流，經茲水雲鄉。", "少陵三百年，繼踵山谷黄。", "二老經行處，草木生輝光。"]'),
('b772989d-f2dc-4b61-b986-66db445a91a6','詩一首','白麟','宋','宋诗','song-poetry','','[]','誰破天荒開僰道，千載巖木護天宮。',32,'全唐诗/poet.song.49000.json','["誰破天荒開僰道，千載巖木護天宮。", "背城山合疑無路，面水窗橫自有風。"]'),
('5f05be82-a34b-4d0d-ab3c-44e7d0af986c','句','雷周輔','宋','宋诗','song-poetry','','[]','路險客須到，山高人盡耕。',12,'全唐诗/poet.song.49000.json','["路險客須到，山高人盡耕。"]'),
('53a036d1-5bd3-4c06-aa9f-363d96ffae20','和康提刑過端州','陳懌','宋','宋诗','song-poetry','','[]','舊歷江山眼重開，平成搖轡賞嵩臺。',32,'全唐诗/poet.song.49000.json','["舊歷江山眼重開，平成搖轡賞嵩臺。", "晉康假道昔爲守，按部今持使節來。"]'),
('9356a6e0-da5e-468f-a11d-fb91c6021b01','和康提刑過康州','陳懌','宋','宋诗','song-poetry','','[]','民居城柵盡非元，唯有江山似昔年。',64,'全唐诗/poet.song.49000.json','["民居城柵盡非元，唯有江山似昔年。", "聽訟棠陰遺舊址，按行臺旆照晴川。", "重來自喜恩威洽，別後常嗟歲月遷。", "道側老人曾臥轍，拜迎相顧倍怡然。"]'),
('a00cb028-1147-40ab-9932-16ecbfc479f6','玉華山','張峋','宋','宋诗','song-poetry','','[]','玉華山誰窮遠近，百里迴旋勢方盡。',192,'全唐诗/poet.song.49000.json','["玉華山誰窮遠近，百里迴旋勢方盡。", "削成蒼玉倚青天，氣象軒軒獨奇俊。", "黄河哮顑摧崑崙，一峰飄落如龍蹲。", "白雲低垂半巖腹，茫茫日輪平地奔。", "驚湍瀑流飛辟歷，松根巉巖裂石壁。", "洞門晝閉不知深，仙人瓊漿滿杯碧。", "饑鼯啼煙猿嘯風，子規聲哀愁滿容。", "山鳥嚶嚀繞喬木，唯有黄鶴鳴噰噰。", "翠華迢迢來避暑，飄然陵雲欲輕舉。", "當時此地最清涼，九成翠微不足數。", "玉鞘聲斷宮殿閑，大龍飛去髯難攀。", "川巒如舊人事變，但見明月留空山。"]'),
('e3443069-4b14-42cc-a03a-c866d52426e7','觀洛城花呈堯夫先生','張㟭','宋','宋诗','song-poetry','','[]','平生自是愛花人，到處尋芳不遇真。',32,'全唐诗/poet.song.49000.json','["平生自是愛花人，到處尋芳不遇真。", "祇道人間無正色，今朝初見洛陽春。"]'),
('c62f6f1c-10ee-4cac-9821-02bfa59243be','句','謝卿材','宋','宋诗','song-poetry','','[]','東傾壺柄雙流水，西闞甌唇四別峰。',16,'全唐诗/poet.song.49000.json','["東傾壺柄雙流水，西闞甌唇四別峰。"]'),
('8372ca0f-f906-47f8-aa8d-d84f50a998f9','將還河北留別堯夫先生','邢恕','宋','宋诗','song-poetry','','[]','先生抱道隱牆東，心迹兼忘出處通。',64,'全唐诗/poet.song.49000.json','["先生抱道隱牆東，心迹兼忘出處通。", "圮下每慚知孺子，床前曾憶拜龐公。", "已將目擊存微妙，直把神交寄始終。", "此日離違限南北，蕭蕭班馬正依風。"]'),
('6afc7415-c4b0-450f-a71f-e6c63a05eef9','送程給事知越州','邢恕','宋','宋诗','song-poetry','','[]','稽山鑑水正宜秋，笑領銅符下鷁舟。',64,'全唐诗/poet.song.49000.json','["稽山鑑水正宜秋，笑領銅符下鷁舟。", "青瑣夕郎傳故事，鴻都仙客足風流。", "錦衣著去經鄉國，繭紙翻成賦郡樓。", "祇恐漢廷須雅望，寇公難得隔年留。"]'),
('766d984e-6bd3-4eb3-8ccb-390b12a49cd2','隨州','邢恕','宋','宋诗','song-poetry','','[]','荆楚西南地，清明咫尺天。',24,'全唐诗/poet.song.49000.json','["荆楚西南地，清明咫尺天。", "遠山猶带雪，高柳已藏煙。"]'),
('2bb6b5a6-4c1c-42b6-9b68-a4542395ad72','酬魏少府侍直史館','邢恕','宋','宋诗','song-poetry','','[]','麗藻高鄭衛，專學美齊傳。',24,'全唐诗/poet.song.49000.json','["麗藻高鄭衛，專學美齊傳。", "容揄難有屬，筆削少能干。"]'),
('439b83d5-58ae-4112-854d-734c792216d5','華嚴巖','邢恕','宋','宋诗','song-poetry','','[]','一簇僧房路屈盤，不踰城郭到林巒。',32,'全唐诗/poet.song.49000.json','["一簇僧房路屈盤，不踰城郭到林巒。", "何人爲假丹青手，寫入輕綃掛壁看。"]'),
('ca8e5063-5a71-47ad-ae40-f633541e75eb','題愚溪','邢恕','宋','宋诗','song-poetry','','[]','溪流貫清江，湍瀨亘百里。',193,'全唐诗/poet.song.49000.json','["溪流貫清江，湍瀨亘百里。", "龍蛇幾盤紆，雷雨忽奔駛。", "石橫渠狀穿鑿，怪力祖誰氏。", "突如見頭角，虎豹或蹲峙。", "橫杠互枝柱，小艇俄紛委。", "蘋藻翳泓澄，松竹蔭崖涘。", "兩山束鳥道，側岸數魚尾。", "繚然閟深幽，梵字疊危址。", "鍾唄雜灘聲，亭臺森水底。", "凭欄幾游目，杖策時臨履。", "酒杓間茶鐺，棋枰延晝晷。", "放懷得天倪，清嘯謝塵滓。", "忽忘兒女縛，似接嬴秦子。", "顧予拙謀身，霜鬢颯垂耳。", "雅意在延齡，丹砂夙充餌。", "焉得茲結廬，帳念遠桑梓。"]'),
('53da0cba-b109-4a9c-87ff-794629c7cec7','獨遊偶題','邢恕','宋','宋诗','song-poetry','','[]','頹然一睡足，巖溜尚潺湲。',24,'全唐诗/poet.song.49000.json','["頹然一睡足，巖溜尚潺湲。", "面几郎山郭，寂無人世喧。"]'),
('1dcb631d-5464-4714-a4ef-cd8c008b61d0','遊浯溪','邢恕','宋','宋诗','song-poetry','','[]','歸舟一夜泊浯溪，曉雨絲絲不作泥。',32,'全唐诗/poet.song.49000.json','["歸舟一夜泊浯溪，曉雨絲絲不作泥。", "□石蒼崖訪遺刻，更磨苔蘚爲留題。"]'),
('81b85f4d-d941-444d-be08-59c9d16e776f','朝陽巖絕句  其一','邢恕','宋','宋诗','song-poetry','','[]','濯足臨澄碧，和雲臥石室。',24,'全唐诗/poet.song.49000.json','["濯足臨澄碧，和雲臥石室。", "淅瀝天風生，披襟當呼吸。"]'),
('533c5c4b-455c-47d6-8f00-6056f815f392','朝陽巖絕句  其二','邢恕','宋','宋诗','song-poetry','','[]','巖巔風雨落泉聲，巖下江流見底清。',32,'全唐诗/poet.song.49000.json','["巖巔風雨落泉聲，巖下江流見底清。", "夾岸松筠倒流影，炊煙漁父近寒城。"]'),
('479d0293-b84d-4770-b513-5355a52fa05f','句  其一','邢恕','宋','宋诗','song-poetry','','[]','雲容山色爭奇□，遠水遙天共落暉。',16,'全唐诗/poet.song.49000.json','["雲容山色爭奇□，遠水遙天共落暉。"]'),
('d43aa3ef-050e-4fa8-977d-e6cfe841922f','句  其二','邢恕','宋','宋诗','song-poetry','','[]','城隅樓榭與雲平，城下溪流見底清。',16,'全唐诗/poet.song.49000.json','["城隅樓榭與雲平，城下溪流見底清。"]'),
('632675c5-384c-46a4-878b-1587bd15d831','句  其三','邢恕','宋','宋诗','song-poetry','','[]','溳水带西城，城高敞郡亭。',12,'全唐诗/poet.song.49000.json','["溳水带西城，城高敞郡亭。"]'),
('46c3e0e7-99b6-4f85-87c4-2aec39bc2ba0','句  其四','邢恕','宋','宋诗','song-poetry','','[]','隨爲楚西南，郡頗富山水。',12,'全唐诗/poet.song.49000.json','["隨爲楚西南，郡頗富山水。"]'),
('ecaec8be-0dc8-4446-9700-8cbf297051d9','別石堅','釋大眼','宋','宋诗','song-poetry','','[]','心如一片苗，是苗皆可植。',24,'全唐诗/poet.song.49000.json','["心如一片苗，是苗皆可植。", "莫種誰堆培，莫容荆與棘。"]'),
('9c9c3120-fa6b-4915-a7ba-56a525c9d402','留京師思歸','王仲甫','宋','宋诗','song-poetry','','[]','黄金零落大刀頭，玉筯歸期劃到秋。',64,'全唐诗/poet.song.49000.json','["黄金零落大刀頭，玉筯歸期劃到秋。", "紅錦寄魚風逆浪，碧簫吹鳳月當樓。", "伯勞知我經春別，香蠟窺人一夜愁。", "好去渡江千里夢，滿天梅雨是蘇州。"]'),
('a0a0613a-431e-473b-ab43-c1a81a83ab16','登天清閣','趙士掞','宋','宋诗','song-poetry','','[]','夕陽低盡已西紅，百尺樓高萬里風。',32,'全唐诗/poet.song.49000.json','["夕陽低盡已西紅，百尺樓高萬里風。", "白髮年年何處得，只應多在倚欄中。"]'),
('a554ab60-3ead-48a1-9b05-7652ab1a7d77','遊虎丘','趙士宇','宋','宋诗','song-poetry','','[]','脫身到泉石，釣具一篷舟。',48,'全唐诗/poet.song.49000.json','["脫身到泉石，釣具一篷舟。", "澗險松筠合，山深宮殿秋。", "角巾可投檄，尊酒且澆愁。", "甚愧阮宣子，青鈱掛杖頭。"]'),
('ab6b408f-8cca-430b-829b-69d3ca1b295c','送程給事知越州','畢仲衍','宋','宋诗','song-poetry','','[]','朝回鳴櫓下東流，人自承明向越州。',64,'全唐诗/poet.song.49000.json','["朝回鳴櫓下東流，人自承明向越州。", "印綬光華將過里，江山蕭灑去迎秋。", "香銷瑣闥成新夢，雲映蓬萊識舊遊。", "須體聖心圖任切，鑑湖雖好莫淹留。"]'),
('66f5103d-c7b8-4e84-bf17-e1c347f88f18','鹿鳴宴贈歌妓','翁邁','宋','宋诗','song-poetry','','[]','年方十三四，嬌羞懶舉頭。',48,'全唐诗/poet.song.49000.json','["年方十三四，嬌羞懶舉頭。", "舞餘駒皎皎，歌罷鹿呦呦。", "近座香先噴，持杯玉更柔。", "高唐人去遠，誰與話風流。"]'),
('957ce62b-c44f-445d-85d0-ee2da887836a','矢惠洪問住山  其一','釋懷志','宋','宋诗','song-poetry','','[]','萬機俱罷付癡憨，蹤迹常容野鹿參。',32,'全唐诗/poet.song.49000.json','["萬機俱罷付癡憨，蹤迹常容野鹿參。", "不脫麻衣拳作枕，幾生夢在綠蘿庵。"]'),
('8d271ffd-3019-4143-b19e-9a5bd4e31c8f','矢惠洪問住山  其二','釋懷志','宋','宋诗','song-poetry','','[]','山中住，獨掩柴門無別趣，三個柴頭品字煨，不用援毫文彩露。',28,'全唐诗/poet.song.49000.json','["山中住，獨掩柴門無別趣，三個柴頭品字煨，不用援毫文彩露。"]'),
('a6ebda59-f4dc-46c0-80dc-d279493e2b3f','偶書','印首座','宋','宋诗','song-poetry','','[]','折脚鐺見謾自煨，飯餘長是坐堆堆。',32,'全唐诗/poet.song.49000.json','["折脚鐺見謾自煨，飯餘長是坐堆堆。", "一從近日生涯拙，百鳥銜華去不來。"]'),
('f7692601-a76d-4b74-b418-e3c01fb76aa0','偈一首','印首座','宋','宋诗','song-poetry','','[]','不掛寸絲方免寒，何須特地裊長竿。',32,'全唐诗/poet.song.49000.json','["不掛寸絲方免寒，何須特地裊長竿。", "而今落落零零也，七佛之名甚處安。"]'),
('8e9cb103-b091-4bdd-8a1d-90ff3cd30df3','偈','印首座','宋','宋诗','song-poetry','','[]','丘師伯莫曉，寂寂明皎皎。',24,'全唐诗/poet.song.49000.json','["丘師伯莫曉，寂寂明皎皎。", "日午打三更，誰人打得了。"]'),
('abe655c0-a856-4c5d-9632-1d809661bb33','送羅正之年兄出使二浙','趙挺之','宋','宋诗','song-poetry','','[]','相逢三十春，歡宴殊未足。',204,'全唐诗/poet.song.49000.json','["相逢三十春，歡宴殊未足。", "都門今見君，行意一何速。", "正之南國秀，德業素所畜。", "才名振京師，賢達競推轂。", "當年諸邑政，惠愛春蘭馥。", "惟思結恩信，幾欲弛鞭扑。", "一朝使王畿，茂草鞠圜獄。", "高懷富經綸，餘事歸簡牘。", "風騷入冥搜，落筆動盈幅。", "忠誠人所懷，正直神介福。", "輕舟揚高旌，錦袂耀鄉服。", "西風浙江遠，秋色方在目。", "歡聲溢閭巷，喜氣霑僮僕。", "東南歲仍饑，仁主意方屬。", "君才固有餘，足以振疲俗。", "行聞變潢潦，千里盡平陸。", "功成辦歸裝，來赴嚴君促。"]'),
('ebd93f6c-df2c-4d41-9e86-0bb39e8d05c2','朱氏天和堂','趙挺之','宋','宋诗','song-poetry','','[]','華亭山水佳，秀色宛如畫。',120,'全唐诗/poet.song.49000.json','["華亭山水佳，秀色宛如畫。", "前賢有隱蹟，卜築俟來者。", "高人養天和，放浪寄林野。", "安知歲月徂，但喜名利捨。", "傳家得之子，流輩推博雅。", "春風振客衣，逸棹東南下。", "賦詩臺閣彥，落落珠璣瀉。", "持觴拜親膝，喜色動鄉社。", "都城十二衢，塵土翳車馬。", "一夢逐君行，茲懷已瀟灑。"]'),
('d2507485-7ed1-4a1f-8d0e-db6f035d9221','楊十七應之兄學士挽辭','趙挺之','宋','宋诗','song-poetry','','[]','廓落襟懷德藝優，身名曾不問沈浮。',66,'全唐诗/poet.song.49000.json','["廓落襟懷德藝優，身名曾不問沈浮。", "當年冊府曾同命，早歲文場每並遊。", "寂寂舊廬東南東觀曉，翩翩歸旐北邙秋。", "都城猶記樽前別，精爽今隨逝水流。"]'),
('1767405a-8d41-4203-8fa3-e3c170571eed','過黯淡灘','初惟深','宋','宋诗','song-poetry','','[]','溪流怪石礙通津，一一操舟若有神。',32,'全唐诗/poet.song.49000.json','["溪流怪石礙通津，一一操舟若有神。", "自是世間無妙手，古來何事不由人。"]'),
('c4938291-3cfa-4768-9b61-982fabd53e13','呈荆公','初惟深','宋','宋诗','song-poetry','','[]','年來身計欲何爲，跌宕無成一軸詩。',64,'全唐诗/poet.song.49000.json','["年來身計欲何爲，跌宕無成一軸詩。", "懶把行藏問詹尹，願將生死遇秦醫。", "丹青效虎留心拙，斤匠良工入手遲。", "此日知音堪屬意，枯桐正在半焦時。"]'),
('4f078fd6-3c07-4266-8bc6-a4861ba2730c','遊園不遇主人題壁','初惟深','宋','宋诗','song-poetry','','[]','何年突兀庭前石，昔日何人種松柏。',64,'全唐诗/poet.song.49000.json','["何年突兀庭前石，昔日何人種松柏。", "乘興閒來就榻眠，一枕春風君莫惜。", "城西今古陽山色，城中誰有千年宅。", "往來何必見主人，主人自是亭中客。"]'),
('a6fff32a-5597-4ddd-a8b1-6a0a7c30fc4d','絕句','初惟深','宋','宋诗','song-poetry','','[]','多年不見玉川翁，今日相逢小榭東。',32,'全唐诗/poet.song.49000.json','["多年不見玉川翁，今日相逢小榭東。", "依舊清涼無長物，只餘松檜養秋風。"]'),
('96043992-d437-46d4-af3d-617bfd7a7e3c','謁荆公不遇','初惟深','宋','宋诗','song-poetry','','[]','春江渺渺抱牆流，煙草茸茸一片愁。',32,'全唐诗/poet.song.49000.json','["春江渺渺抱牆流，煙草茸茸一片愁。", "吹盡柳花人不見，春旗催日下城頭。"]'),
('632fcb74-1877-4db5-bb1a-9c56a05ae68e','挽張幾道','初惟深','宋','宋诗','song-poetry','','[]','吳郡聲名顧與張，龍門當日共升堂。',64,'全唐诗/poet.song.49000.json','["吳郡聲名顧與張，龍門當日共升堂。", "青衫始見登華省，丹旐俄聞入故鄉。", "含淚孤兒生面垢，斷腸慈母滿頭霜。", "嗟君十載人間事，不及南柯一夢長。"]'),
('635fce3e-dc18-4833-a964-fa3c3dd64124','和吳門章太守五日宴九老于廣華詩','初惟深','宋','宋诗','song-poetry','','[]','使君蕭灑上賓閑，金地無人晝敞關。',64,'全唐诗/poet.song.49000.json','["使君蕭灑上賓閑，金地無人晝敞關。", "風靜簫聲來世外，日長仙境在人間。", "詩成郢客爭揮翰，曲罷吳姬一破顔。", "此節東南無此會，高名千古映湖山。"]'),
('87ab118e-c152-4030-a37f-6d7ff1e2e22c','紅梅','初惟深','宋','宋诗','song-poetry','','[]','清香皓質世稱奇，謾作輕紅也自宜。',64,'全唐诗/poet.song.49000.json','["清香皓質世稱奇，謾作輕紅也自宜。", "紫府與丹來換骨，春風吹酒上凝脂。", "直教臘雪無藏處，只恐朝雲有散時。", "溪上野桃何足種，秦人應獨未相知。"]'),
('fea57028-615a-4189-af0d-4161e322796d','古柏','初惟深','宋','宋诗','song-poetry','','[]','四邊喬木盡兒孫，曾見吳宮幾度春。',32,'全唐诗/poet.song.49000.json','["四邊喬木盡兒孫，曾見吳宮幾度春。", "若使當時成大廈，也應隨例作埃塵。"]'),
('9a322b9a-ef93-4ca8-9276-ac4931c84026','虎丘','初惟深','宋','宋诗','song-poetry','','[]','晉人事高曠，所得多奇僻。',60,'全唐诗/poet.song.49000.json','["晉人事高曠，所得多奇僻。", "雲巖佛子廬，曾爲二王宅。", "當時槃樂地，俯仰成今昔。", "林泉亦余好，徘徊想遺迹。", "那知非昔人，復作登臨客。"]'),
('2d1a9464-ee3a-415c-9edc-8752b28d27e8','劍池','初惟深','宋','宋诗','song-poetry','','[]','雲崖倚天開，蒼淵下澄澈。',60,'全唐诗/poet.song.49000.json','["雲崖倚天開，蒼淵下澄澈。", "世傳靈劍飛，山石千丈裂。", "神蹤去不返，今作蛟龍穴。", "是非漭難誥，歲久多異說。", "惟當清夜來，靜賞潭上月。"]'),
('ad6a17f2-5051-4c9d-a2af-c57f10a7ae3f','千人石','初惟深','宋','宋诗','song-poetry','','[]','生公天人師，講法花雨墮。',60,'全唐诗/poet.song.49000.json','["生公天人師，講法花雨墮。", "當時聽法衆，片石千人坐。", "山祇常護持，山鳥不敢污。", "野人心茫然，傲蕩多酒過。", "醉來不肯歸，石上看雲臥。"]'),
('c7c56683-74f4-4317-952c-3b54fc4ead6d','程公闢留客開元飲  其一','初惟深','宋','宋诗','song-poetry','','[]','晝錦新坊路稍西，興來攜客就僧扉。',64,'全唐诗/poet.song.49000.json','["晝錦新坊路稍西，興來攜客就僧扉。", "樽前倒玉清無比，筆下鏗金妙欲飛。", "籃輿直須乘月去，榜歌時聽採菱歸。", "流傳白雪吳城滿，頓覺炎歊一夕微。"]'),
('7ff195a6-e02a-4590-b24c-2f4b5b4060cc','程公闢留客開元飲  其二','初惟深','宋','宋诗','song-poetry','','[]','仙老論文小往還，多才令尹獨能攀。',64,'全唐诗/poet.song.49000.json','["仙老論文小往還，多才令尹獨能攀。", "攜觴步入千做界，借榻清臨一水間。", "笑語不驚沙鳥去，襟懷猶過野僧閑。", "城中此地無人愛，坐對西南見好山。"]'),
('2e33d656-5d1f-49de-b38c-7ba230e8f186','牡丹','初惟深','宋','宋诗','song-poetry','','[]','嫚黄妖紫間輕紅，谷雨初晴早景中。',64,'全唐诗/poet.song.49000.json','["嫚黄妖紫間輕紅，谷雨初晴早景中。", "靜女不言還愛日，彩雲無定只愁風。", "爐煙坐覺沈檀薄，妝面回看粉黛空。", "此別又須經歲月，酒闌攜燭繞芳叢。"]'),
('45f60382-076e-498d-8d00-1d20d0e565f8','雪','初惟深','宋','宋诗','song-poetry','','[]','剪水飛花着地干，世間顔色比應難。',32,'全唐诗/poet.song.49000.json','["剪水飛花着地干，世間顔色比應難。", "謝家兒女空才思，只作因風柳絮看。"]'),
('0e20d724-74e7-48d0-acfb-433e4833c5bc','漁父','初惟深','宋','宋诗','song-poetry','','[]','一葉生涯逐浪流，悠悠生事共萍浮。',64,'全唐诗/poet.song.49000.json','["一葉生涯逐浪流，悠悠生事共萍浮。", "蓑披殘雪湘江晚，鈎拂紅塵渭水秋。", "買酒解衣楊柳岸，得魚吹火荻蘆洲。", "興闌卻返扁舟去，半掩柴門古渡頭。"]'),
('535781ab-fb80-4cc4-882c-84c91d4f22d6','贈黄君俞','初惟深','宋','宋诗','song-poetry','','[]','紫書夕降御床邊，門下褒衣繞數千。',64,'全唐诗/poet.song.49000.json','["紫書夕降御床邊，門下褒衣繞數千。", "捧檄喜隨親色動，授經榮勝主恩偏。", "相如好賦真童子，賈誼多才患少年。", "道在不須憂絳灌，一時卿相盡知賢。"]'),
('ceb695b9-ecb6-4ca5-83d2-b6fac1b372f8','舟下建溪','初惟深','宋','宋诗','song-poetry','','[]','客航收浦月昏黄，野店無燈欲閉門。',32,'全唐诗/poet.song.49000.json','["客航收浦月昏黄，野店無燈欲閉門。", "半出岸汀楓半死，繫舟猶有去年痕。"]'),
('1a13f50b-e18d-4625-91fc-53373bff400a','過無爲吳氏園池','初惟深','宋','宋诗','song-poetry','','[]','傍水尋幽徑，青林晝掩扉。',48,'全唐诗/poet.song.49000.json','["傍水尋幽徑，青林晝掩扉。", "楊花入竹靜，鳥影度塘稀。", "石好頻移坐，波清任濯衣。", "沙鷗如有意，一一近人飛。"]'),
('829ea01a-c63a-4ade-b8b1-2f441b29dafd','都下寄友人葉褧之','初惟深','宋','宋诗','song-poetry','','[]','朝車皆有從，暮轍各有投。',72,'全唐诗/poet.song.49000.json','["朝車皆有從，暮轍各有投。", "茫茫聲利區，賤客難獨留。", "豈無平生交，音容杳南州。", "幽懷欲有訴，寤寐不可求。", "追我夙昔歡，負子今日遊。", "勉矣尚有適，所困非所羞。"]'),
('155be4b1-218d-493c-bc25-e910c7231c87','依韻答楊起公見寄','初惟深','宋','宋诗','song-poetry','','[]','釋卷趨南畝，霜風報穫時。',48,'全唐诗/poet.song.49000.json','["釋卷趨南畝，霜風報穫時。", "不才謀事拙，寸祿及親遲。", "通塞終難問，短長今自知。", "何年得乘興，閑趁逸人期。"]'),
('58b3f971-e864-47bd-830b-f7e0faeb3c08','答公權晚春','初惟深','宋','宋诗','song-poetry','','[]','林圃芳菲盡，空陰繞院青。',48,'全唐诗/poet.song.49000.json','["林圃芳菲盡，空陰繞院青。", "風條初脫絮，露沼欲生萍。", "地僻春猶冷，門閑晝亦扃。", "臨杯學強醉，懷抱只常醒。"]'),
('3b26d6be-2171-4aa7-a35d-a4bc626ad9e1','題九華閣','初惟深','宋','宋诗','song-poetry','','[]','斗起喧卑地，塵埃不入顔。',49,'全唐诗/poet.song.49000.json','["斗起喧卑地，塵埃不入顔。", "微尋清晝夢，靜看別州山。", "隱几孤鴻沒，調琴遠鶴完還。", "何時了吾事，來此伴君閑。"]'),
('d851398b-bbb3-42c3-86a4-bec9169530ab','題公權壁','初惟深','宋','宋诗','song-poetry','','[]','繞舍清陰白晝寒，野情晴喜到門闌。',64,'全唐诗/poet.song.49000.json','["繞舍清陰白晝寒，野情晴喜到門闌。", "陶潛歲計惟栽菊，楚客家風只種蘭。", "雨過落花粘履舄，日長輕絮點杯盤。", "明年官滿君須去，此地應難得此歡。"]'),
('84f2a2ee-4403-451d-90cc-054950f73713','書通德官舍壁','初惟深','宋','宋诗','song-poetry','','[]','楚水分牆北，閩溪出舍東。',48,'全唐诗/poet.song.49000.json','["楚水分牆北，閩溪出舍東。", "冷雲秋欲雪，高木晝常風。", "冠蓋人聲絕，音書鳥道通。", "如何阮家子，平地哭塗窮。"]'),
('587b41f0-4be2-486f-bbde-af5583503842','明教院','初惟深','宋','宋诗','song-poetry','','[]','寶剎臨蒼峽，門迎萬里船。',48,'全唐诗/poet.song.49000.json','["寶剎臨蒼峽，門迎萬里船。", "湍聲沉鳥語，岸沫擁蛟涎。", "朝供收崖栗，宵瓶煮石泉。", "平生林壑趣，向此合留連。"]'),
('e110b2fc-c21c-4c1d-a72b-9ae231d65ee9','送程給事知越州','周直孺','宋','宋诗','song-poetry','','[]','三吳冠蓋並驅馳，名德如公亦已稀。',64,'全唐诗/poet.song.49000.json','["三吳冠蓋並驅馳，名德如公亦已稀。", "胥口沈珠唐相事，會稽懷綬漢臣歸。", "光華晝繡家山近，浩蕩秋風畫鷁飛。", "十萬疲民待仁政，未應祗爲膾鱸肥。"]'),
('e18f16f9-9de7-495e-9655-61dac4a08f64','送程給事知越州  其一','李深','宋','宋诗','song-poetry','','[]','從橫才業聳青冥，出處三朝重老成。',64,'全唐诗/poet.song.49000.json','["從橫才業聳青冥，出處三朝重老成。", "南就金城幾萬里，東歸戎節擁千兵。", "書從禹穴探應古，詩想雞林購得名。", "莫醉故園風月久，壺漿父老已來迎。"]'),
('e48b1652-90da-4d8d-8bb8-edaa693230f9','送程給事知越州  其二','李深','宋','宋诗','song-poetry','','[]','白首雍容侍從中，高懷常寄五湖東。',64,'全唐诗/poet.song.49000.json','["白首雍容侍從中，高懷常寄五湖東。", "游文仙殿才終別，作牧稽山地更雄。", "去國旌旗迎曉日，過家鱸橘正秋風。", "異時治行如登用，故事西京有弱翁。"]'),
('e395f6b6-1072-4c54-9e37-5f8bc1007770','題范文正公祠堂  其一','李深','宋','宋诗','song-poetry','','[]','一章奏免鳥銜茶，惠及饒民幾萬家。',32,'全唐诗/poet.song.49000.json','["一章奏免鳥銜茶，惠及饒民幾萬家。", "遺老至今懷德政，爲余談此屢咨嗟。"]'),
('a556e51a-efeb-4371-a7b5-77e3b94e6f84','題范文正公祠堂  其二','李深','宋','宋诗','song-poetry','','[]','危言遷謫向江湖，放意雲山道豈孤。',32,'全唐诗/poet.song.49000.json','["危言遷謫向江湖，放意雲山道豈孤。", "忠信平生心自許，吉凶何卹賦靈烏。"]'),
('ffefd133-de7a-4eaf-9c84-7cb4c115cc5b','和張祜韻','傅宏','宋','宋诗','song-poetry','','[]','遠望陽城湖，八九雲夢吞。',48,'全唐诗/poet.song.49000.json','["遠望陽城湖，八九雲夢吞。", "白雲宿殿罅，青蘚埋松根。", "樵唱林間路，漁歌寺外村。", "避喧嗜飛閣，未若叩禪門。"]'),
('c704584a-1e4f-4e89-a43b-33fa5faf3adb','和孟郊韻','傅宏','宋','宋诗','song-poetry','','[]','修頂磨穹蒼，雲煙雜古床。',48,'全唐诗/poet.song.49000.json','["修頂磨穹蒼，雲煙雜古床。", "僧飯鐘聲遠，仙風桂子香。", "老檜有寒操，怪石多冷光。", "俯瞰城郭人，衮衮名利場。"]'),
('edb33774-06a2-4295-bbf2-b06737bbabb0','釣臺','賈青','宋','宋诗','song-poetry','','[]','萬疊層峰夾兩溪，雨餘清氣卻炎暉。',32,'全唐诗/poet.song.49000.json','["萬疊層峰夾兩溪，雨餘清氣卻炎暉。", "何時學得嚴陵傲，洗盡塵襟臥釣磯。"]'),
('d0c4d1bd-65fc-46df-9885-1693f046d052','黯淡院','賈青','宋','宋诗','song-poetry','','[]','溪聲灘外急，草色兩中深。',24,'全唐诗/poet.song.49000.json','["溪聲灘外急，草色兩中深。", "客意自南北，山光無古今。"]'),
('a921c38d-894e-4c39-90c1-7a904fc6f08e','送越帥程公闢','曾孝宗','宋','宋诗','song-poetry','','[]','虎符分盾浙江東，艤棹都門使旆雄。',64,'全唐诗/poet.song.49000.json','["虎符分盾浙江東，艤棹都門使旆雄。", "雙漿徘徊枌社日，高牙搖曳剡溪風。", "蓬萊閣宴公書簡，賀監湖浮獄榜空。", "行聽越民歌德政，亟還青瑣見旌忠。"]'),
('8dc92e61-333f-4fb4-ab29-f7083b6c8bf4','題清芬閣','劉琯','宋','宋诗','song-poetry','','[]','自從筆削三千首，復見風騷二百年。',64,'全唐诗/poet.song.49000.json','["自從筆削三千首，復見風騷二百年。", "佳句獨爲時輩許，幽光長伴客星懸。", "耳孫文采方高蹈，鼻祖聲名更盛傳。", "曾到先生棲隱處，桐君山下好林泉。"]'),
('116fbd71-f28f-409f-a9c1-452f530346c2','題清芬閣','馬偕','宋','宋诗','song-poetry','','[]','煌煌英烈照穹蒼，清節高名錦繡腸。',64,'全唐诗/poet.song.49000.json','["煌煌英烈照穹蒼，清節高名錦繡腸。", "千卷共傳詩燦爛，萬鍾能鄙德馨香。", "清芬自是流餘慶，佳氣終當及後昌。", "逸韻雲孫風味好，鵬摶九萬看翱翔。"]'),
('0f3930ad-3fb9-4641-aad7-3494495f0785','和吳公仲庶遊海雲寺','薛繗','宋','宋诗','song-poetry','','[]','寺占靈峰更近州，喧闐騶從錦纏頭。',64,'全唐诗/poet.song.49000.json','["寺占靈峰更近州，喧闐騶從錦纏頭。", "歌鍾乍奏晴雷殷，戈甲急趨春水流。", "幾處醉眠方枕籍，一城謠俗重嬉遊。", "賢侯惠意民知否，幾刻嚴闉爲爾留。"]'),
('19396b1b-5c78-42fb-bd3f-bf245a658c55','永州','楊永節','宋','宋诗','song-poetry','','[]','柳侯好倔奇，頗類元道州。',24,'全唐诗/poet.song.49000.json','["柳侯好倔奇，頗類元道州。", "遂令舂陵行，至今猶風流。"]'),
('b681b433-d02e-40d0-96a6-68d1ad4cc9e6','請州亭鼓山銘','丁竦','宋','宋诗','song-poetry','','[]','鼓屴崱，峰頂特。',80,'全唐诗/poet.song.49000.json','["鼓屴崱，峰頂特。", "窮島夷，頫封域。", "屏閩東，拱辰北。", "歲辛亥，帝司赤。", "竦紳烈，從陗陟。", "搴若華，揖瑤極。", "呵蜚霆，蹴鼇脊。", "披霄根，殫目力。", "高者仰，深必惕。", "謹其至，惟古則。"]'),
('24904d4a-a6af-415a-b882-b1bf8ba7db76','紫閣','薛昌朝','宋','宋诗','song-poetry','','[]','閣下寒溪漲碧湍，閣前蒼翠數峰環。',64,'全唐诗/poet.song.49000.json','["閣下寒溪漲碧湍，閣前蒼翠數峰環。", "危梯續蹬穿松下，細竹分泉落石前。", "好鳥啁啾爭喚客，亂雲開合巧藏山。", "獨來應爲禪僧笑，少有人能伴我閑。"]'),
('eab0fe70-64dc-4081-bd2b-ed97db466a2b','鱸鄉亭','林肇','宋','宋诗','song-poetry','','[]','膾鱸珍珠是吳鄉，丞相曾過賦短章。',64,'全唐诗/poet.song.49000.json','["膾鱸珍珠是吳鄉，丞相曾過賦短章。", "新作水齋堪寓目，舊停桂棹有餘光。", "滿前野景煙波闊，自後秋風意氣長。", "莫待東曹歸憶此，分慳居在碧州旁。"]'),
('a36d3cf2-1809-4774-982e-2e83f079188c','宮詞  其一','王仲修','宋','宋诗','song-poetry','','[]','四海梯航賀歲元，千官環佩拜中天。',32,'全唐诗/poet.song.49000.json','["四海梯航賀歲元，千官環佩拜中天。", "願從今日稱觴後，舜殿垂衣一萬年。"]'),
('862bab1a-41a0-4c1a-a943-5e1a582fb0da','宮詞  其二','王仲修','宋','宋诗','song-poetry','','[]','前殿風傳萬歲聲，九重歌管樂昇平。',32,'全唐诗/poet.song.49000.json','["前殿風傳萬歲聲，九重歌管樂昇平。", "欲知慶事叢元日，瑞氣先從帝鼐生。"]'),
('58e10546-2d7d-4929-a855-346df3b85202','宮詞  其三','王仲修','宋','宋诗','song-poetry','','[]','元夜笙歌滿上都，九霄皓月舞蟾蜍。',32,'全唐诗/poet.song.49000.json','["元夜笙歌滿上都，九霄皓月舞蟾蜍。", "燭龍穿仗來天際，萬疊黄雲覆帝車。"]'),
('dd185549-3a97-4ad4-a1f3-7976df70c4de','宮詞  其四','王仲修','宋','宋诗','song-poetry','','[]','玉鉞光華引六虬，天街萬燭擁宸遊。',32,'全唐诗/poet.song.49000.json','["玉鉞光華引六虬，天街萬燭擁宸遊。", "端門五夜開黄幄，月在蓬山頂上頭。"]'),
('ee8d28a2-05da-44d3-b142-32ea674c119b','宮詞  其五','王仲修','宋','宋诗','song-poetry','','[]','春風來自斗杓東，萬物欣欣鼓舞中。',32,'全唐诗/poet.song.49000.json','["春風來自斗杓東，萬物欣欣鼓舞中。", "鳳紙催裁寬大詔，拂明宣下未央宮。"]'),
('dfd3473c-e5d6-491f-aaf2-51014e1cc41f','宮詞  其六','王仲修','宋','宋诗','song-poetry','','[]','雪消鴛瓦東風暖，已覺金虬刻漏長。',32,'全唐诗/poet.song.49000.json','["雪消鴛瓦東風暖，已覺金虬刻漏長。", "禁里春寒猶未放，日華先拂赭袍光。"]'),
('c52d8d42-1713-4fba-9d80-c203839f6bae','宮詞  其七','王仲修','宋','宋诗','song-poetry','','[]','冒臘交春日向遲，雪殘鳷鵲已多時。',32,'全唐诗/poet.song.49000.json','["冒臘交春日向遲，雪殘鳷鵲已多時。", "宮桃紅小勻丹臉，御柳黄深展翠眉。"]'),
('928803bf-3440-40cb-8f81-789f100171d3','宮詞  其八','王仲修','宋','宋诗','song-poetry','','[]','萬戶千門入建章，金繩界路柳絲黄。',32,'全唐诗/poet.song.49000.json','["萬戶千門入建章，金繩界路柳絲黄。", "和風偏度樂聲細，晴日自隨宮線長。"]'),
('9ef248f1-c29d-41c9-a196-8c3964db4f31','宮詞  其九','王仲修','宋','宋诗','song-poetry','','[]','殿外輕寒一凭欄，春衫初試覺微寬。',32,'全唐诗/poet.song.49000.json','["殿外輕寒一凭欄，春衫初試覺微寬。", "釵頭故插宜男草，圖得君王带笑看。"]'),
('1bfab49a-5500-4f08-8acc-ffd3dfc7ed86','宮詞  其一○','王仲修','宋','宋诗','song-poetry','','[]','畫棟宵寒燕未來，江南誰寄一枝梅。',32,'全唐诗/poet.song.49000.json','["畫棟宵寒燕未來，江南誰寄一枝梅。", "閏年雪後春工晚，羯鼓催花滿檻開。"]'),
('3e7762ec-aa25-4413-95f4-e5490abe7775','宮詞  其一一','王仲修','宋','宋诗','song-poetry','','[]','雲嬌煙懶雨初晴，環碧風輕細浪生。',32,'全唐诗/poet.song.49000.json','["雲嬌煙懶雨初晴，環碧風輕細浪生。", "盡日黄鸝不飛去，萬年枝上聽簫聲。"]'),
('854dad70-31c1-4e49-b0c3-6b044e2bbeb0','宮詞  其一二','王仲修','宋','宋诗','song-poetry','','[]','太平無事似熙豐，天樂聲和下帝宮。',32,'全唐诗/poet.song.49000.json','["太平無事似熙豐，天樂聲和下帝宮。", "禽鳥也能知樂事，宮鶯嬌醉弄春風。"]'),
('a27b2cc0-0a70-4dce-8914-2eb1d8c6288f','宮詞  其一三','王仲修','宋','宋诗','song-poetry','','[]','殿角風搖柳带長，御溝流水落花香。',32,'全唐诗/poet.song.49000.json','["殿角風搖柳带長，御溝流水落花香。", "雨來雙燕歸應早，先上珠簾十二行。"]'),
('8f61a8be-923a-48b5-9d0c-95ea96f22441','宮詞  其一四','王仲修','宋','宋诗','song-poetry','','[]','玉闌萬朵牡丹開，先摘姚黄獻御杯。',32,'全唐诗/poet.song.49000.json','["玉闌萬朵牡丹開，先摘姚黄獻御杯。", "翠幙重重圍繞定，料應蜂蝶不曾來。"]'),
('fdd423a9-5e6f-494b-b48f-e6eb4e4f305d','宮詞  其一五','王仲修','宋','宋诗','song-poetry','','[]','春深百卉過芬芳，雕檻惟餘芍藥香。',32,'全唐诗/poet.song.49000.json','["春深百卉過芬芳，雕檻惟餘芍藥香。", "應是東君偏着意，日華浮動御衣黄。"]'),
('f70b8bef-294c-4b2f-b180-82207d61740b','宮詞  其一六','王仲修','宋','宋诗','song-poetry','','[]','紅乾綠淡有餘香，芳草芊綿苑路長。',32,'全唐诗/poet.song.49000.json','["紅乾綠淡有餘香，芳草芊綿苑路長。", "鶗鴂一聲寒食雨，遊蜂應爲百花忙。"]'),
('2e088398-6f57-4225-b0c0-5b3115ed7bea','宮詞  其一七','王仲修','宋','宋诗','song-poetry','','[]','柳絮飄零春事稀，綠蔭零亂上瑤墀。',32,'全唐诗/poet.song.49000.json','["柳絮飄零春事稀，綠蔭零亂上瑤墀。", "好花着子青如豆，刧憶香紅滿檻時。"]'),
('07875d2b-67d0-412d-8555-f525b65e9105','宮詞  其一八','王仲修','宋','宋诗','song-poetry','','[]','春氣融和萬物佳，殿前仍有四時花。',32,'全唐诗/poet.song.49000.json','["春氣融和萬物佳，殿前仍有四時花。", "宮人刧愛山家景，松竹陰中碾建茶。"]'),
