('1a46d63f-74e8-4410-bef5-ecb4aeb6b80b','慶姪耆登第','王仲修','宋','宋诗','song-poetry','','[]','錫宴便傾光祿酒，賜袍還照上林花。',32,'全唐诗/poet.song.49000.json','["錫宴便傾光祿酒，賜袍還照上林花。", "衣冠盛事堪書日，六世詞科只一家。"]'),
('e7ceb571-c386-45c3-8010-d203f1c75a7b','送程給事知越州','王仲修','宋','宋诗','song-poetry','','[]','乞麾占得山川勝，金紐新提左顧龜。',64,'全唐诗/poet.song.49000.json','["乞麾占得山川勝，金紐新提左顧龜。", "蒼闕鬥龍辭日下，紅旌引騎照江湄。", "剡溪月午何妨醉，曲水春餘好賦詩。", "玉案天香攜滿袖，錦衣誰似過鄉時。"]'),
('0aea44f5-2234-4fc0-9419-7caf95bbd455','詩呈同院諸公六首  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，多朋信可依。',48,'全唐诗/poet.song.49000.json','["秋日同文館，多朋信可依。", "慧鶯還伴鎻，巧燕自知歸。", "藻鑑由來定，翹材未覺稀。", "賢書早晚上，拭目看珠璣。"]'),
('4f107eb6-3ab0-45c9-a293-e50322450bd1','詩呈同院諸公六首  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，朝暉淡淡光。',48,'全唐诗/poet.song.49000.json','["秋日同文館，朝暉淡淡光。", "聚蚊喧敗帳，飛蝠入雕梁。", "香散青綾被，詩飜古錦囊。", "羣居有英彦，晤語興何長。"]'),
('b0ccbd4b-5bc8-435a-b76e-259e17257ed5','詩呈同院諸公六首  其三','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，虛廊日幾回。',48,'全唐诗/poet.song.49000.json','["秋日同文館，虛廊日幾回。", "浮花出林杪，古樾蔽城隈。", "遠笛悲仍壯，幽禽去又來。", "微吟還自喜，共和有清才。"]'),
('d3461e57-8b86-4723-95bd-a3fcedc17d6a','詩呈同院諸公六首  其四','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，分場試未齊。',48,'全唐诗/poet.song.49000.json','["秋日同文館，分場試未齊。", "借書窮石室，刋字費棠梨。", "想見英雄彀，誰當甲乙題。", "喜陪羣彦集，通籍在金閨。"]'),
('6b16f4be-9e56-426d-8854-2d6d3cb96992','詩呈同院諸公六首  其五','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，來遊翰墨場。',48,'全唐诗/poet.song.49000.json','["秋日同文館，來遊翰墨場。", "預聞周俊造，多有漢文章。", "蘭室依新潤，芸書識舊香。", "逢辰强思報，矯首詠明康。"]'),
('72a0f548-12ce-4391-8201-c79af0530cb2','詩呈同院諸公六首  其六','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，晨興不待雞。',48,'全唐诗/poet.song.49000.json','["秋日同文館，晨興不待雞。", "耽書迷甲子，行樂在東西。", "靜對庭柯盼，閒常柿葉題。", "相期放朝後，連日醉如泥。"]'),
('059e9674-f5c8-463b-8b26-ed67cc0e69be','未試即事雜書率用秋日同文館爲首句三首  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，沉沉鎻棘闈。',48,'全唐诗/poet.song.49000.json','["秋日同文館，沉沉鎻棘闈。", "捲簾襟乍快，欹枕夢先歸。", "驟雨憂環堵，回風喜裌衣。", "十年經五試，撫事意多違。"]'),
('4280f504-f8bf-40f3-9d74-14c0bd4785ec','未試即事雜書率用秋日同文館爲首句三首  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，人閒景自長。',48,'全唐诗/poet.song.49000.json','["秋日同文館，人閒景自長。", "重簾朝氣入，嘉木午陰凉。", "朝市喧聊避，山林興未忘。", "頻添繞爐水，還與試香方。"]'),
('1ee3e7ad-b1c7-452d-9bf4-38b5abd4e0ec','未試即事雜書率用秋日同文館爲首句三首  其三','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，重門靜不開。',48,'全唐诗/poet.song.49000.json','["秋日同文館，重門靜不開。", "雲隨鴻影去，風送樂聲來。", "插架書千軸，論文酒百杯。", "脱花陳葉滿，還是作愁媒。"]'),
('b532a997-4fff-445e-9bf6-6e92c994f18a','天啓有少年真喜事之句用其韻和','鄧忠臣','宋','宋诗','song-poetry','','[]','慷慨論邊事，飄蕭動禮闈。',48,'全唐诗/poet.song.49000.json','["慷慨論邊事，飄蕭動禮闈。", "貴須金印綰，老要玉闗歸。", "食酪便榆塞，鳴鐃慣鐡衣。", "懸知雄辯在，志願未應違。"]'),
('73bd5c67-1b49-4a0b-8b28-6ff4646bb19d','詩呈同院後至諸公','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，飛章待報回。',48,'全唐诗/poet.song.49000.json','["秋日同文館，飛章待報回。", "絲綸先日降，鵷鷺忽朋來。", "諸彦俱精鑒，微生亦濫陪。", "紛紛五千牘，誰定冠倫魁。"]'),
('1e277c86-f1be-498a-8a50-69b8feb1cb1e','詩呈同院','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日同文館，論交手重攜。',48,'全唐诗/poet.song.49000.json','["秋日同文館，論交手重攜。", "胡秦常恨邈，李杜豈堪齊。", "尚喜新知語，閒思舊句題。", "十年勞夢想，同直集英西。"]'),
('d78ddfb5-f82d-4fad-b8ec-d0265a3f3918','初入試院','鄧忠臣','宋','宋诗','song-poetry','','[]','東門驄馬止行行，被詔秋闈閲俊英。',64,'全唐诗/poet.song.49000.json','["東門驄馬止行行，被詔秋闈閲俊英。", "三島隔雲天北極，萬燈明路國西城。", "人閒聊假詩書樂，地遠還聞市井聲。", "一夜凉風起閶闔，月中應有桂枝生。"]'),
('4171c948-e3ab-454c-ae63-be50696fc9ab','試院即事呈諸公','鄧忠臣','宋','宋诗','song-poetry','','[]','俊遊常恨邈山河，邂逅文闈喜屢過。',64,'全唐诗/poet.song.49000.json','["俊遊常恨邈山河，邂逅文闈喜屢過。", "朱簿分明俱鼎立，墨圖伻位看星羅。", "人開户牖還相近，朝進英材信可歌。", "雙鑰重闗非不密，只應無奈夢魂何。"]'),
('9782b49f-8086-4bc1-be92-68ff0be8b876','奉酬  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','秋闈深鎻覺愁多，賴有英遊玉趾過。',64,'全唐诗/poet.song.49000.json','["秋闈深鎻覺愁多，賴有英遊玉趾過。", "日望高樓吟楚月，夢隨明月到湘羅。", "南宫曾看揮華藻，西館還來共笑歌。", "六稔飛光如過隙，人生誰奈老催何。"]'),
('bfe4a970-2847-431c-8e51-d60aed81737e','奉酬  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','試場未動文書靜，官舍相聯步履過。',64,'全唐诗/poet.song.49000.json','["試場未動文書靜，官舍相聯步履過。", "千丈蒼波爭倚薄，十圍便腹有森羅。", "登臨已結騷人恨，填委終翻勞者歌。", "後夜中秋佳月色，惟予不飲奈明何。"]'),
('445df14c-106b-4ff5-9950-68569fe6360f','重九考罷試卷書呈同院諸公二首  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','題遍朱籖棟宇充，燈窗長聽景陽鐘。',64,'全唐诗/poet.song.49000.json','["題遍朱籖棟宇充，燈窗長聽景陽鐘。", "昏眵直要金箆刮，黎瘦都如飯顆逢。", "文律自隨星斗變，月評應合士人從。", "了無一事猶深鎻，辜負東籬菊品濃。"]'),
('8021c4fa-d748-4852-b790-3ac8513c2893','重九考罷試卷書呈同院諸公二首  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','屢見高文試澤宫，長年參校愧龍鍾。',64,'全唐诗/poet.song.49000.json','["屢見高文試澤宫，長年參校愧龍鍾。", "懸黎待價由來久，緑綺知音不易逢。", "吉語乍聞隨鵲喜，歸期專欲問龜從。", "到家莫負如泥約，光祿供醪味漸濃。"]'),
('9eacc0c4-2daa-4c19-af2b-c2a4daf6c623','夜聽無咎文潛對榻誦詩響應達旦欽服雄俊輒用九日詩韻奉貽','鄧忠臣','宋','宋诗','song-poetry','','[]','連床交語響舂容，激楚評騷徹曉鐘。',64,'全唐诗/poet.song.49000.json','["連床交語響舂容，激楚評騷徹曉鐘。", "繞宅金絲神共聽，滿潭雷雨劍初逢。", "信知自有江山助，便欲長操几杖從。", "俱是年家情不淺，依蘭應許丐香濃。"]'),
('c5aa036a-3bbc-416d-8ae8-9fb3d6f0ebb8','同舍問及故山景物用鍾字韻詩以答','鄧忠臣','宋','宋诗','song-poetry','','[]','吾廬高對玉池峰，日聽諸天奏鼓鐘。',64,'全唐诗/poet.song.49000.json','["吾廬高對玉池峰，日聽諸天奏鼓鐘。", "海外鶴歸青嶂覺，洞中花落碧溪逢。", "翻經夜對高禪請，採葉晨邀老圃從。", "說與羣仙如畫出，紛然歸思亂雲濃。"]'),
('04b8eb72-8ecd-49f7-8235-3554c0b9f981','感興復用鍾字韻戲呈同舍','鄧忠臣','宋','宋诗','song-poetry','','[]','五年湘水聽霜楓，長樂初聞此夜鐘。',64,'全唐诗/poet.song.49000.json','["五年湘水聽霜楓，長樂初聞此夜鐘。", "遼鶴亦知華表在，仙棋猶許爛柯逢。", "蓬山道藏聊爲戲，石室真游久欲從。", "便擬作歌招隱去，人間得意不須濃。"]'),
('5d1fb0a1-0343-41fb-9d58-ded5daaa8567','和蔡肇慎思說家山之勝用其語得詩','鄧忠臣','宋','宋诗','song-poetry','','[]','野橋隨岸架，茅屋依林脩。',48,'全唐诗/poet.song.49000.json','["野橋隨岸架，茅屋依林脩。", "木落吟霜狖，雲晴舞雪鷗。", "山屏當户列，瀑布入溪流。", "只合樵歌唱，何因得蔡謳。"]'),
('f10d52c8-e627-4566-9acd-d7f54bff3b51','寄次張弟','鄧忠臣','宋','宋诗','song-poetry','','[]','猫頭竹葉細檀欒，新笋如椽日滿盤。',32,'全唐诗/poet.song.49000.json','["猫頭竹葉細檀欒，新笋如椽日滿盤。", "寄語兒童莫多取，來春從上萬餘竿。"]'),
('4656957c-fc49-43b5-b8ae-0fb87f594e8a','和文潛嘲無咎夜起明燈誦予詩','鄧忠臣','宋','宋诗','song-poetry','','[]','參横月轉與天高，歸士飛心憶大刀。',32,'全唐诗/poet.song.49000.json','["參横月轉與天高，歸士飛心憶大刀。", "故作楚吟排滯思，吟成風葉更蕭騷。"]'),
('791d9df5-baa2-4eb8-8118-3ddd4bdebe3d','奉答張文潛戲贈','鄧忠臣','宋','宋诗','song-poetry','','[]','拚老工詩恨不高，苦心錯玉與礱刀。',32,'全唐诗/poet.song.49000.json','["拚老工詩恨不高，苦心錯玉與礱刀。", "正如天祿秋風夜，剔盡寒燈著廣騷。"]'),
('21931ff8-3688-4486-9499-4a2604ce31a8','再謝周顒之句二首  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','眼看秋雁歌汾水，心到陽闗唱渭城。',32,'全唐诗/poet.song.49000.json','["眼看秋雁歌汾水，心到陽闗唱渭城。", "却被維摩居士笑，海潮音作斷腸聲。"]'),
('5c974c9d-0f5b-47fe-8423-f36e1b78e254','再謝周顒之句二首  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','秋日照歌淮上舫，春花引醉福昌城。',32,'全唐诗/poet.song.49000.json','["秋日照歌淮上舫，春花引醉福昌城。", "何如閶闔門西北，卧聽秋風枕畔聲。"]'),
('906c2b3f-1918-4b12-b447-abefabd86c4c','小詩戲無咎','鄧忠臣','宋','宋诗','song-poetry','','[]','文書盈几法筵埋，香火秋來願稍乖。',32,'全唐诗/poet.song.49000.json','["文書盈几法筵埋，香火秋來願稍乖。", "得似鹿門攜手去，定隨繡佛鎮長齋。"]'),
('3d5acb58-97b3-4606-a1c4-57a49f914ca9','已未年春與伯時較試南宫同年被命者六人今兹西館唯同伯時一人而已因書奉呈','鄧忠臣','宋','宋诗','song-poetry','','[]','十載京師五校文，並游多已據通津。',32,'全唐诗/poet.song.49000.json','["十載京師五校文，並游多已據通津。", "再來更鎻城西館，檢點同年只一人。"]'),
('b5b4f7cd-cbd7-4fa6-a3e8-1aebd33ea1ae','中秋月','鄧忠臣','宋','宋诗','song-poetry','','[]','寂寥無聲月亭午，蟾蜍通津墮清露。',32,'全唐诗/poet.song.49000.json','["寂寥無聲月亭午，蟾蜍通津墮清露。", "明星爛爛今何稀，美人熒熒隔煙霧。"]'),
('29963844-aac1-4748-83e3-3d0f75814042','與文潛無咎對榻夜話達旦','鄧忠臣','宋','宋诗','song-poetry','','[]','書窗燈火夜深明，窗外蕭蕭雨葉聲。',32,'全唐诗/poet.song.49000.json','["書窗燈火夜深明，窗外蕭蕭雨葉聲。", "對榻不眠談往事，紞如五鼓過嚴城。"]'),
('2d2b8388-50a4-436a-b47d-19f83eed0252','初伏大雨戲呈無咎四首  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','大明放朝官避暑，長廊翛翛絕塵土。',128,'全唐诗/poet.song.49000.json','["大明放朝官避暑，長廊翛翛絕塵土。", "漢家宫殿敞千門，紫閣拖雲洒甘雨。", "雷恲電笑洗蒸鬱，蕩蕩青天滑流乳。", "憶昨三年田舍中，六月正服農家苦。", "豈望生還直舊廬，得見張晁說新語。", "初聽鈞天驟竊抃，正似聲聞躩起舞。", "喜乘初凉與晤歌，不憂庭潦墊垣户。", "徑攜斗酒相就醉，更置雙鯉充君爼。"]'),
('c1f9d979-c171-4997-bbf5-08c6d6bc8823','初伏大雨戲呈無咎四首  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','汗流龜趺如炊釜，蜉蝣飛空蟻運土。',128,'全唐诗/poet.song.49000.json','["汗流龜趺如炊釜，蜉蝣飛空蟻運土。", "眼看纎雲上太清，曾不崇朝八荒雨。", "金柔火老旱太甚，咀嚼冰雪如餳乳。", "豐隆列缺及時來，蒼生解除焦焚苦。", "張侯不辭茅屋漏，倚柱長吟可人語。", "愛君豪猛爲君和，撫劍悲歌終起舞。", "南城酒壚醅新潑，不獨黄公當門户。", "滿酤鴟夷極懽酌，細摘園蔬供鼎爼。"]'),
('561a5b27-0281-49af-8a03-d58675e0dcba','初伏大雨戲呈無咎四首  其三','鄧忠臣','宋','宋诗','song-poetry','','[]','突洽塵魚生甑釜，十年都城困風土。',128,'全唐诗/poet.song.49000.json','["突洽塵魚生甑釜，十年都城困風土。", "不辭揮汗過三伏，敗屋怯聽滂沱雨。", "張侯作詩召清風，渴讀如飲雪山乳。", "笑我形容太瘦生，我亦悔前用心苦。", "晁子迭唱亦起予，兩人終日同堂語。", "奈何拘學技藝窮，跛鼈欲趁驌驦舞。", "魁然圍腹貯文史，朝來氣爽寛酒户。", "爲君急置槎頭鯿，縷翠霖紅落雕爼。"]'),
('0b6c92e9-6406-4a4f-b780-87b767333cea','初伏大雨戲呈無咎四首  其四','鄧忠臣','宋','宋诗','song-poetry','','[]','神龜不識烹魚釜，生潛深淵長黄土。',128,'全唐诗/poet.song.49000.json','["神龜不識烹魚釜，生潛深淵長黄土。", "誰令誤落魚網中，白晝冥冥作雷雨。", "嗟予蟠然别舊隱，空巖無人滴鍾乳。", "松菊滿山胡不歸，願同妻子忍攻苦。", "長歌漫漫何時旦，起坐中夜私自語。", "茅茨十九漏如澠，誰知華堂醉歌舞。", "山中吾廬歸去來，峰插翠玉朝南户。", "注目操刀必割時，尸祝何煩越尊爼。"]'),
('97578f05-6244-4918-a4cb-1dfd3e568941','曹子方用釜俎字韻賦詩見遺予洎張文潛晁無咎蔡天啓因以奉酬并示四友','鄧忠臣','宋','宋诗','song-poetry','','[]','長愛陳思詠萁釜，幾年不見徂南土。',128,'全唐诗/poet.song.49000.json','["長愛陳思詠萁釜，幾年不見徂南土。", "朅來相逢翰墨場，夜窗共聽空堦雨。", "躍馬蔡卿能齧肥，好書張侯期飲乳。", "晁令知從博士遷，智囊不厭傳經苦。", "於兹邂逅如夙契，睠我劬勞勤晤語。", "詩成乍變龍虎文，筆落更驚鸞鳯舞。", "我將隱遁山林姿，公等整頓乾坤户。", "分同斥鷃搶榆枋，難伴犧牛登鼎俎。"]'),
('31cbb6bd-c5f9-4d12-8ab1-af0375b6b23d','欲知歸期近呈天啓','鄧忠臣','宋','宋诗','song-poetry','','[]','欲知歸期近，行行重攜手。',96,'全唐诗/poet.song.49000.json','["欲知歸期近，行行重攜手。", "掖垣隔華省，明日難邂逅。", "作者六七人，崢嶸竦神秀。", "藏蟄龍虎姿，風雲即騰吼。", "嗟予自遲暮，老驥伏閒廐。", "奪珠不量力，攬臂犯牙口。", "平生辛苦行，何足爲已有。", "政似逢毛嬙，歸憎孟光醜。"]'),
('bf96cddf-692d-4ecc-9a63-616bc4a64a21','考校同文館戲贈子方兼呈文潛','鄧忠臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','五年坎壈哀南方，江湖魏闕兩相忘。',352,'全唐诗/poet.song.49000.json','["五年坎壈哀南方，江湖魏闕兩相忘。", "洞蘿巖桂搴孤芳，月潭風渚儔漁郎。", "單閼孟夏草木長，望都樓觀鬱蒼蒼。", "誰令焚芰辭楚狂，復來上君白玉堂。", "黄門戟曜羽林槍，未央引籍班氐羌。", "雲屯錦縛馬斯臧，大官日膳瓊爲粮。", "追隨威鳯鳴南岡，豈敢偃息復在床。", "投鈴歸休下殿傍，衞士傳詔來如驤。", "館閶闔外西城隍，書槖迫遽不及裝。", "籲俊士集要言揚，得弓勿問何人亡。", "趙璧既入秦城償，頴脱喜見錐出囊。", "同人于野不擇鄉，峨峨羽翮整顔行。", "王閑玉勒皆驌驦，伯喈懷贖望金商。", "魁梧奇偉值文房，家令數術應帝王。", "三英粲粲日爭光，我輒與之較雌黄。", "芳菲滿室蘭生香，坐堂月久秋氣凉。", "將軍思歸歌撫觴，倚梧目送雁南翔。", "想見葭菼水中央，洞庭河漢遥相望。", "香楓葉老赤染霜，感慨少日七步章。", "長安城西約鄭莊，牽率不往有底忙。", "人生可意乃吉祥，快馬劃過小苑墻。", "入門爛醉銀瓶漿，秦箏趙瑟喜高張。"]'),
('66ae2d4f-6472-4a09-8449-4b72a1730a7c','敬次無咎來韻抒寫素懷兼呈文潛天啟伯時仲遠','鄧忠臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','梁宋吳楚各異方，交情一契不相忘。',352,'全唐诗/poet.song.49000.json','["梁宋吳楚各異方，交情一契不相忘。", "况乃顔色瓊枝芳，石渠金馬從諸郎。", "我從瀟湘煙水長，江湖飫見山色蒼。", "扣舷弄月浩歌狂，朅來濫吹崇賢堂。", "儲胥乍駭緑沉槍，擊鼓震礱庸蜀羌。", "爰居受饗謀非臧，悔辭卑飛斑竹崗。", "終日獺祭書繞床，故山秋菊英可糧。", "西風夢掛南斗旁，翠蚪絳螭交首驤。", "坐看樓闕照天隍，壯心鬱律軍騰裝。", "弢弓卧甲氣不揚，揮斤欲斵？人亡。", "劍價倚待風胡償，雲間邂逅得智囊。", "洞庭鈞天奏帝鄉，慷慨奮激萬夫行。", "天路滅没飛驌驦，張侯同聲羽應商。", "蓬萊方丈屋連房，海口瀾翻議百王。", "太乙下照青藜光，要我挾槧弄鉛黄。", "四庫顛倒翻芸香，蔡卿有來安西凉。", "慨慕玉闗歸獻觴，同官李柳並翺翔。", "鸞和節奏聲央央，誰其力薦慰所望。", "九閽白日無雪霜，垂光虹霓急草章。", "沉冥清遠雨蜀莊，人間勢利本不忙。", "麒麟鸑鷟國珍祥，每恨官隔西掖墻。", "可使簸揚挹酒漿，不似箕斗名虛張。"]'),
('ca426784-0c23-4df9-acc5-ea76f92fd186','漫興成章屢蒙子方寵和更辱贈句輒用奉酬','鄧忠臣','宋','宋诗','song-poetry','','[]','聲名詞藻競駸駸，不負平生許與心。',64,'全唐诗/poet.song.49000.json','["聲名詞藻競駸駸，不負平生許與心。", "嗚鳳自須諧玉磬，野麋祗合戀雲林。", "清新每喜羊何和，冥默初聞雅頌音。", "不是南冠厭拘縶，楚人元愛楚風吟。"]'),
('37113f85-1bc2-4098-8b37-f68592159779','邯鄲道中夜行阻風','鄧忠臣','宋','宋诗','song-poetry','','[]','欲瀉懸河雨，先號拔木風。',48,'全唐诗/poet.song.49000.json','["欲瀉懸河雨，先號拔木風。", "問津尨吠處，覓路霓光中。", "徒御憂羣盜，兒童笑拙翁。", "當知步兵哭，初不爲途窮。"]'),
('9a651794-e386-4d33-8f91-2ec1a91e18d5','和胡宿韻寄蔣之奇  其一','鄧忠臣','宋','宋诗','song-poetry','','[]','夢罷靜思巖野迴，何心商鼎作羹梅。',64,'全唐诗/poet.song.49000.json','["夢罷靜思巖野迴，何心商鼎作羹梅。", "東門祖帳新光寵，北斗樞星舊冠魁。", "無故弟兄真可樂，相忘父子總多才。", "扁舟若向東吳去，几杖何由日夕陪。"]'),
('6e07ed08-9161-4b6c-b329-9e642a04d7d2','和胡宿韻寄蔣之奇  其二','鄧忠臣','宋','宋诗','song-poetry','','[]','獨步文章妙一臺，都門便欲掛冠迴。',64,'全唐诗/poet.song.49000.json','["獨步文章妙一臺，都門便欲掛冠迴。", "已憐天上三台路，未盡人間八斗才。", "坐幄每聞千里勝，占雲初見四夷來。", "我公莫作遄歸想，衣笥行看衮繡開。"]'),
('31d5d0b9-e56e-455a-af45-c15e1b047dc4','送程給事知越州','上官均','宋','宋诗','song-poetry','','[]','遠民誰布上恩寬，一紙除書輟近班。',64,'全唐诗/poet.song.49000.json','["遠民誰布上恩寬，一紙除書輟近班。", "候騎百城瞻使節，壺漿十里過鄉關。", "雲山繚繞謳吟外，鈴閣從容指顧間。", "密詔未從疏傅請，追鋒行看日邊還。"]'),
('16e95de7-4366-457b-8199-413fa2355233','題耿氏溫凊堂','上官均','宋','宋诗','song-poetry','','[]','遠山終日自清輝，縹渺喬林野氣微。',64,'全唐诗/poet.song.49000.json','["遠山終日自清輝，縹渺喬林野氣微。", "秋菊已開陶令徑，春風好舞老萊衣。", "溪頭釣艇資閒興，松下歸禽伴息機。", "吟倚醉登堪自慰，不須悵望白雲飛。"]'),
('e2a17fec-8c25-4c84-8ac5-5a9e0b05a39c','望仙峰','傅權','宋','宋诗','song-poetry','','[]','嵯峨山勢傍雲天，試問誰來此望仙。',32,'全唐诗/poet.song.49000.json','["嵯峨山勢傍雲天，試問誰來此望仙。", "終日望仙仙不見，始知仙道若茫然。"]'),
('33f027a3-6e0f-4036-a7b0-7cae6399de0b','橫石潭','傅權','宋','宋诗','song-poetry','','[]','圓如冰鑑石平橫，一派泉流到此停。',32,'全唐诗/poet.song.49000.json','["圓如冰鑑石平橫，一派泉流到此停。", "我信龍潛應咫尺，終終大海潤生靈。"]'),
('bf7340aa-0707-45e8-b78e-64ef80b8f762','夜宿東巖寺','傅權','宋','宋诗','song-poetry','','[]','夜宿給孤園，悠然魂欲仙。',48,'全唐诗/poet.song.49000.json','["夜宿給孤園，悠然魂欲仙。", "恐驚沙上月，莫吸石間泉。", "露落螢初度，風回鶴欲眠。", "更瞻峰嶺氣，非霧復非煙。"]'),
('babbe291-c7e5-460b-9832-eb149fe4fe14','再遊廣福院','傅權','宋','宋诗','song-poetry','','[]','古寺荒涼近水涯，鐘聲朝暮落漁家。',32,'全唐诗/poet.song.49000.json','["古寺荒涼近水涯，鐘聲朝暮落漁家。", "昔年蹤迹曾經此，依舊殘陽伴晚霞。"]'),
('d89cd179-d39d-426a-ba01-bc50cc6f70cb','東峰亭','臧詵','宋','宋诗','song-poetry','','[]','水西庭榭枕東峰，終日秋陰一徑松。',64,'全唐诗/poet.song.49000.json','["水西庭榭枕東峰，終日秋陰一徑松。", "月到灘心來白鷺，雲浮潭面起蒼龍。", "最宜翠斂前山雨，長是聲聞近寺鐘。", "報捷功名今共聞，時攜樽酒訪遺蹤。"]'),
('cc32c1ae-b2b7-4e9f-a338-d9e144918645','一華亭','朱敏功','宋','宋诗','song-poetry','','[]','自聞達摩西來意，五葉敷榮祇一花。',32,'全唐诗/poet.song.49000.json','["自聞達摩西來意，五葉敷榮祇一花。", "從此祖風傳不泯，靈芝到處有奇華。"]'),
('2e5547ce-5c54-4c0b-8ee5-19797bb51f73','和王公覿賞海雲山茶合江梅花','徐彥孚','宋','宋诗','song-poetry','','[]','萬蕊山茶傍臘開，一番春信入江梅。',64,'全唐诗/poet.song.49000.json','["萬蕊山茶傍臘開，一番春信入江梅。", "追遊共按黄金轡，縱賞還傾白玉杯。", "濃艷迎風香斷續，疏枝橫月影徘徊。", "隼旟不負登臨興，更約攜朋載酒來。"]'),
('fcc6c5eb-b5b2-459a-b5f4-08d0d24578f1','西園辨蘭亭和韻','李之純','宋','宋诗','song-poetry','','[]','綠葉纖長間紫莖，蜀人未始以蘭名。',64,'全唐诗/poet.song.49000.json','["綠葉纖長間紫莖，蜀人未始以蘭名。", "有時只怪香盈室，此日方傳譽滿城。", "恩意和風揚馥鬰，光榮灝露滴清英。", "庭階若不逢精鑒，何異深林靜處生。"]'),
('2665313d-8c5f-4ef2-b711-6a711f904314','雪後','李之純','宋','宋诗','song-poetry','','[]','玉環暈月蟠長虹，飛沙捲土號陰風。',212,'全唐诗/poet.song.49000.json','["玉環暈月蟠長虹，飛沙捲土號陰風。", "黄雲冪冪翳晴空，屋頭唧唧鳴寒蟲。", "天符夜下扶桑宮，玄冥震怒鞭魚龍。", "魚龍飛出滄海底，咄嗟如律愁神公。", "急𣂏北斗捲雲漢，凌澌捲入天瓢中。", "椎璋碎六華，剪出寒瓏璁。", "翩翩作穗大如手，千奇萬巧難形容。", "恍如墮我銀沙界，清光皜夜寒朣朧。", "肝腸作祟耿無寐，試把往事間追窮。", "男兒生須銜枚捲甲臂琱兮，徑熱虎穴策奇功。", "不然羊羔酒帳玻璃鐘，侍兒醉臉潮春紅。", "誰能蹇驢駝著灞陵東，骨相酸寒愁煞儂。", "屏山正吐黄虀氣，笑倒坐間亡是公。"]'),
('c57a7e10-f7a5-42b2-ab5f-e68c3fbf81b8','真味堂','李之純','宋','宋诗','song-poetry','','[]','問渠真味若爲言，不著鹽梅也自全。',64,'全唐诗/poet.song.49000.json','["問渠真味若爲言，不著鹽梅也自全。", "黿鼎大夫徒染指，麯車公子謾流涎。", "胸中已有五千卷，徽外更聽三兩弦。", "此老清饞何所嗜，宦途嚼臘已多年。"]'),
('7f38eb9c-cd17-4f26-95ca-948bca86e313','駕幸太學','李之純','宋','宋诗','song-poetry','','[]','羽衛金輿煥彩章，天街端去入虞庠。',64,'全唐诗/poet.song.49000.json','["羽衛金輿煥彩章，天街端去入虞庠。", "嚴師致奠初加拜，延講終篇不計行。", "萬乘屈尊先郡國，諸生賜坐亞侯王。", "輔臣歸美榮歌詠，首發清風政事堂。"]'),
('ac7080a0-257d-439c-beee-a7f28349e5f7','憶李之純三首  其一','王從之','宋','宋诗','song-poetry','','[]','幼歲求真契，中年得偉人。',48,'全唐诗/poet.song.49000.json','["幼歲求真契，中年得偉人。", "傾懷當一面，投分許終身。", "燈火談玄夜，鶯花逐勝春。", "何時重一笑，胸次欲生塵。"]'),
('ff0bb066-d2f6-4f27-9e40-820e628ba3bc','憶李之純三首  其二','王從之','宋','宋诗','song-poetry','','[]','面目三年隔，音傳萬里遙。',48,'全唐诗/poet.song.49000.json','["面目三年隔，音傳萬里遙。", "宦途俱蹭蹬，日事各蕭條。", "志大謀常拙，身孤道亦消。", "本無當世用，隱處會相招。"]'),
('77c22f8c-a454-4437-8bb9-30503924017f','憶李之純三首  其三','王從之','宋','宋诗','song-poetry','','[]','雋氣傾天下，高情到古今。',48,'全唐诗/poet.song.49000.json','["雋氣傾天下，高情到古今。", "啣杯曼卿放，下筆老坡神。", "時論誰優劣，人材自屈伸。", "窮愁須理遣，不必淚沾巾。"]'),
('a37e489c-4862-4f08-9f91-8a9b6befbc2b','題道巖二十韻','黄誥','宋','宋诗','song-poetry','','[]','道士元周其姓胡，朝來遺我仙巖圖。',320,'全唐诗/poet.song.49000.json','["道士元周其姓胡，朝來遺我仙巖圖。", "一堆磐石東西向，鑿破混沌中心虛。", "欲知地面深且廣，架屋百楹端有餘。", "天池高下相灌溉，四柱卓立擎香爐。", "席帽近南猶仰視，雲蓋一峰蟠北隅。", "前巖後巖爲表裏，直過可以肩籃輿。", "吳許遺留試劍石，葛艾棄置燒丹爐。", "當時俗眼固不識，一旦脫屣朝清都。", "至今丹井泉源湧，下接三江連五湖。", "春來桃李開錦繡，宛在武陵溪上居。", "人間酷熱不能到，清風白水搖芙蕖。", "霜飛雪落萬木死，玉葉青青長不枯。", "三清殿前拜章夜，香繞真儀七十軀。", "月光射入嵌空內，皎皎寒冰在玉壺。", "老龍耽睡忽驚覺，一霎萬頃霑膏腴。", "物無疵癘年穀熟，有感則通如合符。", "本朝圖經自該說，厥後荒廢成丘墟。", "元周抵掌來必葺，十四年間復古初。", "崇寧天子降明詔，廢者使興傳聖謨。", "郡邑何時月剡奏，畢封之祝相歡呼。"]'),
('6aa67253-0d83-4d51-be12-ad751737aece','三峽橋','黄誥','宋','宋诗','song-poetry','','[]','橋壓神龍三四秋，良材應是鬼神搜。',64,'全唐诗/poet.song.49000.json','["橋壓神龍三四秋，良材應是鬼神搜。", "猿猱爭飲澗中水，草木不知天下秋。", "隱士閑行隨白鹿，道人長往駕青牛。", "靈源自與天河接，誰信江淮是末流。"]'),
('889e2cd6-fca7-441e-b2d1-d71e58216155','雙劍峰','黄誥','宋','宋诗','song-poetry','','[]','瀉成神劍倚雙峰，天地爲爐造化工。',64,'全唐诗/poet.song.49000.json','["瀉成神劍倚雙峰，天地爲爐造化工。", "萬丈虹霓連碧落，一聲霹靂走豐隆。", "拂開嵐障千山秀，削盡妖魔六宇空。", "應笑鏌鋣爲小器，延平津上合雌雄。"]'),
('526dbe87-3313-4c34-bec2-4294e4255ade','賀吳樵登第','黄誥','宋','宋诗','song-poetry','','[]','連雲山下鳳凰兒，何幸今朝見白眉。',64,'全唐诗/poet.song.49000.json','["連雲山下鳳凰兒，何幸今朝見白眉。", "父子傳經無異說，弟兄題塔又同時。", "北堂偕老椿千歲，南國聯榮桂兩枝。", "青史他年書茂實，一門忠孝是鎡基。"]'),
('d0a3ad9e-d317-4e48-b448-dc4b13f1cfc3','邵武','葉祖洽','宋','宋诗','song-poetry','','[]','江南煙雨蔽征輪，行近樵陽景漸真。',32,'全唐诗/poet.song.49000.json','["江南煙雨蔽征輪，行近樵陽景漸真。", "鳥語乍聞如夢寐，林光初見長精神。"]'),
('729d7a63-54da-4e41-b624-d168a50e3568','釣臺','葉祖洽','宋','宋诗','song-poetry','','[]','先生遺世者，長謝帝京塵。',48,'全唐诗/poet.song.49000.json','["先生遺世者，長謝帝京塵。", "一釣桐江水，高名萬古春。", "客星曾犯座，天子不能臣。", "臺下千帆過，風波愁殺人。"]'),
('b6cce298-956b-439d-8fdc-dba0a264d516','句','葉祖洽','宋','宋诗','song-poetry','','[]','已分桂葉爭雲路，不負榴花結露枝。',16,'全唐诗/poet.song.49000.json','["已分桂葉爭雲路，不負榴花結露枝。"]'),
('fcd35937-a9a1-4864-be37-31129c011603','句','李公寅','宋','宋诗','song-poetry','','[]','嶺分東粤封疆闊，天限中原氣象雄。',16,'全唐诗/poet.song.49000.json','["嶺分東粤封疆闊，天限中原氣象雄。"]'),
('9e74e0a3-7bbb-4ec9-aa57-5a5fe7a634ed','枕流軒','林伯材','宋','宋诗','song-poetry','','[]','誰在紅蓮陣裏行，泠泠飛玉抱山清。',64,'全唐诗/poet.song.49000.json','["誰在紅蓮陣裏行，泠泠飛玉抱山清。", "幾番人世興亡夢，千古雲涯黯淡聲。", "春暖蘚花隨雨到，夜深寒月落溪明。", "倦懷一枕清涼地，斗藪塵埃羽翼生。"]'),
('1472448e-cb77-40c5-8b98-673c2f6868cf','破山八詠 興福寺','劉拯','宋','宋诗','song-poetry','','[]','峨峨烏目山，曾臨貴侯宅。',48,'全唐诗/poet.song.49000.json','["峨峨烏目山，曾臨貴侯宅。", "重房昔珠翠，峻宇煥金碧。", "泉激晨霞明，松搖暮雲白。", "宜爾山中人，日輪自朝夕。"]'),
('e0933896-4385-4a02-97cd-d2da81ee7c09','破山八詠 文舉塔','劉拯','宋','宋诗','song-poetry','','[]','圓旨探雙林，巵言發南華。',48,'全唐诗/poet.song.49000.json','["圓旨探雙林，巵言發南華。", "萬里歸一空，誰云正非邪。", "門影搖青松，曾迴貴侯車。", "猶遺數屋塔，岌岌凌飛霞。"]'),
('a21d8065-5aae-4e0d-8ea4-ef2aecbd42b6','破山八詠 救虎閣','劉拯','宋','宋诗','song-poetry','','[]','三昧遊深慈，結宇依蒼崖。',48,'全唐诗/poet.song.49000.json','["三昧遊深慈，結宇依蒼崖。", "猛虎伏嵬閣，拔箭非忘骸。", "窮獸雖覆車，危雀猶投懷。", "況我見已忘，而彼猶其儕。"]'),
('944ecb48-e80c-4ea3-b020-ede7462a40e0','破山八詠 龍門澗','劉拯','宋','宋诗','song-poetry','','[]','白龍鬥巍峰，長澗落千尺。',48,'全唐诗/poet.song.49000.json','["白龍鬥巍峰，長澗落千尺。", "靈泉應奇蹤，高連暮雲碧。", "寒影凌蒼崖，清流動危石。", "八月苗正枯，猶能變甘澤。"]'),
('2e7a4780-dabb-4949-a009-1c0888c0a042','破山八詠 體如塔','劉拯','宋','宋诗','song-poetry','','[]','妙理悟三伊，巍巍抗奇節。',48,'全唐诗/poet.song.49000.json','["妙理悟三伊，巍巍抗奇節。", "千尺巖下松，蕭然獨凌雪。", "珠影雖青黄，月輪豈圓闕。", "危石揚寒泉，至今伴清絕。"]'),
('cc6ea7ea-6fc0-40df-9ce4-dc61eecdbe80','破山八詠 宗教院','劉拯','宋','宋诗','song-poetry','','[]','妙義傳天台，迷雲凈如掃。',48,'全唐诗/poet.song.49000.json','["妙義傳天台，迷雲凈如掃。", "初終雖五時，修短自三草。", "結隱非此峰，獲藏亦珍寶。", "秋來月正圓，獨照松已老。"]'),
('63dc002f-94d7-49e7-8fa8-c40c33106638','破山八詠 空心潭','劉拯','宋','宋诗','song-poetry','','[]','碧潭發幽石，蕭灑無纖塵。',48,'全唐诗/poet.song.49000.json','["碧潭發幽石，蕭灑無纖塵。", "寒光湛秋月，有物難比倫。", "離鈎況無魚，千尺徒垂綸。", "到此心已空，何用濯吾纓。"]'),
('201eac06-13b6-4426-8367-c2830ae1bc6a','破山八詠 御賜鐘','劉拯','宋','宋诗','song-poetry','','[]','大聲扣洪鐘，萬里來彤庭。',48,'全唐诗/poet.song.49000.json','["大聲扣洪鐘，萬里來彤庭。", "鳥閑樓影重，星淡雲氣清。", "餘響繞巖壑，林葉如迴驚。", "有客發深省，塵耳非謾傾。"]'),
('dae5d40b-95be-43d4-9fe4-61e339653d95','中峰','劉拯','宋','宋诗','song-poetry','','[]','躡徑君高亭，天遠不敢局。',95,'全唐诗/poet.song.49000.json','["躡徑君高亭，天遠不敢局。", "疏捲檐花，百里在舉目。", "江橫縞带明，山隱螺髻綠。", "啼鳥破長煙，飛泉漱寒玉。", "雲回猛虎嘯，清風繞巖谷。", "颼颼入青松，古淡琴一曲。", "倚欄更凝望，斜陽上修竹。", "欲去還遲遲，勝概那可足。"]'),
('2ecacb3f-268b-40e0-bc53-45e3c0638ac0','涵暉閣','劉拯','宋','宋诗','song-poetry','','[]','勝地清無一點埃，水晶城裏小瑤臺。',32,'全唐诗/poet.song.49000.json','["勝地清無一點埃，水晶城裏小瑤臺。", "環堤柳弄碧雲合，浮島蓮分翠蓋來。"]'),
('2c1d8397-981a-441d-86bd-011b94590e35','秋霜閣','劉拯','宋','宋诗','song-poetry','','[]','翰林詩筆振千古，珊瑚照夜橫雕梁。',256,'全唐诗/poet.song.49000.json','["翰林詩筆振千古，珊瑚照夜橫雕梁。", "高文勝地佔江左，我來戴勝初降桑。", "雨師憤鬰欲傾注，氣蒸柱礎如迸漿。", "清風執熱逝可濯，定知五月飛秋霜。", "山盤左右儼環列，賞溪遠带摩寒光。", "蒼松怪柏倚層嶺，不許桃李參其行。", "幹纏薜荔俯危澗，渴龍矯矯鱗甲張。", "雲生樓宇隱金綠，泉落庭除蘭芷芳。", "虎傳老包踞前壁，百獸辟易遠我堂。", "像瞻黄檗若欺魄，智囊豈特降支郎。", "碧雞一聲破煙霧，靜中不覺塵世忙。", "冥搜窮討掃俗軌，更開竹徑通禪房。", "荒臺誰憶遺民釣，樂土長吟帝子章。", "避世徵君想巖穴，濯纓孺子思滄浪。", "臨流賦詩情駘蕩，萬慮不敢愁吾腸。", "會須畏夏繼康樂，青松架壑聊相望。"]'),
('de449f85-9fac-42f8-8082-9184be0c065d','題采石渡','胡璞','宋','宋诗','song-poetry','','[]','抗議金鑾反見讎，一杯蟬蛻此江頭。',32,'全唐诗/poet.song.49000.json','["抗議金鑾反見讎，一杯蟬蛻此江頭。", "當時醉弄波間月，今作寒光萬里流。"]'),
('1c2e8f7b-7e60-400e-937f-e69c4098d1dd','贈象環','陳植','宋','宋诗','song-poetry','','[]','銷整新階繞郡城，知師才智善經營。',64,'全唐诗/poet.song.49000.json','["銷整新階繞郡城，知師才智善經營。", "爲憐世路多傾側，故使行人盡坦平。", "一府輪蹄還往便，千門箕帚掃除清。", "樂遊橋上紅塵接，未免區區事送迎。"]'),
('a5c7ae18-88c9-458d-94de-4b33f128da04','沖虛宮','陳植','宋','宋诗','song-poetry','','[]','鼎邊雞犬知何在，雲外龍鸞去已賒。',32,'全唐诗/poet.song.49000.json','["鼎邊雞犬知何在，雲外龍鸞去已賒。", "惟有黄金餘瓦礫，貧民時復得些些。"]'),
('17912b86-ba81-4204-96de-fe950bde89c5','吳江太湖笠澤虹橋詩','陳植','宋','宋诗','song-poetry','','["\u592a\u6e56"]','膾憶鱸魚秋正肥，當年惟見季鷹歸。',32,'全唐诗/poet.song.49000.json','["膾憶鱸魚秋正肥，當年惟見季鷹歸。", "滄波此處堪垂釣，當代無人肯拂衣。"]'),
('1bf47add-ac84-4118-a0bb-7dd9f0e6615e','胥門','陳植','宋','宋诗','song-poetry','','[]','長堤柳線弄春柔，姑蘇臺下馬如流。',56,'全唐诗/poet.song.49000.json','["長堤柳線弄春柔，姑蘇臺下馬如流。", "春波溶漾綠潑油，官船挝鼓百花洲。", "旌旗𪑓黲城上樓，煙中雉堞高山邱，嗚嗚清角行人愁。"]'),
('274f431f-7277-4571-91df-f61f779daf2b','罾浦坊','陳植','宋','宋诗','song-poetry','','[]','疑是分開混沌初，奔奇走秀兩相於。',64,'全唐诗/poet.song.49000.json','["疑是分開混沌初，奔奇走秀兩相於。", "等閒開圃多栽竹，行到人家盡讀書。", "宴飲直嘗千戶酒，盤飧惟候兩潮魚。", "九華峰頂真仙宅，罾浦坊中出輔車。"]'),
('b9b47423-88f3-4a95-a504-0e4bdb03d328','句','陳植','宋','宋诗','song-poetry','','[]','天際三竿量日月，人間一鏡照山河。',16,'全唐诗/poet.song.49000.json','["天際三竿量日月，人間一鏡照山河。"]'),
('ba126fee-22ca-4234-acb5-59231ce11839','贈廣都遇寓舍賢婦二喻詩','頓起','宋','宋诗','song-poetry','','[]','嘗聞趙清獻，恤孤慰亡友。',288,'全唐诗/poet.song.49000.json','["嘗聞趙清獻，恤孤慰亡友。", "至今西蜀人，談美不容口。", "二喻出儒家，清貧一無有。", "零丁依老姑，破屋僧堂後。", "相對誦詩書，未嘗窺戶牖。", "圭折玉彌方，山寒松更茂。", "縣宰初聞名，咨嗟爲之久。", "從容語其配，夫人曾見否。", "長者二十三，次亦十八九。", "青裾長蔽膝，荆簪短在首。", "我欲效清獻，言不爲人取。", "近於吾邑中，選婿得豪右。", "夫人相宰意，魚蔬薦罇酒。", "屈致二喻來，呼名老與壽。", "女子當有行，詩稱遠父母。", "饑寒日月長，蓬蓽風雨漏。", "大喻前致詞，灑淚濕衣袖。", "荷德固已深，緘情亦須剖。", "上言親未葬，心欲土自負。", "下述妹未笄，𡞦𡞦無傅姆。", "還家復獻書，自敘貧且陋。", "鉛華世所悅，銅臭非吾偶。", "肯效閭閈間，碌碌逐雞狗。", "世無梁伯鸞，應嫌孟光醜。"]'),
('d6a67bd7-5695-478a-a23c-1d06754f166b','元符二年二月七日按部過邛州火井縣三友堂小酌楊公天隱嘗令此邑令此邑以山水竹爲三友余益以風月爲五賢云','頓起','宋','宋诗','song-poetry','','[]','七盤一何高，蒼翠浄寥廊。',240,'全唐诗/poet.song.49000.json','["七盤一何高，蒼翠浄寥廊。", "夜雨濯杉檜，春風散芝藥。", "細雲散巖色，細逕度危筰。", "邑改井已泥，空餘漢城郭。", "土瘠漫生茶，人稀時走玃。", "苔蘚囹圄空，塵埃簿書閤。", "縣圃何蕭條，半櫻半零落。", "偃蹇大夫松，委蛇君子鶴。", "試登三友堂，借問何人作。", "皆云楊先生，好詩心淡泊。", "乘興山水間，此君共獻酢。", "瑯玕無俗韻，仁智有真樂。", "取友信可人，自待宜不薄。", "我來宴坐久，寂寥無唯諾。", "明月來徘徊，清風自蕭索。", "因留風與月，相對成清酌。", "蟾光照金尊，餘輝射杯酒。", "輕颸入朱弦，彷彿奏簫勺。", "醺然造忘形，神交通博約。", "醉號五賢堂，醒來資一噱。"]'),
('6bcd45b2-58bf-4f97-9c04-ac006faa223d','送程給事知越州','范育','宋','宋诗','song-poetry','','[]','雍容青瑣漢儒臣，出牧東南七郡民。',96,'全唐诗/poet.song.49000.json','["雍容青瑣漢儒臣，出牧東南七郡民。", "祕府內分龍節貴，故鄉朝看錦衣新。", "湖山動色迎詩老，牛酒均歡慰路人。", "豈愧能名循吏後，應留美化大江濱。", "相逢日下黄門省，回首風前畫鷁津。", "未省行春周澤國，即聽鳴玉上楓宸。"]'),
('c80c51f7-4aa0-4477-bcd9-5ba42a6b5141','韋曲','范育','宋','宋诗','song-poetry','','[]','竹巷松門堆白沙，老農猶指相君家。',48,'全唐诗/poet.song.49000.json','["竹巷松門堆白沙，老農猶指相君家。", "林塘卜筑今誰問，譜牒名流空自嗟。", "萬簇晴山開玉案，一溪春水滿晴沙。"]'),
('5135e97c-9209-4df4-a562-1e884276fa1e','流花亭','俞純父','宋','宋诗','song-poetry','','[]','山溪窮洞府，江岸繞樓闉。',48,'全唐诗/poet.song.49000.json','["山溪窮洞府，江岸繞樓闉。", "曉艷嘗迷客，飛香尚襲人。", "凭高能賦遠，祖別重傷春。", "莫惜離歌醉，曾聞上玉津。"]'),
('69b4d662-a022-4924-a415-db0f993c4326','天開巖','王獻臣','宋','宋诗','song-poetry','','[]','覺皇普照黄金宅，西有峰巒插空碧。',32,'全唐诗/poet.song.49000.json','["覺皇普照黄金宅，西有峰巒插空碧。", "地靈不放幽境開，都把雲蘿鎖頑石。"]'),
('d148919f-a284-4da8-85ef-10c284a83950','麻姑壇','王獻臣','宋','宋诗','song-poetry','','[]','我佩綠綺琴，獨上麻姑壇。',48,'全唐诗/poet.song.49000.json','["我佩綠綺琴，獨上麻姑壇。", "七弦試拂拭，一天星斗寒。", "仙子爲我來，降語五雲端。", "世人知音少，君今休要彈。"]'),
('b5747c9f-41ca-4850-89e2-2d0d7cb3848d','澄虛閣','王獻臣','宋','宋诗','song-poetry','','[]','此地留仙竈，仙人去何早。',48,'全唐诗/poet.song.49000.json','["此地留仙竈，仙人去何早。", "一粒藥初成，空山絕靈草。", "竈傍五色土，令人百病好。", "況復餌丹人，朱顔幾時老。"]'),
('db60e56a-dba5-4e3b-8aa1-7aa1e79983fe','泗州山','王獻臣','宋','宋诗','song-poetry','','[]','大石小石皆羅列，造化安排非人設。',60,'全唐诗/poet.song.49000.json','["大石小石皆羅列，造化安排非人設。", "覆者如軒深者洞，方者如屏平者席。", "可以安尊罍，可以橫琴瑟。", "天邊烏兔眼前飛，海上波瀾掌中白。"]'),
('f27ca0b7-089d-48a7-a42f-118a3b28d742','寂光寺','王獻臣','宋','宋诗','song-poetry','','[]','霸業何勞問廢興，前人樓閣後人登。',64,'全唐诗/poet.song.49000.json','["霸業何勞問廢興，前人樓閣後人登。", "海山有籍歸真主，雲物無情屬野僧。", "飲鹿澄潭環細浪，啼猿拱木網寒藤。", "紛華不見舊時事，惟有禪龕空報澄。"]'),
('f8568a67-0c4f-4838-815d-acfe7c4b3bf4','句','胡宗炎','宋','宋诗','song-poetry','','[]','飛禽避軒蓋，殘果落莓苔。',12,'全唐诗/poet.song.49000.json','["飛禽避軒蓋，殘果落莓苔。"]'),
('7f9f264b-e75a-40e7-8768-8a91ebcba141','和蓬萊閣賞雪賦詩','許安世','宋','宋诗','song-poetry','','[]','南國收藏晚，黅天凜烈興。',288,'全唐诗/poet.song.49000.json','["南國收藏晚，黅天凜烈興。", "日行黄道市，神御坎宮乘。", "元化初施種，窮陰乍喪朋。", "氣隨鈞外轉，雲自澤中騰。", "集霰紛餘凜，號風助峻稜。", "紫霄零雜珮，玄野碎增冰。", "縞色坳窊遍，寒光上下凝。", "候嚴知節應，空曠覺神澄。", "透隙還同舞，因方不待繩。", "雁飛朝愈急，雞誤夕相應。", "吟絮飄吳苑，禋茅秀楚塍。", "階庭迷鶴鶩，林麓蔽薪蒸。", "瑤水三千里，崑崙九萬層。", "檻前闚化國，波際失西陵。", "舟興懷安道，鱸思鄙季鷹。", "勝遊方罕值，高會喜相仍。", "漲海雄藩屏，東侯實股肱。", "蕊珠辭密侍，阿閣賁華稱。", "將幕開樽俎，賓筵集俊能。", "醴杯親勸酢，龍坂盡隮登。", "郢唱人誰繼，皋謨世共矜。", "擊轅知亂雅，附驥偶同蠅。", "綰席塵空滿，嬰衣體詎勝。", "仰瞻雲漢麗，嘉惠豈虛膺。"]'),
('9ab0c3e8-061f-496f-b80f-fc67a0eec34e','題清化山','許安世','宋','宋诗','song-poetry','','[]','霜鐘清徹隔村聞，南渡橫塘曉色分。',64,'全唐诗/poet.song.49000.json','["霜鐘清徹隔村聞，南渡橫塘曉色分。", "淺淺溪流涵白石，微微山路入青雲。", "勞生已負林泉約，薄宦空增世俗紛。", "見說定香無受想，爲祛塵惑借餘熏。"]'),
('e3db1fce-fc2b-4573-8c66-f96bcd21c7b1','遊天章寺','許安世','宋','宋诗','song-poetry','','[]','常時俯仰尚爲陳，千載重來感一深。',64,'全唐诗/poet.song.49000.json','["常時俯仰尚爲陳，千載重來感一深。", "曲水已傷迷故跡，崇山依舊對遊人。", "縈紆雪路聯珠騎，蕭爽風亭岸角巾。", "秖恐瑤池歸扈宴，不能脩禊見深春。"]'),
('dcceec0b-63ca-47f7-926f-515916229e61','詠史','許安世','宋','宋诗','song-poetry','','[]','天下有誅賞，固非君所私。',48,'全唐诗/poet.song.49000.json','["天下有誅賞，固非君所私。", "太宗泣君集，意恐勞臣疑。", "至公一以廢，智術相維持。", "哀哉功名士，汲汲尚趨時。"]'),
('c5e0cacf-bc87-4bc9-9555-32ee920c3051','句','王鄰臣','宋','宋诗','song-poetry','','[]','仲舒窺圃三年廢，東野看花一日多。',16,'全唐诗/poet.song.49000.json','["仲舒窺圃三年廢，東野看花一日多。"]'),
('bb1487bd-eeca-48e7-94cc-dc5c4a23f041','馬齧麥','孔武仲','宋','宋诗','song-poetry','','[]','馬齧麥，僕飲冰，北風軒軒摇丘林，霖霪十日吁可驚。',140,'全唐诗/poet.song.49000.json','["馬齧麥，僕飲冰，北風軒軒摇丘林，霖霪十日吁可驚。", "南山喜見朝日升，尋陽北岸霜泥薄，窮臘獨爲千里行。", "五里聊一止，十里復一息。", "楊柳弄輕黄，已作春顔色。", "川原入眼雖似快，時節去家還可惜。", "齧麥不須飽，飲冰勿畏寒。", "起鞭移擔復五里，帝鄉即在須臾間。", "悠哉役夫勉桓桓，征途幾何莫永嘆，亦莫悲歌行路難。"]'),
('04468c14-4d44-4e97-8e7c-0aa515c4fd77','兒歸行','孔武仲','宋','宋诗','song-poetry','','[]','兒歸兒不歸，朝爲子母歡。',224,'全唐诗/poet.song.49000.json','["兒歸兒不歸，朝爲子母歡。", "暮爲禽鳥飛，故居不得返。", "深林安可依，此身寂寞已如此。", "我母在家應憶子，子今豈不思其親。", "空有舊心無舊身，兒歸兒不歸。", "春已暮，朝多風，夕多雨。", "山雖有泉隴有黍，兒寒有誰訴，兒饑與誰語。", "萬物卵翼皆相隨，兒今不得兒子母。", "兒歸兒不歸，年年三月種麻時。", "此聲煩且悲，聞昔一母生兩兒。", "于已所生獨愛之，麻生指作還家期。", "惟憎者來愛者去，物理反覆不可知。", "天公豈欲故如此，善惡報敏如塤箎。", "至今哀怨留空山，長爲鍳戒子母間。", "豈獨行客愁心顔，兒歸摧痛傷心肝。"]'),
('621dd2d6-062f-4b08-96c2-1ee7a7ea451e','胡人走馬行','孔武仲','宋','宋诗','song-poetry','','[]','天街極目如平水，胡人走馬天街裏。',144,'全唐诗/poet.song.49000.json','["天街極目如平水，胡人走馬天街裏。", "南宫宴罷晚色深，宿雨初乾塵不起。", "胡巾滿插漢京花，雕鞍一簇濃如霞。", "千蹄撇過在頃刻，閃電飛星不留迹。", "路旁看者如堵墻，街使傳呼俱辟易。", "朝家和戎七十年，隻矢不射胡中天。", "爾曹不必夸馳騁，官家無意窺幽燕。", "穩將金帛北歸去，萬歳千秋祝明主。", "氈車滿野春草長，任爾祁連山下住。"]'),
('7005fe8f-e0d9-47dc-a533-4d5e8cf26405','昨日之日行','孔武仲','宋','宋诗','song-poetry','','[]','昨日之日嗟可憂，羣山積雨漫溪流。',160,'全唐诗/poet.song.49000.json','["昨日之日嗟可憂，羣山積雨漫溪流。", "行人兩兩相負過，雖有橋梁如拍浮。", "南歸童僕皆賈勇，濶步豈顧川無舟。", "狂瀾更與人爭力，一跌性命甘長休。", "乘險徼幸乃無患，作客如此真何求。", "今日之日却優游，青天挂幕陰霾收。", "朝陽透射鳥烏樂，宿潦平帖蛟龍愁。", "新花芳草色鮮瑩，時而殷紅垂石榴。", "風景清曠亦可嘉，旅衣酸寒馬足羞。", "岡原漸高沮洳少，此行應快無遲留。"]'),
('4c40140c-144e-4b95-a3fa-b9eb64180511','車家行','孔武仲','宋','宋诗','song-poetry','','[]','上坂車聲遲，下坂車聲快。',92,'全唐诗/poet.song.49000.json','["上坂車聲遲，下坂車聲快。", "遲如鬼語相喧啾，快如溪沙瀉鳴瀬。", "一車人十捧擁行，江南江北不計程。", "青天白日有時住，無人止得車輪聲。", "晚來驟雨聲濯濯，平曉郊原盡溝壑。", "方悟車家進退難，不如田家四時樂。"]'),
('45160558-f936-4223-962d-fc006d825650','猗猗堂下竹','孔武仲','宋','宋诗','song-poetry','','[]','猗猗堂下竹，我來初萌芽。',180,'全唐诗/poet.song.49000.json','["猗猗堂下竹，我來初萌芽。", "生意甚蹇薄，纔能出泥沙。", "狂霖一夕作，霹靂連轟車。", "回首未幾日，其成何速耶。", "修然數尺高，秀色蔚以佳。", "餘陰過盆池，喜躍見魚鮭。", "乃知地道敏，不待歳月賖。", "念彼遠遊子，聨翩入京華。", "勢利勇奔趨，被服爭豪奢。", "外雖逐喜好，顧盼相陵夸。", "中乃昏智識，有損無増加。", "曾竹之不如，徒比草木花。", "經風已簸落，枯槁良可嗟。", "而我方涉世，浩渺無津涯。", "因竹亦自悟，慨歌窗日斜。"]'),
('9af830b9-8f23-47ae-adf4-8e12a27161d6','白湖泥','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','昔浮洞庭浪，今踏白湖泥。',84,'全唐诗/poet.song.49000.json','["昔浮洞庭浪，今踏白湖泥。", "水陸雖異趣，客程皆嶮巇。", "浮身無根株，轉徙長路岐。", "嘗聞昔人言，欲以瓦爲衣。", "風雨輒不出，華堂安所栖。", "我今南復北，擾擾亦奚爲。", "行役衆所同，浩歌聊自怡。"]'),
('443774fc-dbd1-4da7-9cfe-d39c9c8c9d18','道中觀荷花','孔武仲','宋','宋诗','song-poetry','','[]','放棹東南去，正值荷花榮。',48,'全唐诗/poet.song.49000.json','["放棹東南去，正值荷花榮。", "玉質不待染，仙香無限清。", "朱朱仍白白，脉脉復盈盈。", "迢遞天風起，誰憐舞態輕。"]'),
('2476dfcd-e468-4a2c-b26d-74685ee628d9','與廖開甫自淮南同行赴舉相别二十五年復相遇於蘄水縣爲詩贈之','孔武仲','宋','宋诗','song-poetry','','[]','束書吾初走夷門，傾蓋得君恨不早。',240,'全唐诗/poet.song.49000.json','["束書吾初走夷門，傾蓋得君恨不早。", "蘭溪駐馬復相逢，二紀飛馳如電埽。", "惜君憔悴力不任，顧我滄浪髪先暠。", "憶昔同行氣頗驕，青驄馬快鞍韉好。", "荒山破屋風豪橫，大澤長堂雪傾倒。", "高談洒落見天機，健句縱橫濾腹藁。", "辛勤始得到京邑，文辭不入春官考。", "可憐六翮委沙泥，坐看群仙上蓬島。", "壯年多難寸心折，勁鏃已衰難破縞。", "而君施設有餘才，西佐元戎奪城堡。", "牛刀拂拭試一縣，如引滄浪灌行潦。", "歸來赴愬天子庭，正欲披腹呈瑰寶。", "片辭未吐疾先入，藜杖扶行色枯槁。", "籃輿復指天涯去，長川橫濫聲浩浩。", "驊騮不日歸王閑，那久低摧卧霜草。"]'),
('ece368c0-a40f-44ea-95a1-f3e6be8963b9','久長驛書事','孔武仲','宋','宋诗','song-poetry','','[]','空堂深深閃燈燭，羣奴鼾眠聲動屋。',64,'全唐诗/poet.song.49000.json','["空堂深深閃燈燭，羣奴鼾眠聲動屋。", "豆肥草軟馬亦便，嚼美只如蠶上簇。", "天事由來不可量，初更月出星煌煌。", "須臾變作霏霏雨，客枕不眠知夜長。"]'),
('8552d8f1-c7b7-47e4-ba0e-11ca97645b56','故縣作','孔武仲','宋','宋诗','song-poetry','','[]','促促遠行役，勞勞羣僕夫。',132,'全唐诗/poet.song.49000.json','["促促遠行役，勞勞羣僕夫。", "上漂以霖雨，下濺以泥塗。", "寒入骨脛裂，潤兼巾裳汚。", "行路何其難，我馬亦已瘏。", "逢人問前舍，指點山墻孤。", "投得數閒屋，慘寂日已晡。", "橫流正浩蕩，驚飇尚號呼。", "篝火就空室，排入如燕雛。", "投醪不及均，自酌以爲娛。", "箕踞不爾責，但願僵者蘇。", "亦有蘄春酒，汩汩傾淺壺。"]'),
('caaae016-8a40-4fe5-9749-0e3efd0aeb2a','白砂驛作','孔武仲','宋','宋诗','song-poetry','','[]','浮雲紛紛鏁太清，驟雨肅肅飛中庭。',172,'全唐诗/poet.song.49000.json','["浮雲紛紛鏁太清，驟雨肅肅飛中庭。", "冰虀脫粟冷徹骨，欲語寂然誰和譍。", "辭家十日心甚壯，今日始覺愁腸幷。", "僕夫聚首亦不樂，泥深灘密尤難行。", "長途何意此艱險，彼蒼其誰司晦明。", "閉門篝燈夜未久，試遶前楹望星斗。", "頑陰稍避避青冥，白月飛光臨户牖。", "推移變態俄頃間，坐使慘寂成歡顔。", "群奴喧喧亦相語，明日快馬臨關山。", "陰亦不可知，晴亦不可必。", "爾曹穩眠莫匆匆，清明更待東方白。"]'),
('449330d6-1fca-4195-8d47-3cc86f53735c','題鮑家鋪','孔武仲','宋','宋诗','song-poetry','','[]','郵亭秣馬朝寒天，雪雲壓山山湧泉。',64,'全唐诗/poet.song.49000.json','["郵亭秣馬朝寒天，雪雲壓山山湧泉。", "隴頭客饑欲噤口，屋底人閒猶鼾眠。", "敲門得薪感相濟，征衫如洗頼火然。", "江南亦有安栖處，却羡郵亭人穩佳。"]'),
('be939595-4fba-411b-b816-b9f20f619645','發光山','孔武仲','宋','宋诗','song-poetry','','[]','摇摇春霜草頭白，冰如龍蛇當轍迹。',144,'全唐诗/poet.song.49000.json','["摇摇春霜草頭白，冰如龍蛇當轍迹。", "天開日麗非偶然，昨夜滿山明月色。", "憶昨北走關山中，下坂還登百千尺。", "狂風虛霰何可當，破碎貂狐作巾幘。", "今朝驛道千里平，而况六幙俱空明。", "昔何艱險此何易，付予榮枯豈天意。", "人心既好馬亦驕，騰韁齧轡鳴蕭蕭。", "我今亦復歌且謡，惠相好者同遊遨。", "相與馳君之樂郊，從此不嗟衝涉勞。"]'),
('3064b6f0-6773-47d9-8a18-cd1e31b67d5d','至趙莊鎮捨轎乘馬二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','淮康望夷門，驛舍猶六七。',180,'全唐诗/poet.song.49000.json','["淮康望夷門，驛舍猶六七。", "我車嗟已勞，我馬亦太逸。", "朝來天色好，輝煥川上日。", "郊原莽而蒼，生意密如櫛。", "農飱頗順適，晝氣更盈溢。", "摳衣就鞍韉，前引以一卒。", "馳提曆灣紆，林木榮棗栗。", "豁然就平曠，天壤合爲一。", "稍過王務陂，陂長水波濶。", "驚風摇澎湃，鳬鴨語啾唧。", "却思在江湖，雙艣更輕疾。", "川陸雖不同，吾心兩無必。", "匆匆背鄉井，瑣瑣干禄秩。", "功名未及試，行役甘于蜜。", "安得擺覉牽，優游老蓬蓽。"]'),
('249de9da-7c42-4ba4-a1cf-f49ed23ea970','至趙莊鎮捨轎乘馬二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','晴郊漠漠翠烟浮，乘興閒登棗下騮。',32,'全唐诗/poet.song.49000.json','["晴郊漠漠翠烟浮，乘興閒登棗下騮。", "風色斗回成凛冽，却添貂帽擁駝裘。"]'),
('500757b1-b4d5-4cc4-806d-fe7a1370d42b','舍轎馬而步','孔武仲','宋','宋诗','song-poetry','','[]','嚴風駕雪霜，吾轎頗温燠。',216,'全唐诗/poet.song.49000.json','["嚴風駕雪霜，吾轎頗温燠。", "白日煖郊原，吾馬快馳逐。", "二者皆得用，翩如兩黄鵠。", "馬驕倦提策，轎狹厭攣束。", "何以救斯弊，奔馳有吾足。", "副之兩革靴，隨以一笻竹。", "鳬趨上高岡，虎步出平陸。", "折花得低枝，照影臨深谷。", "道逢田間叟，時訪以耕牧。", "北音稍入耳，俚語俄滿腹。", "行行及前堆，小汗已霡霂。", "芳草可爲茵，吾眠不須褥。", "人生忌太佚，終歳居華屋。", "醉飽耳目昏，軟暖筋骸縮。", "今吾異于此，千里干微禄。", "朝隨麏麞騁，夜侣鴻雁宿。", "户摳勞乃久，金礦鍛方熟。", "聊歌以自娛，不作楊朱哭。"]'),
('61a13088-8ba1-49b1-8df4-da401d993dbb','江晦叔見訪于興國寺見庭中修竹兩竿云竹雖不多而蕭騷可愛因贈之詩','孔武仲','宋','宋诗','song-poetry','','[]','憶昨在江都，聨君城一曲。',216,'全唐诗/poet.song.49000.json','["憶昨在江都，聨君城一曲。", "我家百色無，唯有數竿竹。", "琅玕淨相倚，蕭灑意常足。", "君亦時見過，笑語伴幽獨。", "别來七見春，屢送光景速。", "京師車馬煩，高塵蔽華屋。", "僧室日閉關，靜若在巖谷。", "忽聞剥啄聲，把手叙寒燠。", "嵌空疉石畔，亦有雙筠緑。", "動君青雲興，賞眄不移目。", "愛其蕭騷風，摇此蒼翠玉。", "有如嗜膾炙，久矣虛其腹。", "一旦逢割鮮，欣然喜如沃。", "乃知物外適，可以傲流俗。", "奉常官事簡，佳集時可卜。", "軒窗闢深邃，冠帯脫拘束。", "文枰稍拂拭，白黑看馳逐。", "更設茶兩旗，何須酒百斛。"]'),
('f4d30768-dd64-422a-beb1-cdedd3f4f87a','寄經父兄','孔武仲','宋','宋诗','song-poetry','','[]','我出亂山來，兄入亂山去。',84,'全唐诗/poet.song.49000.json','["我出亂山來，兄入亂山去。", "出山何必佳，匹馬紅塵路。", "入山勿辭勤，﨑嶇與天鄰。", "天門西北去，石眼行車輪。", "落盡江南柳，塞榆應知春。", "去去何時歸，天涯可寄衣。", "霜高鴻雁還，無使信音稀。"]'),
('c08a6768-2a96-493b-b38c-1aa23be5ba77','大風','孔武仲','宋','宋诗','song-poetry','','[]','昔遊江湖上，厭看無限不測之高浪。',324,'全唐诗/poet.song.49000.json','["昔遊江湖上，厭看無限不測之高浪。", "今栖塵土中，慣聽掀天拔木之狂風。", "風豪浪狠常相逐，我生此世宜阨窮。", "浪頭漫漫從海起，客舟摇戰如枯葦。", "回橰轉尾入深灣，往往三分偷得一分睡。", "豈如秋宜門東僦屋居，突兀前堂掌平地。", "風從崑崙溟渤來，平頭疾轉數千里。", "金鋒相磨衆鬼兵，介馬爭先萬胡騎。", "㨟搶震壓尤可驚，千妖百怪悲號聲。", "我時安眠不覺躩然起，爐烟寂滅燈冥冥。", "褰衣正欲走出户，户未開扃已吹仆。", "閉門正欲避風來，風入衣襟不肯去。", "天涯地角兩茫茫，一身渾無逃遁處。", "明朝撿點窗户間，浮埃委積如丘山。", "遥知九衢中，馬走廢往還。", "我欲投書訴風伯，帝閽峨峨不可攀。", "怒攜干將遶四璧，空有壯氣膨心肝。", "頗疑猛虎嘯林薄，慘淡陰威動寥廓。", "又疑土伯夜與風神爭，叱咤喑啞騁獰惡。", "明當折簡問巫陽，天上誰人司槖籥。"]'),
('6e09b245-4892-4167-b9df-97c7338aa74e','數詩分題二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','一邑臨襄漢，青衫正少年。',120,'全唐诗/poet.song.49000.json','["一邑臨襄漢，青衫正少年。", "二毛侵鬢髪，披霧始窺天。", "三接龍光遠，曈曨白日邊。", "四門方雜還，羔雁賁林泉。", "五斗安微禄，雖貧志浩然。", "六韜聊自試，有策佐平燕。", "七札穿强弩，諸君必凱旋。", "八荒馳貢篚，恩旨罷戈鋋。", "九九期君用，慚非命世賢。", "十官何敢望，於此卜歸田。"]'),
('3732bdc3-ec98-42bc-b694-74620c3fe8c0','數詩分題二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','一樽勸君飲，舉觴莫遲遲。',120,'全唐诗/poet.song.49000.json','["一樽勸君飲，舉觴莫遲遲。", "二月風景妍，都人正游嬉。", "三春已失一，胡不惜芳時。", "四郊更清曠，紅紫耀漣漪。", "五侯盛供帳，出以歌鼓隨。", "六龍西翺翔，迅速不可追。", "七澤起悲風，晚景含崦嵫。", "八音莫停奏，妙舞隨金絲。", "九門稍合鑰，莫時淚沾衣。", "十里燈燭光，醉矣各還歸。"]'),
('f07467e3-f211-458a-abea-b4dc468980eb','招竹元珍賞江洲新茶','孔武仲','宋','宋诗','song-poetry','','[]','我生世味薄，所好唯真茶。',264,'全唐诗/poet.song.49000.json','["我生世味薄，所好唯真茶。", "江南隔浮雲，廬岳望苦賖。", "煎烹逐風土，白水和脂麻。", "有客自遠至，開緘得新芽。", "乍見真邂逅，失喜成讙譁。", "掬視未及飲，清香破昏邪。", "堂堂京邑雄，萬貨來天涯。", "念此至靈草，﨑嶇亦隨車。", "小磨元自攜，瑩白無纎瑕。", "玉塵漸委積，鷹嘴猶交加。", "汲泉方汙埃，上以密葉遮。", "蟹眼已鳴沸，君來何晚耶。", "相呼共一啜，如到神仙家。", "煩襟得浣濯，兩目袪昏花。", "閒居無他樂，頼有此趣佳。", "煌煌金張門，酒肉爭豪奢。", "冷淡不輒飲，千金賞箏琶。", "一醒又五斗，顔角如烘霞。", "蔗漿爽肺肝，金椀嗽齒牙。", "坐覘吾曹癖，往往笑以嗟。", "人生樂不同，未用相矜夸。", "吟罷腹饑吼，空庭噪昏鴉。"]'),
('de924fe5-a3eb-4b07-aad4-fcdbba3d32d3','廣津倉檢視斛斗','孔武仲','宋','宋诗','song-poetry','','[]','長渠西來擬天漢，千里清陰緑楊岸。',192,'全唐诗/poet.song.49000.json','["長渠西來擬天漢，千里清陰緑楊岸。", "高墉傑屋如屯雲，碧瓦參差插天半。", "小樓三尺偷晨光，山低堆積白與黄。", "千艘一卸須臾了，江湖極目來帆檣。", "國家稅法擬前古，還以養人非自富。", "連雲習射皆貔貅，月禀太倉急風雨。", "歳深敝積如鼠穴，檢視之官緣此設。", "我初受牒頗激昂，匹馬朝朝踏殘月。", "千籌簇簇來如林，袍鞾兀坐清槐陰。", "秋毫増損必拘送，莫怨小官持法深。", "吾槩視此平如水，運量四海亦如此。", "今朝且佐大司農，他時敢獻明天子。"]'),
('d94a44c5-5fca-4777-8d4b-49eb9a4549a4','送元珍赴官合州','孔武仲','宋','宋诗','song-poetry','','[]','羈旅倦京國，春風常閉門。',180,'全唐诗/poet.song.49000.json','["羈旅倦京國，春風常閉門。", "叩門誰過我，云是竹王孫。", "頎然八尺長，玉質文理温。", "探之以羣書，浩渺傾崑崙。", "餘波濯我熱，挹取不計盆。", "朝落清風窗，暮埽明月軒。", "傲兀足真趣，不隨車馬喧。", "動可與俱遊，靜可與忘言。", "胡爲捨我去，獨指岷江源。", "偪側鳳翔西，叠嶺如駿奔。", "滔滔蜀天漏，沉沉山月昏。", "到官復何時，清秋禾黍翻。", "冷局自少責，讀書勿忘餐。", "登臨時自適，吟思攪乾坤。", "魚雁若可託，篇詩寄湘沅。"]'),
('180c2423-254b-4952-ba30-a3fa12e502a5','送李大夫管勾太平宫居袁州','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','康定慶曆披羣英，公爲布衣歌太平。',224,'全唐诗/poet.song.49000.json','["康定慶曆披羣英，公爲布衣歌太平。", "熙寧元豐王道興，公作太守逢休明。", "四十年間走四海，崛然不肯干公卿。", "峨峨正議天柱壯，皎皎素節冰壺清。", "胸中慨慷外間易，年高未見白髪生。", "罷節巴陵歸意銳，奈何去就不敢輕。", "馳歸天寵乞閒避，諸郎惜祿猶屢爭。", "毅然不與兒女計，飛章丹扆論赤誠。", "明朝果得琳宫去，匡廬山色遥相迎。", "玉溪氣象自瀟灑，新磨古鏡當霄橫。", "修篁萬竿飽霜雪，枯棋一局酒滿觥。", "時邀賓朋叙野史，間擁雪鶴登岩扃。", "妄排丹鼎夜不寐，邂逅黄金燒可成。", "未應謝傅入滄海，行見盧敖朝玉京。"]'),
('198792dd-6f96-4c9e-87e9-028a21f432ce','代簡别林次中','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','常思洞庭湖，夢想東南游。',168,'全唐诗/poet.song.49000.json','["常思洞庭湖，夢想東南游。", "浩渺七百里，控带三五州。", "霪霖稍開霽，萬頃涵新秋。", "此時登臨勢，併在岳陽樓。", "水天兩琉璃，瑩濶相沉浮。", "爽氣動林木，無風亦颼飀。", "願言追壯觀，兩漿推輕舟。", "何異泛滄海，便可掛浮丘。", "前日到君家，日暮空回舟。", "徑遣長鬚來，見邀頗綢繆。", "謂此千里别，一散未易收。", "相去况咫尺，能上河梁不。", "顧我行役長，感君風義遒。", "好在更加飱，行子不可留。"]'),
('adbf1053-9144-4643-a077-8cd48c0db75b','代簡答次中見留','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','詩誇洞庭湖，蓋舉其麤爾。',168,'全唐诗/poet.song.49000.json','["詩誇洞庭湖，蓋舉其麤爾。", "自此稍南行，更有瀟湘水。", "瀟湘如此流，淺深清見底。", "吾邑在其旁，桑麻百餘里。", "民經南巡後，淳龎猶可喜。", "白酒日相沽，鱸魚夜成市。", "念方從吏隱，小官不爲耻。", "先期了賦租，隨時用鞭箠。", "此外無餘事，看山聊隠几。", "還作小詩篇，寄聲前御史。", "御史吾故人，風義今爲偉。", "超遷未復甚，久仆行復起。", "但使交期在，不須論遠邇。", "今夕宿朱仙，相望月明裏。"]'),
('baa1160d-60b8-4b0c-ad64-7a8bf3a0adf2','時雨','孔武仲','宋','宋诗','song-poetry','','[]','空車輾雷幟推電，千里冥冥甘雨遍。',80,'全唐诗/poet.song.49000.json','["空車輾雷幟推電，千里冥冥甘雨遍。", "元豐嘉號卜長年，太乙尊神宅畿甸。", "齋宫夜禱天俯聽，美澤朝流慰人願。", "豆苖蓬蓬粟低垂，土脉舒蘇蝗不飛。", "野老謳歌忘帝力，夕陽相與荷鋤歸。"]'),
('ab580dbd-4bb0-47ef-99c0-cb7356e7fbd2','雨中','孔武仲','宋','宋诗','song-poetry','','[]','大雨已滂流，小雨仍霡霂。',48,'全唐诗/poet.song.49000.json','["大雨已滂流，小雨仍霡霂。", "風來掃欲斷，雲送還相續。", "凝陰壓天宇，蒸潤浸旅服。", "隴上麥經秋，江南梅已熟。"]'),
('52c70b7b-b9bb-4b8a-8414-73809327429f','蔡州三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','愁雲昏昏掩六月，電光霍霍盤四隅。',240,'全唐诗/poet.song.49000.json','["愁雲昏昏掩六月，電光霍霍盤四隅。", "淮西一雨三晝夜，長瀾積潦無處無。", "試登高樓望四野，平田渺渺成江湖。", "山源奔溢來處遠，晨朝又報高丈餘。", "重闉閉築僅自守，一带縈疊何其孤。", "頽墻處處若山壞，百舍相望無完區。", "辛勤買得稭一束，馬饑况乏粟與芻。", "三十年間走四方，始遭此厄真窮途。", "跧居丘亭往來斷，時起顧是青雲衢。", "如絲一罅見天面，頑陰復起相糢糊。", "幽憂填胸不自遣，强扣瓦缶傾殘壺。", "醉中暫爾神氣王，醒定更覺心摧枯。", "城陰老蛙正逸樂，聲如轉軸相鳴呼。", "强弓毒矢未易射，欲殺唯有企翁符。", "吾家此去八十驛，愁來更展江湖圖。"]'),
('1cfc8b46-1eb2-4863-a3c4-82158959abff','蔡州三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','狂霖出羣山，夜半擊堤口。',144,'全唐诗/poet.song.49000.json','["狂霖出羣山，夜半擊堤口。", "水橫溢陵阿，餘波猶怒吼。", "東村五百户，一塌如摧朽。", "硉兀聲如雷，牛馬不及走。", "壯者上枝柯，幼子浮罌缶。", "驚逐吞天瀾，兒猶闖其母。", "旁人避形迹，睨視誰敢救。", "凍餒何足言，餘生豈能久。", "人云淮西水，如此昔未有。", "我生真厄窮，出與此災偶。", "晨興得枯槎，泛若上牛斗。", "獨濟恐難安，人危敢援手。"]'),
('4d1b905c-1aa9-45a2-845f-72c01bd0b8f9','蔡州三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','行路難，歸去來。',134,'全唐诗/poet.song.49000.json','["行路難，歸去來。", "三日汝南城不開，天角隱隱聞輕雷。", "掣電更劃劃，猛雨還漼漼。", "稍添汪汪陂，漸淹高高臺。", "我欲晨興出南郭，極目唯有白水漫蒿萊。", "驛道安在哉，連山洑流相喧豗。", "父母不復顧，嬰孩棄之如塵埃。", "戢戢生魚頭，人世永隔良可哀。", "清都咫尺可以訴，誰挽北斗魁。", "嗚呼行路之難，邦人之災。"]'),
('3f581e9b-f796-4123-a76f-74fbdf0b5ae4','劉公詩','孔武仲','宋','宋诗','song-poetry','','[]','原甫吾不識，聞之士大夫。',252,'全唐诗/poet.song.49000.json','["原甫吾不識，聞之士大夫。", "少時已絕羣，卓犖千里駒。", "讀書足智慮，萬卷力有餘。", "善發六藝藴，高談詆先儒。", "天文地理學，道藏及浮屠。", "纎悉無不講，講之皆粲如。", "文章弄豪贍，咳唾玉與珠。", "避落八極間，買者論錙銖。", "爲人又挺特，不與俠者俱。", "伉健虎獨步，軒昂鶴仍孤。", "身雖登兩禁，未及秉鈞樞。", "爽氣隨沆瀣，斂收入清都。", "嗟嗟劉夫子，信是荀揚徒。", "冨貴非窮愁，而復多著書。", "荒城過宿雨，古寺入平蕪。", "鬱鬱壁上詩，奎鈎照天衢。", "我來值日暮，篝火爲踟蹰。", "想見其風骨，磊落眉宇踈。", "邦人好事少，不以玉石摹。", "歳月更久遠，彫摧逐泥塗。", "作詩貴述美，聊用贊不渝。"]'),
('01308674-2ee6-4c93-bcdb-890ca551c77a','入關山','孔武仲','宋','宋诗','song-poetry','','[]','輕輿兀兀乘朝暉，漸入山徑行逶迤。',176,'全唐诗/poet.song.49000.json','["輕輿兀兀乘朝暉，漸入山徑行逶迤。", "昨日喜與山相見，今日得與山相隨。", "山中老翁迎我笑，借問久矣來何遲。", "答云王都冨且樂，四方車馬皆奔馳。", "我雖踈慵亦勉强，天恩得邑方南歸。", "山林朝市不同調，公雖高？宜無譏。", "老翁聞語更驩意，爲我煮水燒松枝。", "山家十錢得升酒，勸我引觴聊沃饑。", "爲翁一奏白雪曲，翁亦爲我歌紫芝。", "此聲淡泊極有味，往往世俗無人知。", "山中之樂有如此，嗟我捨此將焉之。"]'),
('c2f6eb37-2fa2-4229-922f-2d33744d6cc7','新安鋪三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','罩罩澗中草，泠泠山崦泉。',40,'全唐诗/poet.song.49000.json','["罩罩澗中草，泠泠山崦泉。", "泉甘而草芳，旁有屋數椽。", "夕陽漸近西風起，行客山頭望千里。"]'),
('6c8c96b5-71ff-44bc-a618-5b0affb8950f','新安鋪三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','薄雲斜日亂山川，投得荒亭晚息肩。',32,'全唐诗/poet.song.49000.json','["薄雲斜日亂山川，投得荒亭晚息肩。", "地僻誰知藏好景，庭前花數折金錢。"]'),
('eee1da86-a591-42fc-bba9-c4cdc80b64ae','新安鋪三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','簟如秋水憩回廊，素月分輝百倍凉。',32,'全唐诗/poet.song.49000.json','["簟如秋水憩回廊，素月分輝百倍凉。", "山木交加無意緒，故教疏影到人床。"]'),
('7f13a7e0-32df-4c64-8930-027b26a8f91e','晝息于林下','孔武仲','宋','宋诗','song-poetry','','[]','大暑涉長川，前山後山深。',108,'全唐诗/poet.song.49000.json','["大暑涉長川，前山後山深。", "忽逢輪囷木，投得數畝陰。", "僕夫六七人，卧起且呻吟。", "念爾亦太勞，獨佚我何心。", "試爲蘇門嘯，泠泠鸞鶴音。", "遺聲滿坑谷，爽氣回中林。", "松風爲之興，凉冷破煩襟。", "神骨斗醒快，炎蒸豈能侵。", "安得冩此懷，寄之朱絲琴。"]'),
('29546bd3-b3b0-488b-9b14-b9d843adeebf','途中大熱','孔武仲','宋','宋诗','song-poetry','','[]','促促客行遠，悠悠山路長。',132,'全唐诗/poet.song.49000.json','["促促客行遠，悠悠山路長。", "南歸當六月，復值此驕陽。", "祝融秉炎火，清曉升扶桑。", "流焰鍛地精，兀兀馳澗岡。", "籃輿如入焙，坐席似探湯。", "睛瞳熨不醒，背汗雨洋洋。", "否悶幾至死，忍渇尚傍徨。", "願借萬里雲，蔚蔚排穹蒼。", "護彼三足烏，潜行天中央。", "繼之以冷風，淅淅吹衣裳。", "豈獨一身輕，與物共清凉。"]'),
('db7a019e-63e0-4f6a-bf89-2d67cb121706','寄信州交代錢德循','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','處君以西軒之爽氣，贈君以仙府之名花。',190,'全唐诗/poet.song.49000.json','["處君以西軒之爽氣，贈君以仙府之名花。", "名花芬敷隨曉日，爽氣蕭颯凌朝霞。", "山川從此增秀色，塵埃不復留君家。", "羨君年少氣力銳，况有長才可經世。", "馳聲京邑蓋有年，作幕山州不得意。", "漫尋幽景養天真，積明不學陶潜醉。", "錢夫子，我今去指湘江邊，洞庭波瀾濶如海，與君似隔東南天。", "饒州亦有木犀種，真骨來從武夷洞。", "自有清香百步聞，煩君爲買雙株送。", "勿云千里移致難，從古物輕人意重。", "但將木李對瓊瑶，餘物區區且安用。"]'),
('c2cf8374-1f30-4361-b302-ecd83e3da565','湓城東','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山之岑岑，橫絕東南天。',108,'全唐诗/poet.song.49000.json','["廬山之岑岑，橫絕東南天。", "大江之湯湯，洲渚相鈎連。", "山水兩中間，君家之故園。", "憶昨别此去，春風初破年。", "歸來已秋節，登覽怳依然。", "萬里一轉蓬，四時真蛻蟬。", "退無環堵宫，長逐車與船。", "風景日愈佳，塵埃日纒綿。", "人事正浩蕩，徒勞賦歸田。"]'),
('81195b2e-b78b-47f5-a069-274ee4758d3e','喜雨','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','暑伏忽已盡，金風稍自秋。',144,'全唐诗/poet.song.49000.json','["暑伏忽已盡，金風稍自秋。", "驕陽仍不戢，歳計實可憂。", "昊天雖甚高，聰聰徹九州。", "聞其憔悴聲，知此黎民愁。", "白日収赫赫，慘雲布油油。", "昨朝雨意足，來自匡山頭。", "稍添郭南坡，次及城西疇。", "入夜又滂沛，四境略已周。", "平明出東郭，翠畝連山丘。", "爽氣吹客襟，餘聲壯溪流。", "自此飽香秔，可以繼麥麰。", "聊爲拊髀歌，以代擊壤謳。"]'),
('845f0239-44f1-493b-8e42-9cb93fcee114','白公草堂','孔武仲','宋','宋诗','song-poetry','','[]','達士因忘世，非求高尚名。',72,'全唐诗/poet.song.49000.json','["達士因忘世，非求高尚名。", "林泉得佳處，風物有餘清。", "貝錦傷讒舌，浮雲寄宦情。", "詩才今古備，性理死生明。", "蓮沼秋芳合，香山晚翠橫。", "黄蘆繞官舍，不復念青城。"]'),
('d5c0ccac-8087-4287-94af-3a62cfad705a','宿天池','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我思廬山遊，發興自年少。',204,'全唐诗/poet.song.49000.json','["我思廬山遊，發興自年少。", "偶來得閒侣，更欲窺衆妙。", "幽林穿蒙籠，青峰上嶮峭。", "遥看天池路，一線在巖徼。", "辛勤得至此，慘寂已西照。", "雲池桂無根，瞪視心膽掉。", "暮夜煙雲昏，西巖亦登眺。", "聖燈稍稍出，弄影何窈窕。", "一枝分百點，變態不可料。", "須臾歸寂滅，何處觀朕兆。", "僧房得栖宿，爽氣冰毛竅。", "翻然亦興盡，却恨歸途窵。", "緬懐道隆師，確不奉明詔。", "似與山間石，慇懃論久要。", "我今來時迫，心灰真可笑。", "明朝指繡谷，裹足登凉轎。", "揩却壁上名，恐爲高人笑。"]'),
('5026c528-326b-486f-aab9-fed53fef3331','卧龍潭','孔武仲','宋','宋诗','song-poetry','','[]','已登卧龍庵，更看卧龍瀑。',120,'全唐诗/poet.song.49000.json','["已登卧龍庵，更看卧龍瀑。", "來從不盡山，奔入無底谷。", "谷中鳴百雷，林外潄寒玉。", "雄豪與清泚，上下相接續。", "陽崖發幽花，陰壑偃喬木。", "兩崖天劃開，萬古神潜伏。", "我來坐潭上，俯仰清耳目。", "神骨倍瀟灑，衣襟仍霡霂。", "名山到能幾，好景看不足。", "慇懃莫思歸，更共潭邊宿。"]'),
('9610f6f8-ed9e-42ba-b2f8-7dd894be63c0','二賢','孔武仲','宋','宋诗','song-poetry','','[]','羲之之墨池，淵明之醉石。',92,'全唐诗/poet.song.49000.json','["羲之之墨池，淵明之醉石。", "人生嗜好亦天然，豈顧書淫與酒癖。", "一時聲價動宇宙，千古林泉記蹤跡。", "書固吾不能，酒亦久不喫。", "支笻葱翠畔，鑑影泓澄側。", "蕭然欣會間，頗類師也辟。", "所慕不靳能，舍此山南宅。"]'),
('a212b08a-e031-4f72-b630-60d343e087e2','磁湖安流亭','孔武仲','宋','宋诗','song-poetry','','[]','怪石倚洪流，朱欄截荒磴。',132,'全唐诗/poet.song.49000.json','["怪石倚洪流，朱欄截荒磴。", "來窺空曠野，喜值波瀾定。", "涵虛無邊裏，見底皆淥淨。", "磁湖萬家會，華閣相輝映。", "雙峰引西洑，控帯浮郭盛。", "乃知一聚落，富庻亦有命。", "鐵冶今久貧，豪右蓋已病。", "憶初締造人，有力如卓鄭。", "瑰材照密石，歳久尚鮮瑩。", "俛仰正忘歸，白日動明鏡。", "風順當進帆，徘徊寄孤詠。"]'),
('9aa7348d-6cf5-41ee-83fb-4a35069726c9','寄題王道祖秀光亭','孔武仲','宋','宋诗','song-poetry','','[]','徙倚望西南，秀色如可掬。',72,'全唐诗/poet.song.49000.json','["徙倚望西南，秀色如可掬。", "湘水蹙纎羅，湘山叠明玉。", "清輝來西隅，朝爽浮萬屋。", "圖冩卒難成，登覽常不足。", "會計當而已，廉吏當寡欲。", "蕭然忘軒冕，日可娛幽獨。"]'),
('89e161e2-1da5-41e2-b936-9c1fd89c8d0b','西堂假山','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','范蠡不歸吳，魯連東泛海。',180,'全唐诗/poet.song.49000.json','["范蠡不歸吳，魯連東泛海。", "當其縱目時，長有青山在。", "我今囚一官，宅舍不容改。", "塵囂日侵陵，視聽乏爽塏。", "天機能幾何，與物相葅醢。", "當求景物凈，以滌身心凂。", "縣南山不遠，溪口石可採。", "叠累亦成形，依稀聊自紿。", "寒餘洞泉脉，緑帯天邊藹。", "翠壁漸孱顔，奇峰何𡾊嵬。", "喬林相隱映，亭院生光彩。", "笑揖浮丘翁，霓旌如可待。", "區區浹時力，直欲凌真宰。", "稍全仁者樂，未恤兒軰駭。", "又動江南思，匡廬田已買。"]'),
('fbbbe428-6bf5-46fe-b1cf-ae816713a3c7','寄題經父萱堂','孔武仲','宋','宋诗','song-poetry','','[]','萱堂有秋花，對客如勸侑。',228,'全唐诗/poet.song.49000.json','["萱堂有秋花，對客如勸侑。", "人生本多事，更以百憂副。", "愔愔橫天壤，擾擾迷刻漏。", "傾地救海涸，掲柱支山仆。", "徒將一心淑，日與萬慮鬭。", "不如偷餘閒，來此玩孤秀。", "熒熒千明缸，照映相前後。", "凝氣粲如笑，泣露亂欲溜。", "頽然寓遠懷，可以消永晝。", "吾兄儒林傑，器業包宇宙。", "﨑嶇從遠宦，爲國警邊候。", "飛沙蔽城隍，積雪冷襟袖。", "頗思東南州，水竹兩幽茂。", "樓臺壓江濤，窻户排雲岫。", "翹瞻不可見，夢想勞頭脰。", "樊籠送飛鴻，檻井看騰狖。", "暫憑時景佳，寛此腰圍瘦。", "吾儕所至樂，未厭夷居陋。", "賓侣時可邀，從容醉方酭。"]'),
('50eee0bd-9f3d-407a-a550-84caba6af569','尋真觀','孔武仲','宋','宋诗','song-poetry','','[]','武皇車駕東南出，訪道求仙希萬一。',128,'全唐诗/poet.song.49000.json','["武皇車駕東南出，訪道求仙希萬一。", "屏風九叠雲物清，意恐神仙藏此室。", "羽章之館締構新，壇塲夜夜祈星辰。", "蓬萊縹緲不可到，橋山一閉逾千春。", "詠真之天在旁側，白晝潭心飛霹靂。", "田收歳美龍亦閒，唯有濟瀹照空碧。", "誰道尋真是女郎，朝飡松桂夜焚香。", "明眸緑髩今何在，意已霞衣侍玉皇。"]'),
('18239543-47c0-4972-bac9-9305894bf483','松上老藤','孔武仲','宋','宋诗','song-poetry','','[]','古木已昂藏，長藤亦奇怪。',108,'全唐诗/poet.song.49000.json','["古木已昂藏，長藤亦奇怪。", "潛根蒼蘚中，矯尾青雲外。", "嚴嚴秋霜剥，悠悠夏景曬。", "摧殘復長養，鍛錬成老大。", "蛇蟠筋脈壯，龍死軀殻在。", "他時雷破山，大雨洒滂沛。", "兹松若變化，無乃遭結襘。", "附枝物所患，奪朱古爲戒。", "何不淬斧斤，誅鉏此蕭艾。"]'),
('414413da-e012-4901-bd37-aa8e18277c49','高臺歌','孔武仲','宋','宋诗','song-poetry','','[]','廢地積爲冡，昔曾遊宴來。',56,'全唐诗/poet.song.49000.json','["廢地積爲冡，昔曾遊宴來。", "冡廢無子孫，東家砌成臺。", "臺雖平方冡雖秃，物理廢興有往復。", "相逢莫喜亦莫愁，乘興且同臺上遊。"]'),
('847b07a8-d1b3-4834-92c4-465df19bcc71','種粟行','孔武仲','宋','宋诗','song-poetry','','[]','大兒肩鋤出茅屋，小兒傾盤糝新粟。',54,'全唐诗/poet.song.49000.json','["大兒肩鋤出茅屋，小兒傾盤糝新粟。", "春來雪稀雨不成，田雖翻犂苦未足。", "嗚呼農人今向太平年，安得甘雨一洒萬物皆醒然。"]'),
('ef9cc6b7-3a3e-4923-a52a-d0ad00ba7dfe','賦張芸叟蕃刀','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','王師前年下靈州，先生奉詔爲參謀。',352,'全唐诗/poet.song.49000.json','["王師前年下靈州，先生奉詔爲參謀。", "軍書堆案不足道，欲斬名王懸髑髏。", "官供器械如山積，裝結雖巧體質浮。", "傳聞蕃刀最可用，買置不惜千金酧。", "沙河洗湔血痕盡，瑩若一水横清秋。", "長庚輝輝奪明月，光景迸溢不可收。", "軍回倉卒未及試，提挈萬里來荒陬。", "空齋倒掩閲圖史，深林永日號猩𪕋。", "揮鳴且欲驚暴客，敢議與國平寃讐。", "夜郎蒙恩放李白，炎嶺得旨還幽求。", "輕船共泊長沙岸，幾日對語清湘樓。", "紅蓮幕中邀客飲，霧雨咫尺迷汀洲。", "雜花落盡無處覓，官妓遣歸不敢留。", "清歡未免假外物，共說鐵劍勝倡優。", "君家所寶世稀有，滿坐傳看驚殊尤。", "護之太過却銹澁，頑蘚鬱結纒蒼虯。", "横磨十萬祇虚語，得此已足馳燕幽。", "今公又應元戎辟，真能寸截鯨鯢不。", "郗生入幕宜有畫，定遠出塞將封侯。", "我今喜得隨君去，長江渺渺平天流。", "路危或恐逢水怪，尾脊崔崒當吾舟。", "煩公一効佽飛勇，爲公椎鼓傾金甌。"]'),
('3b95fae3-9b3a-443a-b5ba-d47ed382508d','張秉叔出紫雲回鑾圖以示坐客因爲賦之','孔武仲','宋','宋诗','song-poetry','','[]','開元太平無兵戎，真人味道希夷中。',144,'全唐诗/poet.song.49000.json','["開元太平無兵戎，真人味道希夷中。", "人間之樂已饒足，惟有青霄未追逐。", "坐中誰似葉先生，以氣爲糧常辟穀。", "朝登員嶠夕崑崙，只與神遊不要人。", "忽逢邀攜看月去，縹緲虚空生紫雲。", "蟾宫竟不容久住，仙樂飄飄送回去。", "歸來宫漏未移更，甲帳明釭宛如故。", "汾水悲歌仙不成，梨園空沒有遺聲。", "紅塵如海漲朝市，從此無人遊玉京。"]'),
('23d59e17-a3ce-4934-b6fd-27eb62473a1b','徐成之園亭三詠 瑞香檻子','孔武仲','宋','宋诗','song-poetry','','[]','異國攜來看愈新，移當樽俎會嘉賓。',64,'全唐诗/poet.song.49000.json','["異國攜來看愈新，移當樽俎會嘉賓。", "雖無絕艷驚流俗，爲有清香得近人。", "燭下更宜觀態度，酒闌尤覺醒精神。", "湖南莫作淹留歎，已見潯陽二月春。"]'),
('d85adc07-2c56-4db2-85b8-a8d22665fee3','徐成之園亭三詠 竹逕桃花','孔武仲','宋','宋诗','song-poetry','','[]','闢地不盈畝，點綴成阻修。',48,'全唐诗/poet.song.49000.json','["闢地不盈畝，點綴成阻修。", "相招竹林逸，更作桃源遊。", "綽約新飲露，琅玕曾倚秋。", "春風蕩人意，此境獨清幽。"]'),
('22f61821-81eb-49f2-9179-d07f854d8aae','徐成之園亭三詠 石盤','孔武仲','宋','宋诗','song-poetry','','[]','攻玉爲方盤，可據以飲食。',96,'全唐诗/poet.song.49000.json','["攻玉爲方盤，可據以飲食。", "又可安文枰，兩仙相對奕。", "簿書應接罷，胥不留蹤跡。", "散步到其間，如臨蒼山壁。", "下有清冷波，灔灔欲侵席。", "坐兼仁智樂，豈獨煩襟釋。", "長沙春正妍，樽酒會嘉客。", "好事清河翁，題名刻之石。"]'),
('18163cbb-de5e-4386-8fe7-948976324c50','寄題徐亭','孔武仲','宋','宋诗','song-poetry','','[]','清晨讀君碑，如到徐亭下。',132,'全唐诗/poet.song.49000.json','["清晨讀君碑，如到徐亭下。", "靈境猶縹緲，仙風已瀟洒。", "亭雖人爲之，洞是天開者。", "化工不自了，待子闢蓁野。", "徐君神骨不埃塵，疏眉秀目方青春。", "窮追屢束冦賊手，幽討却作煙霞人。", "當年遠祖嘗浮海，採藥仙山竟何在。", "君今復探山中奇，潭潭六室世未知。", "嗚呼安得此亭此洞在吾鄉，廬岳自此増輝光。"]'),
('0f33e835-0a84-40dc-baac-f144ff3cdc99','祠二廟之明日未得順風呈同行','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','岳州西祠從古有，控带洞庭湖之口。',214,'全唐诗/poet.song.49000.json','["岳州西祠從古有，控带洞庭湖之口。", "前對隠顯明滅之湘山，下接淵淪洶湧之長川。", "茫茫白沙連絕嶼，淡淡古木蟠蒼烟。", "昭靈王，左安流，右翠帳，朱幡擁前後。", "鋸牙虎視森兩廂，氣骨生獰欲奔走。", "我來纜舟日已昏，袍鞾跪聽祠官言。", "伏興進退如法式，四頋詭譎驚心魂。", "平明結束舟將解，叱吸仍聞北風大。", "焚香奏酒殊無計，伏渚藏汀姑有待。", "二王威神世所傳，鈐攝鬼怪賓靈仙。", "好風相送勢不難，舒卷造化須臾間。", "波回草動似有意，舉棹開帆即千里。", "吟詩賞月岳陽樓，買魚沽酒巴陵市。"]'),
('a8e901ab-38f3-4bc6-95e7-86ef2ab19392','廟下候風呈同行','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚水千百源，洞庭爲壯觀。',240,'全唐诗/poet.song.49000.json','["楚水千百源，洞庭爲壯觀。", "勢居七澤右，地裂荆吳半。", "而我泛扁舟，飄然一歸雁。", "來之豈爲益，去亦未足算。", "胡不吹清波，縱發如飛翰。", "朝辭廟山曲，午泊巴陵岸。", "况有三面風，迎送俱無間。", "定非偏薄厚，以掇行旅訕。", "奈何苦流滯，兀兀晨復旰。", "采芹朝當蔬，伐竹暮供爨。", "舟師三十人，餓虎奔芻豢。", "使之裹糧絕，慮有探囊患。", "二王東南望，貌像頗輝煥。", "歌鼓歲無休，香燈夜侵旦。", "我爲江湖士，乞靈從弱冠。", "四到祠宫下，霜髯今已燦。", "王其故舊卹，勿以塗人看。", "尊師况慈忍，善道陰有賛。", "王心或未回，師頰固宜緩。", "靈珓似見許，歸來整檣幔。"]'),
('20121ae5-bbc1-4d16-82c3-b5390b5c96cf','登君山二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','徑欲涉方壺，滄溟何太遠。',48,'全唐诗/poet.song.49000.json','["徑欲涉方壺，滄溟何太遠。", "試登君山杪，直望蒼梧晚。", "寂無纎塵動，迥快千里眼。", "勝境真少倫，仙山連禁苑。"]'),
('d9f19084-5fdb-4c79-af79-874d3a8e54c0','登君山二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','楚水吞東南，皤然天一腹。',48,'全唐诗/poet.song.49000.json','["楚水吞東南，皤然天一腹。", "君山枕波面，半插蛾眉緑。", "平空接遊氣，杳蕩無川陸。", "歸槳恨匆匆，殘陽挂喬木。"]'),
('c00a7cd2-5cfd-4e8b-b4ae-ed43bbe50a7f','武昌縣西山寺','孔武仲','宋','宋诗','song-poetry','','[]','吳王宫殿西山頭，蕭蕭爽氣長如秋。',176,'全唐诗/poet.song.49000.json','["吳王宫殿西山頭，蕭蕭爽氣長如秋。", "武昌連都甚偪仄，頼有此山供勝遊。", "東南豪傑俱故舊，當年孝廉孫仲謀。", "一朝名號僣九五，朱紫羅列皆公侯。", "驩娱應似河朔飲，縹緲宜有雲端樓。", "危絃脆管落天上，飲散咸入西江流。", "而今寂寞皆陳迹，遍地松竹清陰浮。", "巖泉滴瀝醒四座，相見環珮鏘琳球。", "龍泉寶氣亦消盡，磨劍只有空池留。", "老僧向我說遺事，興廢反覆令人愁。", "但當沈酣卷大白，徐趁明月牽歸舟。"]'),
('d90337bd-4007-42f0-8625-01edf04eb35d','同年兄袁思正江行相遇既别寓詩寄懐','孔武仲','宋','宋诗','song-poetry','','[]','楚水緑涵天，羣山靄而秀。',168,'全唐诗/poet.song.49000.json','["楚水緑涵天，羣山靄而秀。", "君行當何之，我謁慚已後。", "輕舟翻然來，喜氣瀉襟袖。", "問知道途遠，驚我形容瘦。", "駸駸光景馳，暮夜逐清晝。", "嵩衡猶可秃，鬚鬢豈長茂。", "惟其寸心在，皎日經宇宙。", "持蓀可相慰，不必傾醇酎。", "君家多冠冕，煜煜五公胄。", "聲華滿天都，名字在英彀。", "登科况肩隨，兩紀詞塲舊。", "誰云班荆樂，却歎掺袪驟。", "荆民日安堵，漢政多寛宥。", "飲酒祝無何，千篇遲歸奏。"]'),
('16a47a9a-ec91-4394-b7b8-d9322eabafa6','留題攬秀亭','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生愛湓浦，亦復思匡廬。',60,'全唐诗/poet.song.49000.json','["平生愛湓浦，亦復思匡廬。", "恨無謝公屐，日與佳景疏。", "茲巖特曠快，一覽已有餘。", "驟雨過軒檻，清風來綺疏。", "因懐騎鯨客，更欲凌空虚。"]'),
('6bdd16d9-40d3-4667-a667-2a303ff73dd8','自寶嚴入太一宫','孔武仲','宋','宋诗','song-poetry','','[]','蔚蔚山間松，泠泠山下泉。',84,'全唐诗/poet.song.49000.json','["蔚蔚山間松，泠泠山下泉。", "相遇復一時，小别已三年。", "松色愈深翠，泉意自潺湲。", "惟余不如昔，正憂世事煎。", "安得散萬慮，卷收歸自然。", "童顔替癯貌，緑髪换圓顛。", "因召杏壇叟，去拍洪崖肩。"]'),
('5b4d1d77-01e3-4f55-98ac-dffbf95382ff','炭步港觀螢','孔武仲','宋','宋诗','song-poetry','','[]','九華之南蘆葦長，流螢夕起不計雙。',64,'全唐诗/poet.song.49000.json','["九華之南蘆葦長，流螢夕起不計雙。", "爛如神仙珠玉闕，青羅掩映千明釭。", "空江沉沉未見月，近浦穿林起還滅。", "魚遊鳥宿自不驚，我知此火初無情。"]'),
('2d1b6cba-77fc-4f4d-b7e3-fafc76f424ed','彭澤縣','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西江之水何悠悠，下與江南爲一州。',312,'全唐诗/poet.song.49000.json','["西江之水何悠悠，下與江南爲一州。", "□□□□□□□，正以彭澤爲襟喉。", "千川百谷所合庾，盡傾此澤如盃甌。", "鳴聲唶唶光油油，不知其下有底不。", "昔人有卷長繩投，繫以南山之巨石，百尺不徹深潭湫。", "□□□□□□□，頗疑潜行通十洲。", "不然何此彈丸地，吸彼尾閭曾不休。", "城南十里山更稠，如立象馬如驅牛。", "下飲長江勢不竭，無始以來向東流。", "旋灣觸抵勁且遒，虎眼倒射驚沙鷗。", "黿鼉雖輕不能游，而况往復之行舟。", "下水從容勢猶可，上水辛勤人更愁。", "祠神皆以北風求，不爾豈但須臾留。", "天公頗知元元憂，胡不推山作平地，兩闢旁野爲通溝。", "征行萬里皆帖妥，靈揚之威從可收。", "陰官聞我言，駭汗盈臂韝。", "洒爲猛雨沃四野，驚雷夜震波瀾滮。", "我舌閣且凝，久病竟不瘳。", "强爲短歌題柿葉，欲憑雙鯉寄陽侯。"]'),
('675433dd-c407-4cfb-ad72-7eb72bb4723c','泊趙屯','孔武仲','宋','宋诗','song-poetry','','[]','憶昨省覲趨𤃩川，萊衣擁緑方少年。',332,'全唐诗/poet.song.49000.json','["憶昨省覲趨𤃩川，萊衣擁緑方少年。", "艱難險阻俱未歴，孟浪勇决唯争先。", "舟發趙屯猶未飯，有風北起空濛間。", "掀搖三山簸五岳，巨浪倒潑東南天。", "千林向人俱頓仆，兩岸過眼真飛鶱。", "帆檣迴戞河漢底，鷁首俯飲蛟龍淵。", "跳波濺沫來四面，坐中時得鯉與鱣。", "妻啼婢訕殊不頋，兀坐正讀逍遙篇。", "爲言方破萬里浪，不爾捉月爲神仙。", "江中逢巨石，頗突爲引牽。", "逡巡水勢亦平緩，幸免肝脛輸烏鳶。", "暮投彭澤宿荒草，神驚魄顫何能眠。", "自兹稍悟垂堂戒，靴紋纔起不敢前。", "矜持太過僅無患，往往所至傷流連。", "乃知老謀與壯事，心膽殊異難兼全。", "重來此地畏洶湧，藏舟别浦看漪漣。", "魚跳鷗下自可喜，何用蛟鰐飲流涎。", "斜陽依依炤草木，夾岸葭菼鋪書氈。", "兒今弱冠昔何有，昔頷無鬚今皓然。", "二十餘年纔瞬息，時事幾蛻如秋蟬。", "區區走俗亦何賴，安得尺地巢林泉。"]'),
('ee441478-7a61-4833-a915-3fccd2782de0','雷亭四言','孔武仲','宋','宋诗','song-poetry','','[]','雷震於天，石隕於山。',100,'全唐诗/poet.song.49000.json','["雷震於天，石隕於山。", "石則何罪，龍殛石間。", "容而不拒，石則有愆。", "毋謂恢廣，不察神奸。", "想方震時，大雨溢川。", "萬里晦冥，風霆後先。", "獨恨不及，徙倚縱觀。", "睨而不驚，知神之全。", "余後過之，間四十年。", "乃記其始，以永其傳。"]'),
('1b2ae0c9-bd74-40d8-ad94-b5c64c49af25','清溪詞','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','譙門之南溪水長，斜暉倒閃青銅光。',56,'全唐诗/poet.song.49000.json','["譙門之南溪水長，斜暉倒閃青銅光。", "下與長江作支股，愁霖漲天江潦黄。", "江潦黄，入清溪。", "清溪到底終無泥，還如初出秀山時。"]'),
('e69f727a-fef3-4615-a86c-05196cc96277','瓜步阻風','孔武仲','宋','宋诗','song-poetry','','[]','昨日焚香謁聖母，青衫鞠躬如負弩。',200,'全唐诗/poet.song.49000.json','["昨日焚香謁聖母，青衫鞠躬如負弩。", "但乞天開萬里明，埽去浮雲戢風雨。", "謂宜言發即響報，豈知神不聽我語。", "門前白浪如銀山，江上狂風如怒虎。", "船癡艣硬不能拔，未免棲遲傍洲渚。", "輕盈但愛白鷗飛，顛頓可憐芳草舞。", "三江五湖歴已盡，勢合平夷反齟齬。", "上水歌呼下水愁，北船縈絆南船去。", "寄言南船莫雄豪，萬事低昂如桔橰。", "我當賣劍買牲牢，再掃靈宇陳肩尻。", "黄金壺樽沃香醪，神喜借以南風高。", "揚帆拍手笑爾曹，不知流落何江皋，荒洲寂寥聽怒號。"]'),
('2fb161fd-43a7-450f-9a9c-6ba4432e0137','奉祠城西夜坐苑中即事','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','喬林翳明星，林缺星粲然。',84,'全唐诗/poet.song.49000.json','["喬林翳明星，林缺星粲然。", "長江闊咫尺，銀河爲通川。", "爽氣浮襟裾，中夜不成眠。", "星轉轂而西，河逶迤以遷。", "惜此嘉景邁，無由駐青天。", "萬古留此境，誰保金石堅。", "徘徊吟華月，更欲隨飛仙。"]'),
('fe33631f-0cf7-468d-8a05-b95998ec9875','賦碼碯笛','孔武仲','宋','宋诗','song-poetry','','[]','羌兒吹笛作龍吟，中有太古之純音。',195,'全唐诗/poet.song.49000.json','["羌兒吹笛作龍吟，中有太古之純音。", "伊人已死笛仍在，千古月明江水深。", "誰知巧匠尋山谷，蹙踏溪雲採明玉。", "雲谷之竹色黯黯，淺紫輕紅花映雨。", "正聲隠顯初無端，造化推移指法間。", "黄鍾妍美霜朝暖，無射凄凉暑月寒。", "軺車走遍天南北，此笛此聲何處得。", "韜之湘竹川錦囊，廣坐聊持衒賓客。", "弘農學士九尺長，頰顴山起鬢髯張。", "從容奏罷陽春曲，氣衰坦腹眠繩床。", "由來雅器自有合，不與教坊管絃雜。", "君不見開元名臣宋侍中，手揮羯鼓疾如風。"]'),
('1c6ae5aa-e675-4c9e-bfc7-a5a10d87bad2','癸酉冬雪','孔武仲','宋','宋诗','song-poetry','','[]','平時看積雪，吟對佳山川。',120,'全唐诗/poet.song.49000.json','["平時看積雪，吟對佳山川。", "此地冨華屋，聽觀亦浩然。", "愛景匿何處，凍雪迷遠天。", "離離黄庭沙，種作白玉田。", "飛舞勢未已，參差態逾妍。", "坐來生精神，起步輕欲仙。", "京師百萬家，幾室無炊煙。", "南郭踵欲隨，袁安正高眠。", "且傾光禄酒，逸氣隨觥船。", "近害遠或利，從古占豐年。"]'),
('1cce3b11-688a-420d-9670-c2553be1d761','送范中濟侍郎知慶州','孔武仲','宋','宋诗','song-poetry','','[]','平時廣朝中，相見輒歡喜。',192,'全唐诗/poet.song.49000.json','["平時廣朝中，相見輒歡喜。", "昂藏八尺身，所負必奇偉。", "四方獻善敗，軍國盈虚計。", "叩之如川流，滚滚不知已。", "天子曰汝能，吾臣鮮其比。", "而况所設施，粲粲在邊鄙。", "西戎未純一，汝可三軍帥。", "擒之或縱之，高枕惟爾恃。", "公拜稽首歸，眉目凛生氣。", "頑童玩天恩，豢養若驕子。", "欲痛以鞭笞，而畏啼不止。", "二者不兩全，在所以節制。", "又如畜狂犬，繫頸不繫尾。", "收其要害處，進退隨所指。", "重城夜徹關，沙漠浄如水。", "辭别不躊躇，安邊從此始。"]'),
('465fcd06-bab3-4a7d-9913-c1562961425d','題瑞聖園','孔武仲','宋','宋诗','song-poetry','','[]','深沉百尺池，坐見淵魚躍。',120,'全唐诗/poet.song.49000.json','["深沉百尺池，坐見淵魚躍。", "蓊蔚千秋木，中聞魚鳥樂。", "久與魚鳥暌，塵土厭徽索。", "偶來叩異境，佳思得開廓。", "朝廷尚清熙，聖主守勤約。", "鑾輿不遊幸，花卉任榮落。", "便如到山林，不悟近城郭。", "心閒與境一，足以慰寂寞。", "由來市朝味，未易勝林壑。", "因循不遠引，僉信吾儕弱。"]'),
('99690656-e7b1-4e65-a68f-19136cc3864c','答毅父','孔武仲','宋','宋诗','song-poetry','','[]','朝趁朔風出，暮乘殘月歸。',108,'全唐诗/poet.song.49000.json','["朝趁朔風出，暮乘殘月歸。", "塵埃變髪毛，豈不損裘衣。", "憶昔年少日，未知願輕肥。", "登高作越吟，所喜獨翠微。", "至今清興在，夢與南雲飛。", "奈何寸景間，擾擾隨鞍鞿。", "已營三畝田，臨流架柴扉。", "惠而好我者，儻許相因依。", "種玉雖未熟，清泉猶禦饑。"]'),
('0d0c07d2-4f73-4c56-92f0-6f4760f7021b','送林子中知成都','孔武仲','宋','宋诗','song-poetry','','[]','鞍馬覆山黑，旌旗垂野紅。',156,'全唐诗/poet.song.49000.json','["鞍馬覆山黑，旌旗垂野紅。", "問遠誰當行，太守臨蜀中。", "太守時之豪，學博文章工。", "人事未稱遂，﨑嶇已巴東。", "公年方六十，皎皎頭如童。", "不服何首烏，自有夜氣充。", "丹田芙蕖開，餘光發形容。", "推此見治民，亦與治身同。", "以静鎮浮躁，以仁蘇疲癃。", "一夫無向隅，四野常年豐。", "間出作遨頭，伐擊鼓與鐘。", "遠民生愛敬，有古循吏風。", "豈止招學徒，區區繼文翁。"]'),
('a0f82f1f-656f-4670-95cd-0b378dbbfc4c','夏夜坐遊李左藏園常父子駿明叔毅父元忠時新除宣守不與朝參故斷章及之','孔武仲','宋','宋诗','song-poetry','','[]','王城雖多賢，相過每希濶。',120,'全唐诗/poet.song.49000.json','["王城雖多賢，相過每希濶。", "今夕復何夕，共此青天月。", "鄰園初剗築，咫尺夷且潔。", "胡床占勢便，漫不就行列。", "素華正冲融，湛露已凝冽。", "羣星亦自喜，點點欲螢滅。", "衣襟稍凄凉，何處有炎熱。", "夐宜在山谷，乃復近城闕。", "高談追鴻冥，不墮世覊紲。", "趣駕公等歸，晨雞有朝謁。"]');
